<script>
        // --- CONFIG & STATE ---
        let CONFIG = { 
            funcUrl: localStorage.getItem('conduit_funcUrl') || '',
            repoName: localStorage.getItem('conduit_repoName') || 'IDE',
            projectPath: localStorage.getItem('conduit_projectPath') || ''
        };
        let sessionLogs = [];
        let dbHistory = [];
        let repoFiles = []; 
        let hOffset = 0; let lOffset = 0; let wPage = 1;
        const PAGE_SIZE = 20;
        let editHistory = []; let historyIndex = -1;

        // --- INIT ---
        window.onload = async () => {
            document.getElementById('setting-func-url').value = CONFIG.funcUrl;
            document.getElementById('setting-repo-name').value = CONFIG.repoName;
            document.getElementById('setting-project-path').value = CONFIG.projectPath;

            const savedJson = localStorage.getItem('conduit_autosave');
            if(savedJson) {
                document.getElementById('json-input').value = savedJson;
                editHistory.push(savedJson);
                historyIndex = 0;
            }

            if(CONFIG.funcUrl) {
                await fetchState();
                // We delay the initial preview slightly to ensure state is ready
                setTimeout(() => bundleAndPreview(null), 500); 
            } else {
                switchTab('tab-settings', document.querySelectorAll('.nav-item')[4]);
            }
        };

        // --- CORE UTILS ---
        function b64DecodeUnicode(str) {
            return decodeURIComponent(atob(str).split('').map(function(c) {
                return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
            }).join(''));
        }

        function apiBody(obj) {
            return JSON.stringify({ ...obj, repo_name: CONFIG.repoName });
        }

        // Resolves relative paths (./utils.js) against a base (js/main.js) -> js/utils.js
        function resolvePath(base, relative) {
            const stack = base.split('/');
            stack.pop(); // Remove filename from base
            const parts = relative.split('/');
            for (let i = 0; i < parts.length; i++) {
                if (parts[i] === '.') continue;
                if (parts[i] === '..') stack.pop();
                else stack.push(parts[i]);
            }
            return stack.join('/');
        }

        // --- SETTINGS ---
        async function saveSettings() {
            const funcUrl = document.getElementById('setting-func-url').value.trim();
            const repoName = document.getElementById('setting-repo-name').value.trim() || 'IDE';
            let projectPath = document.getElementById('setting-project-path').value.trim();
            // Ensure trailing slash if not empty
            if(projectPath && !projectPath.endsWith('/')) projectPath += '/';

            if(!funcUrl) return alert("Function URL is required");

            // Save to LocalStorage
            localStorage.setItem('conduit_funcUrl', funcUrl);
            localStorage.setItem('conduit_repoName', repoName);
            localStorage.setItem('conduit_projectPath', projectPath);

            // Update Runtime Config
            CONFIG.funcUrl = funcUrl;
            CONFIG.repoName = repoName;
            CONFIG.projectPath = projectPath;

            alert("Settings Saved! Context: " + repoName + (projectPath ? ` / ${projectPath}` : ''));

            // Clear current UI to prevent confusion
            document.getElementById('file-list-container').innerHTML = '';
            document.getElementById('history-container').innerHTML = '';
            document.getElementById('terminal-list').innerHTML = '';
            document.getElementById('preview-frame').srcdoc = '';

            // Switch tab and fetch new state
            switchTab('tab-context', document.querySelectorAll('.nav-item')[0]);
            await fetchState(true);
            fetchFileList();
        }

                // --- API & DATA FETCHING ---
        function resetOffsets() { hOffset = 0; lOffset = 0; }

        async function fetchState(force = false) {
            const histContainer = document.getElementById('history-container');
            const termContainer = document.getElementById('terminal-list');

            if(force) {
                resetOffsets();
                histContainer.innerHTML = '<div style="padding:10px; text-align:center;">Syncing...</div>';
                termContainer.innerHTML = '<div style="padding:10px; text-align:center; color:#666">Syncing logs...</div>';
            }

            try {
                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: 'init', history_offset: hOffset, log_offset: lOffset })
                });
                const data = await res.json();

                if (hOffset === 0) histContainer.innerHTML = '';
                if (lOffset === 0) termContainer.innerHTML = '';

                if (data.history && data.history.length > 0) {
                    console.log(`[Sync] Received ${data.history.length} history items. Total cached: ${hOffset + data.history.length}`);
                    dbHistory = hOffset === 0 ? data.history : [...dbHistory, ...data.history];
                    renderHistory(data.history, hOffset > 0);
                    document.getElementById('btn-load-history').style.display = data.history.length === PAGE_SIZE ? 'block' : 'none';
                } else if (hOffset === 0) {
                    histContainer.innerHTML = '<div style="padding:10px; text-align:center;">No history found.</div>';
                }

                if (data.logs && data.logs.length > 0) {
                    data.logs.forEach(log => {
                        const id = 'term-saved-' + log.id;
                        const div = document.createElement('div');
                        div.id = id; div.className = 'log-entry'; div.style.marginBottom = '12px';
                        termContainer.appendChild(div);
                        updateTerminalCard(id, log.data, null);
                        const timeEl = div.querySelector('.log-time');
                        if(timeEl) timeEl.innerText = new Date(log.created_at).toLocaleString();
                    });
                    document.getElementById('btn-load-logs').style.display = data.logs.length === PAGE_SIZE ? 'block' : 'none';
                } else if (lOffset === 0) {
                    termContainer.innerHTML = '<div style="padding:10px; text-align:center; color:#444;">No logs found.</div>';
                }
            } catch (e) { console.error(e); }
        }

        function loadMoreHistory() { hOffset += PAGE_SIZE; fetchState(); }
        function loadMoreLogs() { lOffset += PAGE_SIZE; fetchState(); }

        async function fetchWorkflows() {
            const container = document.getElementById('workflow-list');
            if (wPage === 1) container.innerHTML = '<div style="padding:20px; text-align:center;">Fetching Runs...</div>';

            try {
                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: 'fetch_workflows', page: wPage })
                });
                const data = await res.json();
                if (wPage === 1) container.innerHTML = '';

                if (data.runs && data.runs.length > 0) {
                    data.runs.forEach(run => {
                        const div = document.createElement('div');
                        div.className = 'log-entry'; div.style.marginBottom = '10px';
                        const isFail = run.conclusion === 'failure';
                        div.innerHTML = `
                            <div class="log-header">
                                <div class="log-meta">
                                    <span class="status-pill ${isFail ? 'pill-fail' : 'pill-success'}">${run.conclusion || 'running'}</span>
                                    <strong>${run.name}</strong>
                                    <span class="log-time">#${run.run_number}</span>
                                </div>
                                <div class="flex-gap">
                                    <small style="color:var(--text-muted)">${new Date(run.created_at).toLocaleTimeString()}</small>
                                    ${isFail ? `<button class="btn-dev" style="padding:2px 8px; font-size:10px; width:auto;" onclick="triggerAutoFix('${run.id}')">Auto-Fix</button>` : ''}
                                </div>
                            </div>`;
                        container.appendChild(div);
                    });
                    document.getElementById('btn-load-workflows').style.display = data.runs.length >= 20 ? 'block' : 'none';
                } else if (wPage === 1) {
                    container.innerHTML = '<div style="padding:20px; text-align:center; color:#666;">No workflow runs found.</div>';
                }
            } catch (e) { container.innerHTML = 'Error: ' + e.message; }
        }

        function loadMoreWorkflows() { wPage++; fetchWorkflows(); }

        function jumpToHistory(conduitId) {
            console.log(`[Jump] Target ConduitID: ${conduitId}`);

            // 1. Switch Tab
            const historyTabBtn = document.querySelectorAll('.nav-item')[3];
            switchTab('tab-history', historyTabBtn);
            console.log("[Jump] Switched to History Tab");

            // 2. Wait for DOM cycle
            setTimeout(() => {
