        // --- THE MODULE BUNDLER (Recursive) ---
        // --- THE MODULE BUNDLER (With Multiline Import Support) ---
  async function bundleAndPreview(index) {
            if(!CONFIG.funcUrl) return;

            // 1. Setup Context
            let entry = (typeof index === 'number') ? dbHistory[index] : null;
            let sha = entry ? entry.sha : null;
            let rootPrefix = ''; 
            if (entry && entry.type === 'Prod') {
                const match = entry.title.match(/Deployed\s+(.+)/);
                if (match && match[1]) rootPrefix = `${match[1]}/`;
            }

            // FIX: We use effectiveRoot for stripping paths to ensure subfolders (DSE/) are flattened
            const effectiveRoot = rootPrefix || CONFIG.projectPath;
            const entryFile = effectiveRoot + 'index.html';
            const iframe = document.getElementById('preview-frame');
            iframe.srcdoc = `<div style="color:#666; font-family:sans-serif; text-align:center; padding:20px;">Bundling ${entryFile}...</div>`;

            // 2. Fetch All Files
            let allFiles = [];
            try {
                 const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'fetch' }) });
                 const data = await res.json();
                 allFiles = data.files.map(f => f.path);
            } catch(e) { return iframe.srcdoc = "Error fetching file list"; }

            const fileCache = {}; 
            const versionFiles = allFiles.filter(f => f.startsWith(effectiveRoot));

            async function fetchAndCache(path) {
                if(fileCache[path]) return;
                try {
                    const res = await fetch(CONFIG.funcUrl, {
                        method: 'POST', headers: {'Content-Type': 'application/json'},
                        body: apiBody({ action: 'preview_file', file_path: path, ref_sha: sha })
                    });
                    const data = await res.json();
                    if(data.content) fileCache[path] = { content: b64DecodeUnicode(data.content), mime: getMime(path) };
                } catch(e) {}
            }
            function getMime(path) {
                if(path.endsWith('.html')) return 'text/html';
                if(path.endsWith('.js')) return 'text/javascript';
                if(path.endsWith('.css')) return 'text/css';
                return 'application/octet-stream';
            }

            await Promise.all(versionFiles.map(f => fetchAndCache(f)));
            if(!fileCache[entryFile]) return iframe.srcdoc = `Error: ${entryFile} not found`;

            // 3. REWRITE IMPORTS (The Linker)
            function rewriteImports(code, currentPath) {
                return code.replace(/(import|export)([\s\S]*?)(['"])([^'"]+)(['"])/g, (match, keyword, mid, q1, importPath, q2) => {
                    if(importPath.startsWith('.')) {
                        const resolved = resolvePath(currentPath, importPath);

                        // FIX: Use effectiveRoot to strip the prefix (e.g. "DSE/ui.js" -> "ui.js")
                        const cleanKey = resolved.startsWith(effectiveRoot) ? resolved.substring(effectiveRoot.length) : resolved;
                        return `${keyword}${mid}${q1}${cleanKey}${q2}`;
                    }
                    return match;
                });
            }

            // Rewrite all cached JS files
            Object.keys(fileCache).forEach(path => {
                if(fileCache[path].mime === 'text/javascript') {
                    fileCache[path].content = rewriteImports(fileCache[path].content, path);
                }
            });

            // 4. GENERATE BLOBS & IMPORT MAP
            const importMap = { imports: {} };
            Object.keys(fileCache).forEach(path => {
                // FIX: Use effectiveRoot to generate flat map keys
                const mapKey = path.startsWith(effectiveRoot) ? path.substring(effectiveRoot.length) : path;
                const blob = new Blob([fileCache[path].content], { type: fileCache[path].mime });
                const blobUrl = URL.createObjectURL(blob);
                fileCache[path].blobUrl = blobUrl;
                importMap.imports[mapKey] = blobUrl;
            });

            // 5. INJECT INTO HTML
            let html = fileCache[entryFile].content;
            const parser = new DOMParser();
            const doc = parser.parseFromString(html, 'text/html');

            // Fix A: Rewrite Inline Scripts
            doc.querySelectorAll('script:not([src])').forEach(el => {
                if (el.type === 'module' || el.textContent.includes('import')) {
                    el.textContent = rewriteImports(el.textContent, entryFile);
                }
            });

            // Fix B: Rewrite External Scripts
            doc.querySelectorAll('script[src]').forEach(el => {
                const src = el.getAttribute('src');
                if(!src) return;
                // Use effectiveRoot to find the actual file in cache
                const repoPath = src.startsWith('./') ? resolvePath(entryFile, src) : (effectiveRoot + src);

                if(fileCache[repoPath]) {
                    if(fileCache[repoPath].mime === 'text/javascript') {
                        // FIX: Use effectiveRoot to strip prefix for the inline import
                        const cleanKey = repoPath.startsWith(effectiveRoot) ? repoPath.substring(effectiveRoot.length) : repoPath;
                        const inlineScript = doc.createElement('script');
                        inlineScript.type = 'module';
                        inlineScript.textContent = `import "${cleanKey}";`;
                        el.replaceWith(inlineScript);
                    } else {
                        el.src = fileCache[repoPath].blobUrl;
                    }
                }
            });

            // Fix C: CSS & Images
            doc.querySelectorAll('link[rel="stylesheet"]').forEach(el => {
                const href = el.getAttribute('href');
                if(!href) return;
                const repoPath = href.startsWith('./') ? resolvePath(entryFile, href) : (effectiveRoot + href);
                if(fileCache[repoPath]) el.href = fileCache[repoPath].blobUrl;
            });
            doc.querySelectorAll('img[src]').forEach(el => {
                const src = el.getAttribute('src');
                if(!src) return;
                const repoPath = src.startsWith('./') ? resolvePath(entryFile, src) : (effectiveRoot + src);
                if(fileCache[repoPath]) el.src = fileCache[repoPath].blobUrl;
            });

            // Inject Map
            const mapTag = doc.createElement('script');
            mapTag.type = "importmap";
            mapTag.textContent = JSON.stringify(importMap);
            doc.head.insertBefore(mapTag, doc.head.firstChild);

            iframe.srcdoc = doc.documentElement.outerHTML;
            document.getElementById('preview-url-display').innerText = sha ? `Viewing: ${entry.title}` : `Viewing: Live Dev (${CONFIG.repoName})`;
            switchTab('tab-preview', document.querySelectorAll('.nav-item')[2]);
        }

        // --- ACTIONS ---
        async function runPatch(actionType) {
            const inputVal = document.getElementById('json-input').value;
            let payload = {};
            try { 
                if(actionType === 'patch') {
                    const parsed = JSON.parse(inputVal);
                    payload = parsed.operations || parsed; 
                }
            } catch(e) { return alert("Invalid JSON"); }

            if(actionType === 'commit_prod') payload.version_name = prompt("Version Name (e.g. v1.0):") || "v1.0";

            // 1. USE HELPER: Create Loading Card
            const termId = addTerminalCard(null, { loading: true });

            try {
                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: actionType, operations: payload, version_name: payload.version_name })
                });
                const data = await res.json();

                // 2. USE HELPER: Update Card with Rich Details
                updateTerminalCard(termId, data, payload);

                if(data.success) {
                    if(actionType === 'patch') setTimeout(() => bundleAndPreview(null), 1500);
                    setTimeout(fetchState, 1000);

                }
            } catch (e) {
                updateTerminalCard(termId, { error: e.message });
            }
        }

// --- TERMINAL & LOGGING UI ---
        function addTerminalCard(data, options = {}) {
            const container = document.getElementById('terminal-list');
            const id = 'term-' + Date.now();
            const div = document.createElement('div');
            div.id = id; 
            div.className = 'log-entry';

            if(options.loading) {
                div.innerHTML = `<div class="log-header"><span>Processing...</span></div>`;
            } else if (options.error) {
                div.innerHTML = `<div class="log-header" style="color:var(--danger)"><span>Error</span></div><div class="log-body open" style="padding:12px; color:var(--danger); font-size:11px;">${options.error}</div>`;
            }

            container.prepend(div);
            return id;
        }

        window.OP_CACHE = {}; // Global cache for operation data

        function updateTerminalCard(id, response, originalPayload) {
            const el = document.getElementById(id);
            if(!el) return;

            if(response.error) {
                el.innerHTML = `<div class="log-header" style="color:var(--danger)"><span>API Error</span><span class="status-pill pill-fail">500</span></div><div class="log-body open" style="padding:12px; color:var(--danger); font-size:11px;">${response.error}</div>`;
                return;
            }

            let failCount = 0; 
            let hasAI = false;
            let opHtml = '';

            // Handle "Patch" Results
            if(response.results && Array.isArray(response.results)) {
                response.results.forEach(fileRes => {
                    opHtml += `<div style="background:#111; padding:6px 12px; font-weight:bold; color:#fff; border-bottom:1px solid #222; display:flex; justify-content:space-between;"><span>📄 ${fileRes.file}</span><span style="opacity:0.5; font-size:10px">${fileRes.status}</span></div>`;

                    if(fileRes.operations) {
                        fileRes.operations.forEach(op => {
                            if(!op.success) failCount++;
                            const isFail = !op.success;

                            // Generate ID and Cache Data
                            const opId = 'op-' + Math.random().toString(36).substr(2, 9);
                            // Store the Commit SHA from the response to fetch versions later
                            window.OP_CACHE[opId] = { 
                                file: fileRes.file, 
                                op: op, 
                                commit_sha: response.commit_sha || null 
                            };

                            // Determine Score Color
                            let scoreColor = 'var(--text-muted)';
                            let badgeText = `${op.score}% Match`;

                            if (op.message && (op.message.includes('AI Repaired') || op.message.includes('✨ AI'))) {
                                scoreColor = '#d946ef'; 
                                badgeText = `✨ AI ${op.score || 0}%`;
                                hasAI = true;
                            } 
                            else if(op.score === 100) scoreColor = 'var(--prod)';
                            else if(op.score >= 80) scoreColor = 'var(--dev)';
                            else if(op.score > 0) scoreColor = 'var(--danger)';

                            opHtml += `
                            <div class="op-row ${isFail ? 'row-fail' : ''}" onclick="toggleOpMenu('${opId}')">
                                <div class="op-title">
                                    <span>${op.type.replace(/_/g, ' ').toUpperCase()}</span>
                                    <span class="score-badge" style="border:1px solid ${scoreColor}; color:${scoreColor}">${badgeText}</span>
                                </div>
                                <div class="op-details">${op.message}</div>
                            </div>
                            <div id="${opId}-opts" class="op-options">
                                <button class="op-opt-btn" onclick="openOpModal('${opId}')">
                                    <svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M10 21h7a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v11m0 5l4.879-4.879m0 0a3 3 0 104.243-4.242 3 3 0 00-4.243 4.242z"></path></svg>
                                    Show Details
                                </button>
                                <button class="op-opt-btn" onclick="openDiffViewer('${opId}')">
                                    <svg width="12" height="12" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M8 7h12m0 0l-4-4m4 4l-4 4m0 6H4m0 0l4 4m-4-4l4-4"></path></svg>
                                    Show Diff
                                </button>
                            </div>`;
                        });
                    }
                });
            } 
            // Handle "Commit Prod" Results
            else if (response.count !== undefined) {
                opHtml = `<div class="op-row"><div class="op-details" style="color:var(--prod)">Production Deploy: ${response.count} files synced to Main.</div></div>`;
            }
            // Fallback message
            else if (response.message) {
                 opHtml = `<div class="op-row"><div class="op-details" style="color:var(--prod)">${response.message}</div></div>`;
            }

            const isFail = failCount > 0;
            const badgeClass = isFail ? 'pill-fail' : 'pill-success';
            const statusText = isFail ? `${failCount} FAILED` : 'SUCCESS';

            // Build the collapsible Header and Body
            const jumpBtn = response.conduit_id ? `<button class="icon-btn" style="color:var(--primary); border-color:var(--primary-dim);" onclick="event.stopPropagation(); jumpToHistory(${response.conduit_id})">VIEW IN HISTORY</button>` : '';

            el.innerHTML = `
                <div class="log-header ${isFail ? 'expanded' : ''}" onclick="toggleLogBody('${id}')">
                    <div class="log-meta">
                        <span class="log-time">${new Date().toLocaleTimeString()}</span>
                        ${hasAI ? '<span class="status-pill" style="background:rgba(217,70,239,0.2); color:#d946ef; margin-right:4px;">✨ AI</span>' : ''}
                        <span class="status-pill ${badgeClass}">${statusText}</span>
                    </div>
                    <div class="flex-gap">
                        ${jumpBtn}
                        <button class="icon-btn" style="padding:2px 6px; height:24px;" onclick="event.stopPropagation(); copyLogData('${id}')">COPY</button>
                        <span style="font-size:10px; color:#666">▼</span>
                    </div>
                </div>
                <div class="log-body ${isFail ? 'open' : ''}" id="${id}-body">
                    ${opHtml}
                </div>
                <textarea id="${id}-data" class="hidden">${JSON.stringify(response, null, 2)}</textarea>
            `;
        }

