        async function downloadSingleFile(path, btn) {
            const originalHtml = btn.innerHTML;
            btn.innerHTML = '...'; btn.disabled = true;
            try {
                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: 'preview_file', file_path: path })
                });
                const data = await res.json();
                if(!data.content) throw new Error("Empty");

                const byteCharacters = atob(data.content);
                const byteNumbers = new Array(byteCharacters.length);
                for (let i = 0; i < byteCharacters.length; i++) byteNumbers[i] = byteCharacters.charCodeAt(i);
                const blob = new Blob([new Uint8Array(byteNumbers)], {type: "application/octet-stream"});

                const link = document.createElement('a');
                link.href = URL.createObjectURL(blob);
                link.download = path.split('/').pop();
                document.body.appendChild(link);
                link.click();
                document.body.removeChild(link);
            } catch (e) { alert("Fail: " + e.message); } 
            finally { btn.innerHTML = originalHtml; btn.disabled = false; }
        }

        // --- NEW EXPORT LOGIC ---
        function openExportModal() {
            const checked = document.querySelectorAll('.file-check:checked');
            if(checked.length === 0) return alert("No files selected.");
            document.getElementById('export-status').innerText = `Ready to export ${checked.length} files.`;
            document.getElementById('export-modal').style.display = 'flex';
        }

        async function processExport(type) {
            // Target specific file-list container to avoid selecting hidden or phantom checkboxes
            const checked = Array.from(document.querySelectorAll('#file-list-container .file-check:checked')).map(c => c.value);
            const statusEl = document.getElementById('export-status');
            const btns = document.querySelectorAll('#export-modal button');

            // Lock UI
            btns.forEach(b => b.disabled = true);
            statusEl.innerText = "Fetching files... (0/" + checked.length + ")";

            try {
                const fetchedFiles = [];

                // Fetch files sequentially to avoid hitting rate limits
                for (let i = 0; i < checked.length; i++) {
                    const path = checked[i];
                    statusEl.innerText = `Fetching ${i+1}/${checked.length}: ${path}`;

                    try {
                        const res = await fetch(CONFIG.funcUrl, {
                            method: 'POST', headers: {'Content-Type': 'application/json'},
                            body: apiBody({ action: 'preview_file', file_path: path })
                        });
                        const data = await res.json();
                        if (data.content) {
                            fetchedFiles.push({ path: path, content: b64DecodeUnicode(data.content) });
                        }
                    } catch (e) { console.error("Failed to fetch", path); }
                }

                statusEl.innerText = "Generating " + type.toUpperCase() + "...";

                if (type === 'zip') {
                    const zip = new JSZip();
                    fetchedFiles.forEach(f => {
                        // Remove leading slash if present to avoid empty folders
                        const cleanPath = f.path.startsWith('/') ? f.path.slice(1) : f.path;
                        zip.file(cleanPath, f.content);
                    });

                    const blob = await zip.generateAsync({type: "blob"});
                    const link = document.createElement('a');
                    link.href = URL.createObjectURL(blob);
                    link.download = `${CONFIG.repoName}-export.zip`;
                    link.click();
                } 
                else if (type === 'txt') {
                    let giantText = `EXPORT FROM ${CONFIG.repoName}\nDATE: ${new Date().toLocaleString()}\n\n`;
                    fetchedFiles.forEach(f => {
                        const delimiter = "=".repeat(60);
                        giantText += `${delimiter}\nFILE: ${f.path}\n${delimiter}\n\n`;
                        giantText += f.content + "\n\n";
                    });

                    const blob = new Blob([giantText], {type: "text/plain"});
                    const link = document.createElement('a');
                    link.href = URL.createObjectURL(blob);
                    link.download = `${CONFIG.repoName}-merged.txt`;
                    link.click();
                }

                document.getElementById('export-modal').style.display = 'none';
            } catch (e) {
                alert("Export failed: " + e.message);
                statusEl.innerText = "Error: " + e.message;
            } finally {
                btns.forEach(b => b.disabled = false);
            }
        }

        async function addNote(index) {
            const newNote = prompt("Note:", dbHistory[index].note || '');
            if(newNote !== null) {
                dbHistory[index].note = newNote; renderHistory(dbHistory);
                await fetch(CONFIG.funcUrl, {
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: 'update_note', id: dbHistory[index].id, note: newNote })
                });
            }
        }

        function resetSession() {
            if(confirm("Clear local session log?")) { sessionLogs = []; alert("Session log cleared."); }
        }

        function handleBriefing(mode) {
             const checkedFiles = Array.from(document.querySelectorAll('.file-check:checked')).map(cb => cb.value);
             let report = "# Session Briefing\n**Repo:** " + CONFIG.repoName + "\n**Date:** " + new Date().toLocaleString() + "\n\n## 1. Changelog\n";
             if(sessionLogs.length === 0) report += "(No changes yet)\n";
             else sessionLogs.forEach(log => { report += `### [${log.time}] ${log.type}\n`; if(log.data.commit_sha) report += `- Commit: ${log.data.commit_sha.substring(0,7)}\n`; report += "\n"; });
             report += "\n## 2. Context Files\n";
             checkedFiles.forEach(f => report += `- ${f}\n`);
             if(mode === 'copy') navigator.clipboard.writeText(report).then(() => alert("Copied!"));
             else { const blob = new Blob([report], { type: 'text/markdown' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = "briefing.md"; a.click(); }
        }

     // --- 1. REPLACEMENT: renderFileList (Now with Click Event) ---
        function renderFileList(files) {
            const container = document.getElementById('file-list-container');
            container.innerHTML = '';
            if (!files || files.length === 0) return container.innerHTML = '<div style="padding:20px; text-align:center;">No files found.</div>';

            files.forEach(file => {
                const div = document.createElement('div');
                div.className = 'file-item';
                const sizeKB = file.size ? (file.size / 1024).toFixed(1) + ' KB' : '...';
                // Use a fallback for the timestamp if not provided specifically per file
                const timeStr = file.last_updated ? new Date(file.last_updated).toLocaleString([], {month:'short', day:'numeric', hour:'2-digit', minute:'2-digit'}) : 'Recently';

                div.innerHTML = `
                    <div class="v-info" onclick="openFileViewer('${file.path}')" style="cursor:pointer; flex:1;">
                        <strong>${file.path.split('/').pop()}</strong>
                        <div class="file-meta-row">
                            <span>${sizeKB}</span>
                            <span>•</span>
                            <span>Updated: ${timeStr}</span>
                        </div>
                        <small style="display:block; margin-top:2px; opacity:0.6;">${file.path}</small>
                    </div>
                    <div class="flex-gap" style="align-items:center;">
                        <button class="menu-btn" onclick="downloadSingleFile('${file.path}', this)">⬇</button>
                        <input type="checkbox" class="file-check" value="${file.path}" checked style="accent-color:var(--primary)">
                    </div>`;
                container.appendChild(div);
            });
        }

        // --- 2. ADDITION: Ace Editor Logic ---
        let aceEditorInstance = null;

        async function openFileViewer(path) {
            const viewer = document.getElementById('code-viewer');
            const title = document.getElementById('viewer-filename');
            const container = document.getElementById('ace-container');

            // 1. Show Loading UI
            viewer.classList.add('active');
            title.innerText = "Loading " + path + "...";

            // 2. Initialize Ace (Singleton pattern)
            if (!aceEditorInstance) {
                aceEditorInstance = ace.edit("ace-container");
                aceEditorInstance.setTheme("ace/theme/tomorrow_night_bright");
                aceEditorInstance.setOption("showPrintMargin", false);
                aceEditorInstance.setOption("fontSize", "13px");
                aceEditorInstance.setReadOnly(true); // Read-only mode
            }

            // 3. Configure Wrapping (Crucial for mobile)
            aceEditorInstance.session.setUseWrapMode(true);
            aceEditorInstance.setValue("Loading content...", -1);

            try {
                // 4. Fetch Content
                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST', 
                    headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: 'preview_file', file_path: path })
                });
                const data = await res.json();

                if (data.content) {
                    const content = b64DecodeUnicode(data.content);
                    title.innerText = path;

                    // 5. Detect Mode based on extension
                    let mode = "ace/mode/text";
                    if (path.endsWith('.js')) mode = "ace/mode/javascript";
                    else if (path.endsWith('.html')) mode = "ace/mode/html";
                    else if (path.endsWith('.css')) mode = "ace/mode/css";
                    else if (path.endsWith('.json')) mode = "ace/mode/json";
                    else if (path.endsWith('.md')) mode = "ace/mode/markdown";

                    aceEditorInstance.session.setMode(mode);
                    aceEditorInstance.setValue(content, -1); // -1 moves cursor to start
                } else {
                    aceEditorInstance.setValue("// Error: File is empty or could not be loaded.", -1);
                }
            } catch (e) {
                title.innerText = "Error";
                aceEditorInstance.setValue("// Error loading file:\n" + e.message, -1);
            }
        }

        function closeFileViewer() {
            document.getElementById('code-viewer').classList.remove('active');
            // Reset search UI when closing
            document.getElementById('ace-search-bar').style.display = 'none';
            document.getElementById('viewer-filename').style.display = 'block';
        }

      // --- ACE SMART SEARCH (Robust Multiline) ---
        function toggleAceSearch() {
            const bar = document.getElementById('ace-search-bar');
            const title = document.getElementById('viewer-filename');
            const input = document.getElementById('ace-search-input');

            if (bar.style.display === 'none') {
                bar.style.display = 'flex';
                title.style.display = 'none';
                input.focus();
                // Pre-fill with selected text
                const selected = aceEditorInstance.getSelectedText();
                if(selected) { input.value = selected; aceFind(null); }
            } else {
                bar.style.display = 'none';
                title.style.display = 'block';
                aceEditorInstance.selection.clearSelection();
            }
        }

function clearAceSearch() {
            const input = document.getElementById('ace-search-input');
            const count = document.getElementById('ace-search-count');

            input.value = '';
            count.innerText = '';
            input.focus();

            if(aceEditorInstance) {
                aceEditorInstance.selection.clearSelection();
            }
        }

        function aceFind(direction) {
            if (!aceEditorInstance) return;
            const input = document.getElementById('ace-search-input');
            const countEl = document.getElementById('ace-search-count');
            const query = input.value;

            if (!query) {
                countEl.innerText = "";
                aceEditorInstance.selection.clearSelection();
                return;
            }

            // 1. Prepare Regex: Escape chars, then replace spaces with \s+
            // This allows "div> div" to match "div>\n\n   div"
            const escaped = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
            const pattern = escaped.replace(/\s+/g, '\\s+');

            // 2. Search Raw Content (Bypasses Ace's line-by-line limitation)
            const content = aceEditorInstance.getValue();
            const regex = new RegExp(pattern, 'gim'); // Global, Case-Insensitive, Multiline

            const matches = [];
            let match;
            // Find ALL matches in the entire file string
            while ((match = regex.exec(content)) !== null) {
                matches.push({
                    index: match.index,
                    length: match[0].length
                });
            }

            const total = matches.length;
            if (total === 0) {
                countEl.innerText = "0 found";
                return;
            }

            // 3. Find Current Position relative to matches
            const currentPos = aceEditorInstance.getCursorPosition();
            const currentIndexVal = aceEditorInstance.session.doc.positionToIndex(currentPos);

            // Find which match we are currently on or after
            let matchIdx = -1;
            for (let i = 0; i < total; i++) {
                // Check if cursor is inside this match
                if (currentIndexVal >= matches[i].index && currentIndexVal < matches[i].index + matches[i].length) {
                    matchIdx = i;
                    break;
                }
            }

            // 4. Calculate Target Index
            let nextIdx = 0;
            if (direction === 'next') {
                if (matchIdx !== -1) nextIdx = (matchIdx + 1) % total;
                else {
                    // Find first match after cursor
                    nextIdx = matches.findIndex(m => m.index > currentIndexVal);
                    if (nextIdx === -1) nextIdx = 0; // Wrap to start
                }
            } else if (direction === 'prev') {
                if (matchIdx !== -1) nextIdx = (matchIdx - 1 + total) % total;
                else {
                    // Find last match before cursor
                    for (let i = total - 1; i >= 0; i--) {
                        if (matches[i].index < currentIndexVal) {
                            nextIdx = i;
                            break;
                        }
                    }
                    if (nextIdx === -1) nextIdx = total - 1; // Wrap to end
                }
            } else {
                // Typing (No direction): Stay on current or find nearest
                if (matchIdx !== -1) nextIdx = matchIdx;
                else {
                    nextIdx = matches.findIndex(m => m.index >= currentIndexVal);
                    if (nextIdx === -1) nextIdx = 0;
                }
            }

            // 5. Convert Index back to Ace Coordinates & Highlight
            const target = matches[nextIdx];
            const startPos = aceEditorInstance.session.doc.indexToPosition(target.index);
            const endPos = aceEditorInstance.session.doc.indexToPosition(target.index + target.length);

            const Range = ace.require('ace/range').Range;
            const aceRange = new Range(startPos.row, startPos.column, endPos.row, endPos.column);

            aceEditorInstance.selection.setRange(aceRange);
            aceEditorInstance.revealRange(aceRange);
            countEl.innerText = `${nextIdx + 1} of ${total}`;
        }

        function renderHistory(historyData, append = false) {
             const container = document.getElementById('history-container');
             if (!append && (!historyData || historyData.length === 0)) return container.innerHTML = '<div style="padding:10px; text-align:center;">No history.</div>';

             const html = historyData.filter(h => h.title !== "Rollback").map((h) => {
                 // Use the global dbHistory index by matching the conduit_id
                 const globalIdx = dbHistory.findIndex(item => item.conduit_id === h.conduit_id);
                 const canLoad = !!h.ops;
                 const canRestore = !!h.sha; 
                 return `
                <div class="version-item" id="hist-item-${h.conduit_id}">
                    <div class="v-header">
                        <div class="v-info"><strong>${h.title}</strong><small>${new Date(h.created_at).toLocaleString()}</small></div>
                        <div style="position:relative">
                            <button class="menu-btn" onclick="event.stopPropagation(); toggleMenu(${index})">⋮</button>
                            <div id="menu-${index}" class="menu-dropdown">
                                ${canLoad ? `<div class="menu-item" onclick="loadVersion(${index})">Load Patch</div>` : ''}
                                <div class="menu-item" onclick="bundleAndPreview(${index})">Preview</div>
                                <div class="menu-item" onclick="addNote(${index})">Note</div>
                                <div class="menu-item danger" onclick="deleteHistory(${index})">Delete</div>
                                ${canRestore ? `<div class="menu-item danger" onclick="handleRestore(${index})">Restore State</div>` : ''}
                            </div>
                        </div>
                    </div>
                    <div class="v-note ${h.note ? 'has-content' : ''}" onclick="addNote(${globalIdx})">${h.note || ''}</div>
                </div>`;
            }).join('');

            if (append) container.insertAdjacentHTML('beforeend', html);
            else container.innerHTML = html;
        }

        // --- HELPERS ---
        function toggleAllFiles(s) { document.querySelectorAll('.file-check').forEach(cb => cb.checked = s.checked); }
        function switchTab(id, btn) { 
            document.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active')); 
            document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active')); 
            document.getElementById(id).classList.add('active'); 
            if(btn) btn.classList.add('active');
            if(id === 'tab-cicd' && wPage === 1) fetchWorkflows();
        }
        function toggleFullscreen(a) { a ? document.body.classList.add('fs-mode') : document.body.classList.remove('fs-mode'); }
        function toggleMenu(i) { document.querySelectorAll('.menu-dropdown').forEach(m => m.classList.remove('show')); document.getElementById(`menu-${i}`).classList.add('show'); }
        function closeAllMenus(e) { if(!e.target.closest('.menu-btn')) document.querySelectorAll('.menu-dropdown').forEach(m => m.classList.remove('show')); }
        function filterFiles(q) { if(!window.repoFiles) return; if(!q) return renderFileList(window.repoFiles); const f = window.repoFiles.filter(i => i.path.toLowerCase().includes(q.toLowerCase())); renderFileList(f); }
        function loadVersion(i) { if(confirm('Load patch?')) { document.getElementById('json-input').value = JSON.stringify({ operations: dbHistory[i].ops }, null, 2); saveState(); switchTab('tab-patcher', document.querySelectorAll('.nav-item')[1]); } }
        function saveState() { const val = document.getElementById('json-input').value; localStorage.setItem('conduit_autosave', val); if (historyIndex === -1 || editHistory[historyIndex] !== val) { editHistory = editHistory.slice(0, historyIndex + 1); editHistory.push(val); historyIndex++; } }
        function editorUndo() { if (historyIndex > 0) { historyIndex--; document.getElementById('json-input').value = editHistory[historyIndex]; localStorage.setItem('conduit_autosave', editHistory[historyIndex]); } }
        function editorRedo() { if (historyIndex < editHistory.length - 1) { historyIndex++; document.getElementById('json-input').value = editHistory[historyIndex]; localStorage.setItem('conduit_autosave', editHistory[historyIndex]); } }
        function clearEditor() { document.getElementById('json-input').value = ''; saveState(); }

// --- OPERATION INTERACTIVITY ---
        function toggleOpMenu(id) {
            const menu = document.getElementById(id + '-opts');
            if(menu) menu.classList.toggle('show');
        }

        function openOpModal(id) {
            const data = window.OP_CACHE[id];
            if(!data) return;
            const op = data.op;

            const modal = document.getElementById('op-modal');
            const title = document.getElementById('op-modal-title');
            const body = document.getElementById('op-modal-body');

            title.innerText = `${op.type} in ${data.file}`;

            // Helper to escape HTML for display
            const esc = (s) => typeof s === 'string' ? s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;") : JSON.stringify(s, null, 2);

            let content = '';

            // Normalize Backend Keys
            const searchVal = op.find_block || op.anchor;
            const replaceVal = op.replace_with || op.content;

            // Search Block (Red/Remove) - Only show if it's a replacement/removal context
            if(searchVal && (op.action === 'replace_block' || op.action.includes('insert'))) {
                content += `
                <div class="code-block-wrapper">
                    <label class="code-label">${op.action.includes('insert') ? 'Anchor Point' : 'Code to Replace'}</label>
                    <button class="code-copy" onclick="navigator.clipboard.writeText(this.nextElementSibling.innerText)">Copy</button>
                    <pre class="code-pre diff-remove">${esc(searchVal)}</pre>
                </div>`;
            }

            // Replace Block (Green/Add)
            if(replaceVal) {
                content += `
                <div class="code-block-wrapper">
                    <label class="code-label">New Content</label>
                    <button class="code-copy" onclick="navigator.clipboard.writeText(this.nextElementSibling.innerText)">Copy</button>
                    <pre class="code-pre diff-add">${esc(replaceVal)}</pre>
                </div>`;
            }

            // Fallback for non-text operations or simple logs
            if(!content) {
                content += `<div class="code-block-wrapper"><pre class="code-pre">${esc(op.message)}</pre></div>`;
            }

            body.innerHTML = content;
            modal.style.display = 'flex';
        }

        let aceDiffInstance = null;

        let diffLeft = null;
        let diffRight = null;

        function closeDiffViewer() {
            document.getElementById('diff-viewer').classList.remove('active');
        }

        async function openDiffViewer(id) {
            const data = window.OP_CACHE[id];
            if(!data) return;

            const viewer = document.getElementById('diff-viewer');
            const title = document.getElementById('diff-title');

            viewer.classList.add('active');
            title.innerText = `Comparing: ${data.file.split('/').pop()}`;

            // 1. Initialize Editors (Lazy Load)
            if(!diffLeft) {
                diffLeft = ace.edit("diff-left");
                diffLeft.setTheme("ace/theme/tomorrow_night_bright");
                diffLeft.setReadOnly(true);
                diffLeft.setOption("showPrintMargin", false);

                diffRight = ace.edit("diff-right");
                diffRight.setTheme("ace/theme/tomorrow_night_bright");
                diffRight.setReadOnly(true);
                diffRight.setOption("showPrintMargin", false);

                // Sync Scrolling logic
                diffLeft.session.on('changeScrollTop', (top) => diffRight.session.setScrollTop(top));
                diffRight.session.on('changeScrollTop', (top) => diffLeft.session.setScrollTop(top));
                diffLeft.session.on('changeScrollLeft', (left) => diffRight.session.setScrollLeft(left));
                diffRight.session.on('changeScrollLeft', (left) => diffLeft.session.setScrollLeft(left));
            }

            // Reset
            diffLeft.setValue("Loading...", -1);
            diffRight.setValue("Loading...", -1);

            try {
                // 2. Fetch Content
                const rightRef = data.commit_sha || 'HEAD';
                const leftRef = rightRef + '^';

                const fetchFile = async (ref) => {
                    const res = await fetch(CONFIG.funcUrl, {
                        method: 'POST', headers: {'Content-Type': 'application/json'},
                        body: apiBody({ action: 'preview_file', file_path: data.file, ref_sha: ref })
                    });
                    const d = await res.json();
                    return d.content ? b64DecodeUnicode(d.content) : '';
                };

                const [leftContent, rightContent] = await Promise.all([
                    fetchFile(leftRef).catch(() => ""),
                    fetchFile(rightRef).catch(() => "")
                ]);

                // 3. Set Content & Mode
                let mode = "ace/mode/text";
                if (data.file.endsWith('.js')) mode = "ace/mode/javascript";
                else if (data.file.endsWith('.html')) mode = "ace/mode/html";

                diffLeft.session.setMode(mode);
                diffLeft.setValue(leftContent, -1);

                diffRight.session.setMode(mode);
                diffRight.setValue(rightContent, -1);

                // 4. Highlight the Changes
                const Range = ace.require('ace/range').Range;

                // Highlight Left (Removal)
                const searchRemove = data.op.find_block || data.op.anchor;
                if(searchRemove) {
                    diffLeft.find(String(searchRemove), {
                        backwards: false, wrap: true, caseSensitive: false, wholeWord: false, regExp: false
                    });
                    const sel = diffLeft.selection.getRange();
                    if(sel && !sel.isEmpty()) {
                        diffLeft.session.addMarker(sel, "marker-remove", "text");
                        diffLeft.scrollToLine(sel.start.row, true, true, function() {});
                    }
                }

                // Highlight Right (Addition)
                const searchAdd = data.op.replace_with || data.op.content;
                if(searchAdd) {
                    diffRight.find(String(searchAdd), {
                        backwards: false, wrap: true, caseSensitive: false, wholeWord: false, regExp: false
                    });
                    const sel = diffRight.selection.getRange();
                    if(sel && !sel.isEmpty()) {
                        diffRight.session.addMarker(sel, "marker-add", "text");
                        diffRight.scrollToLine(sel.start.row, true, true, function() {});
                    }
                }

            } catch(e) {
                diffLeft.setValue("Error: " + e.message, -1);
            }
        }

    </script>
</body>

</html>



