<script>
    // --- CONFIG & STATE ---
    let CONFIG = { 
        funcUrl: localStorage.getItem('conduit_funcUrl') || '',
        repoName: localStorage.getItem('conduit_repoName') || 'IDE',
        projectPath: localStorage.getItem('conduit_projectPath') || ''
    };

    // Global State
    let sessionLogs = [];
    let dbHistory = [];
    let repoFiles = []; 
    let editHistory = []; 
    let historyIndex = -1;

    // NEW: Cache for Operation Details & File Mapping
    window.OP_CACHE = {}; 
    window.BUILD_CACHE = {}; // Cache for Transpiled Blobs { sha: string, blobUrl: string }
    let FILE_OP_MAP = {}; // Maps 'path/to/file.js' -> 'op-id-123' (The last op that touched it)

    // --- INIT ---
    window.onload = async () => {
        // 🛑 ULTIMATE RECURSION GUARD: Check for the flag injected by the bundler
        if (window.IS_CONDUIT_PREVIEW) {
            console.log("Conduit Preview Mode Detected. Halting Init.");
            return;
        }

        // Initialize Editors if needed or settings
        document.getElementById('setting-func-url').value = CONFIG.funcUrl;
        document.getElementById('setting-repo-name').value = CONFIG.repoName;
        document.getElementById('setting-project-path').value = CONFIG.projectPath;

        const savedJson = localStorage.getItem('conduit_autosave');
        if(savedJson) {
            document.getElementById('json-input').value = savedJson;
            editHistory.push(savedJson);
            historyIndex = 0;
        }

        // Check for Acorn availability
        if(typeof acorn === 'undefined') {
            console.warn("Acorn library not found. Syntax checking will be disabled.");
        }

        if(CONFIG.funcUrl) {
            await fetchState();
            setTimeout(() => bundleAndPreview(null), 500); 
        } else {
            switchTab('tab-settings', document.querySelectorAll('.nav-item')[4]);
        }
    };

    // --- CORE UTILS ---
    function b64DecodeUnicode(str) {
        return decodeURIComponent(atob(str).split('').map(function(c) {
            return '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2);
        }).join(''));
    }

    function apiBody(obj) {
        return JSON.stringify({ ...obj, repo_name: CONFIG.repoName });
    }

    function resolvePath(base, relative) {
        const stack = base.split('/');
        stack.pop(); 
        const parts = relative.split('/');
        for (let i = 0; i < parts.length; i++) {
            if (parts[i] === '.') continue;
            if (parts[i] === '..') stack.pop();
            else stack.push(parts[i]);
        }
        return stack.join('/');
    }

    // --- NEW: SYNTAX CHECKER ---
    function checkSyntaxErrors(code, filePath) {
        // Requires Acorn library
        if (!code || typeof acorn === 'undefined') return null;
        // Only check JS/Module files
        if (!filePath.endsWith('.js') && !filePath.endsWith('.mjs')) return null;

        try {
            acorn.parse(code, {
                ecmaVersion: 2022,
                sourceType: 'module',
                locations: true
            });
            return null; // Success
        } catch (e) {
            return {
                message: e.message,
                line: e.loc ? e.loc.line : '?',
                column: e.loc ? e.loc.column : '?'
            };
        }
    }

