    // --- BUNDLER (React/JSX Supported) ---
    async function bundleAndPreview(index) {
        if(!CONFIG.funcUrl) return;

        let entry = (typeof index === 'number') ? dbHistory[index] : null;
        let sha = entry ? entry.sha : null;
        let rootPrefix = ''; 
        if (entry && entry.type === 'Prod') {
            const match = entry.title.match(/Deployed\s+(.+)/);
            if (match && match[1]) rootPrefix = `${match[1]}/`;
        }

        const effectiveRoot = rootPrefix || CONFIG.projectPath;
        // React projects often use index.html or main.jsx. We try to stick to standard entry.
        const entryFile = effectiveRoot + 'index.html';
        const iframe = document.getElementById('preview-frame');
        iframe.srcdoc = `<div style="color:#666; font-family:sans-serif; text-align:center; padding:20px;">Fetching & Building ${entryFile}...</div>`;

        const fileCache = {}; window.CURRENT_FILE_CACHE = fileCache;

        // 1. OPTIMIZED BATCH FETCH
        try {
            const res = await fetch(CONFIG.funcUrl, { 
                method: 'POST', 
                headers: {'Content-Type': 'application/json'}, 
                body: apiBody({ 
                    action: 'fetch_project_bundle', // New optimized endpoint
                    project_path: effectiveRoot,
                    ref_sha: sha 
                }) 
            });
            const data = await res.json();
            const bundle = data.files || {};

            // 2. PROCESS FILES & CHECK CACHE
            Object.keys(bundle).forEach(path => {
                const rawData = bundle[path];
                const mime = getMime(path);
                const content = mime === 'image' ? rawData.content : b64DecodeUnicode(rawData.content);

                // Store raw content for "View Code" / "AutoFix" features
                fileCache[path] = { content, mime, sha: rawData.sha };
            });

        } catch(e) { 
            console.error(e);
            return iframe.srcdoc = `Error bundling project: ${e.message}`; 
        }

        function getMime(path) {
            if(path.endsWith('.html')) return 'text/html';
            if(path.endsWith('.js') || path.endsWith('.mjs')) return 'text/javascript';
            if(path.endsWith('.jsx') || path.endsWith('.tsx') || path.endsWith('.ts')) return 'text/jsx';
            if(path.endsWith('.css')) return 'text/css';
            if(path.endsWith('.json')) return 'application/json';
            if(path.match(/\.(png|jpg|jpeg|gif|svg|ico)$/)) return 'image'; 
            return 'application/octet-stream';
        }

        if(!fileCache[entryFile]) return iframe.srcdoc = `Error: ${entryFile} not found (Check Project Path settings)`;

        // --- SYNTAX CHECK (Skip for JSX for now to prevent false positives) ---
        let syntaxErrorFound = false;
        Object.keys(fileCache).forEach(path => {
            // Only check standard JS. Skip JSX because Acorn doesn't understand it without plugins.
            if (fileCache[path].mime === 'text/javascript') {
                const error = checkSyntaxErrors(fileCache[path].content, path);
                if (error) {
                    syntaxErrorFound = true;
                    // ... (Keep existing error reporting logic) ...
                    // For brevity, assuming existing logic here (highlightCulpritOp etc)
                    console.error("Syntax Error", error);
                    iframe.srcdoc = `<div style="color:red; padding:20px;">Syntax Error in ${path}: line ${error.line}</div>`;
                }
            }
        });
        if (syntaxErrorFound) return; 

        // --- REWRITE IMPORTS ---
        function rewriteImports(code, currentPath) {
            return code.replace(/(import|export)([\s\S]*?)(['"])([^'"]+)(['"])/g, (match, keyword, mid, q1, importPath, q2) => {
                // If importing React/ReactDOM, leave it alone (Import Map handles it)
                if(importPath === 'react' || importPath === 'react-dom' || importPath === 'react-dom/client') return match;

                if(importPath.startsWith('.')) {
                    const resolved = resolvePath(currentPath, importPath);
                    const cleanKey = resolved.startsWith(effectiveRoot) ? resolved.substring(effectiveRoot.length) : resolved;
                    return `${keyword}${mid}${q1}${cleanKey}${q2}`;
                }
                return match;
            });
        }

        // Generate Import Map (With React Support)
        const importMap = { 
            imports: {
                "react": "https://esm.sh/react@18.2.0",
                "react-dom/client": "https://esm.sh/react-dom@18.2.0/client"
            } 
        };

        // Process Files
        Object.keys(fileCache).forEach(path => {
            const isJs = fileCache[path].mime === 'text/javascript';
            const isJsx = fileCache[path].mime === 'text/jsx';

            if(isJs || isJsx) {
                fileCache[path].content = rewriteImports(fileCache[path].content, path);
            }

            // Create Blob URLs
            const mapKey = path.startsWith(effectiveRoot) ? path.substring(effectiveRoot.length) : path;

            // COMPILATION STEP: Transpile JSX/TSX to JS using the Parent Window's Babel
            // CACHE CHECK: If we have a build for this specific SHA, use it.
            const cacheKey = path;
            const currentSha = fileCache[path].sha;

            if (isJsx) {
                if (window.BUILD_CACHE[cacheKey] && window.BUILD_CACHE[cacheKey].sha === currentSha) {
                    // CACHE HIT: Skip Babel!
                    fileCache[path].content = window.BUILD_CACHE[cacheKey].code;
                    fileCache[path].mime = 'text/javascript';
                } else {
                    // CACHE MISS: Run Babel
                    try {
                        const res = Babel.transform(fileCache[path].content, { 
                            presets: [['env', { modules: false }], 'react'],
                            filename: path 
                        });
                        fileCache[path].content = res.code;
                        fileCache[path].mime = 'text/javascript'; // It is now valid JS

                        // Update Cache
                        window.BUILD_CACHE[cacheKey] = { sha: currentSha, code: res.code };

                    } catch (e) {
                        console.error("Babel Compilation Error", e);
                        return iframe.srcdoc = `<div style="color:red; font-family:monospace; padding:20px;"><strong>Build Error in ${path}:</strong><br>${e.message}</div>`;
                    }
                }
            }

            // CSS-IN-JS STEP
            if (fileCache[path].mime === 'text/css') {
                 const cleanCss = fileCache[path].content.replace(/`/g, '\\`').replace(/\\/g, '\\\\');
                 fileCache[path].content = `const style = document.createElement('style'); style.textContent = \`${cleanCss}\`; document.head.appendChild(style);`;
                 fileCache[path].mime = 'text/javascript';
            }

            // JSON STEP: Export as default object
            if (fileCache[path].mime === 'application/json') {
                fileCache[path].content = `export default ${fileCache[path].content};`;
                fileCache[path].mime = 'text/javascript';
            }

            // IMAGE STEP: Export as Base64 Data URI
            if (fileCache[path].mime === 'image') {
                const ext = path.split('.').pop();
                let imgMime = 'image/png';
                if(ext === 'svg') imgMime = 'image/svg+xml';
                else if(ext === 'jpg' || ext === 'jpeg') imgMime = 'image/jpeg';

                // Create Data URI
                const dataUri = `data:${imgMime};base64,${fileCache[path].content}`;
                fileCache[path].content = `export default "${dataUri}";`;
                fileCache[path].mime = 'text/javascript';
            }

            // BLOB STEP: Create Blob from the (now processed) content
            const blob = new Blob([fileCache[path].content], { type: fileCache[path].mime });
            fileCache[path].blobUrl = URL.createObjectURL(blob);
            importMap.imports[mapKey] = fileCache[path].blobUrl;

            // FALLBACK: The 'else' block is removed because we process everything above.
            if (false) {
                // For JSX, we store the content directly in the import map as a data URI or handle via Babel script injection
                // Easier approach: Babel Standalone can fetch external scripts if type="text/babel"
                // But for import maps to work with Babel, we need a special loader or simple injection.
                // Let's go with: Inject content into script tags.
            }
        });

        // Inject HTML
        let html = fileCache[entryFile].content;
        const parser = new DOMParser();
        const doc = parser.parseFromString(html, 'text/html');

        // 1. Inject Preview Flag & Process Polyfill
        const flagScript = doc.createElement('script');
        flagScript.textContent = 'window.IS_CONDUIT_PREVIEW = true; window.process = { env: { NODE_ENV: "development" } };';
        doc.head.insertBefore(flagScript, doc.head.firstChild);

        // 2. Inject Babel Standalone
        const babelScript = doc.createElement('script');
        babelScript.src = "https://unpkg.com/@babel/standalone/babel.min.js";
        doc.head.appendChild(babelScript);

        // 3. Handle Scripts
        // We need to collect all JSX files and inject them as <script type="text/babel">
        // Standard JS files are handled via Import Map

        doc.querySelectorAll('script[src]').forEach(el => {
            const src = el.getAttribute('src');
            if(!src) return;
            const repoPath = src.startsWith('./') ? resolvePath(entryFile, src) : (effectiveRoot + src);

            if(fileCache[repoPath]) {
                if(fileCache[repoPath].mime === 'text/jsx') {
                    // It's a React file. Inject content directly as Babel script
                    const inlineScript = doc.createElement('script');
                    inlineScript.type = 'text/babel';
                    inlineScript.setAttribute('data-presets', 'react,env');
                    inlineScript.textContent = fileCache[repoPath].content;
                    el.replaceWith(inlineScript);
                } else if(fileCache[repoPath].mime === 'text/javascript') {
                    // Standard Module
                    const cleanKey = repoPath.startsWith(effectiveRoot) ? repoPath.substring(effectiveRoot.length) : repoPath;
                    const inlineScript = doc.createElement('script');
                    inlineScript.type = 'module';
                    inlineScript.textContent = `import "${cleanKey}";`;
                    el.replaceWith(inlineScript);
                } else {
                    el.src = fileCache[repoPath].blobUrl;
                }
            }
        });

        // 4. Inject Import Map
        const mapTag = doc.createElement('script');
        mapTag.type = "importmap";
        mapTag.textContent = JSON.stringify(importMap);
        doc.head.insertBefore(mapTag, doc.head.firstChild);

        const finalHtml = doc.documentElement.outerHTML;
        iframe.srcdoc = finalHtml;

        // Create a "Localhost" style Blob URL for the Pop-out button
        if(window.PREVIEW_BLOB_URL) URL.revokeObjectURL(window.PREVIEW_BLOB_URL); // Cleanup previous
        const blob = new Blob([finalHtml], { type: 'text/html' });
        window.PREVIEW_BLOB_URL = URL.createObjectURL(blob);

        // HOT PUSH: If popout is open, force it to update to the new version
        if(window.POPOUT_REF && !window.POPOUT_REF.closed) {
            window.POPOUT_REF.location.replace(window.PREVIEW_BLOB_URL);
        }

        document.getElementById('preview-url-display').innerText = sha ? `Viewing: ${entry.title}` : `Viewing: Live Dev (${CONFIG.repoName})`;
        switchTab('tab-preview', document.querySelectorAll('.nav-item')[2]);
    }

    function openPopOut() {
        if(window.PREVIEW_BLOB_URL) {
            // Store the window reference so we can update it later
            window.POPOUT_REF = window.open(window.PREVIEW_BLOB_URL, '_blank');
        }
        else alert("Please build the preview first.");
    }

    // --- VISUAL ERROR BLAMING ---
    function highlightCulpritOp(opId, error) {
        // Find the operation row in the DOM
        // We look for the onclick handler that contains the ID
        const allOps = Array.from(document.querySelectorAll('.op-row'));
        const opRow = allOps.find(el => el.getAttribute('onclick') && el.getAttribute('onclick').includes(opId));

        if(opRow) {
            // 1. Style the row
            opRow.style.borderLeft = "4px solid var(--danger)";
            opRow.style.backgroundColor = "rgba(239, 68, 68, 0.15)";

            // 2. Append Error Details (Enhanced)
            const detailsDiv = opRow.querySelector('.op-details');
            if(detailsDiv) {
                const errDiv = document.createElement('div');
                errDiv.style.cssText = "background:rgba(239,68,68,0.1); border:1px solid var(--danger); border-radius:6px; padding:8px; margin-top:8px; display:flex; flex-direction:column; gap:6px;";

                const path = window.OP_CACHE[opId] ? window.OP_CACHE[opId].file : 'unknown';
                const safeMsg = encodeURIComponent(error.message);
                const safePath = encodeURIComponent(path);

                errDiv.innerHTML = `
                    <div style="color:var(--danger); font-weight:600; font-size:11px;">⚠️ SYNTAX ERROR (Line ${error.line})</div>
                    <div style="color:#fab; font-size:11px;">${error.message}</div>
                    <div style="display:flex; gap:6px; margin-top:4px;">
                        <button onclick="event.stopPropagation(); handleAutoFix(decodeURIComponent('${safePath}'), ${error.line}, decodeURIComponent('${safeMsg}'))" class="op-opt-btn" style="border-color:#d946ef; color:#d946ef;">✨ Auto-Fix</button>
                        <button onclick="event.stopPropagation(); openFileAtLine(decodeURIComponent('${safePath}'), ${error.line})" class="op-opt-btn">Jump ↗</button>
                        <button onclick="event.stopPropagation(); copyErrorReport(decodeURIComponent('${safePath}'), ${error.line}, decodeURIComponent('${safeMsg}'))" class="op-opt-btn">Copy</button>
                    </div>
                `;
                detailsDiv.appendChild(errDiv);
            }

            // 3. Open the Log Group
            const logBody = opRow.closest('.log-body');
            const logHeader = logBody ? logBody.previousElementSibling : null;

            if(logBody) logBody.classList.add('open');
            if(logHeader) logHeader.classList.add('expanded');

            // 4. Scroll to it
            opRow.scrollIntoView({ behavior: 'smooth', block: 'center' });

            alert(`Found Source of Syntax Error!\nCheck the highlighted operation in the Terminal.`);
        }
    }
