    function openFileAtLine(path, line) {
        window.viewerJumpLine = line;
        openFileViewer(path);
    }

    function copyErrorReport(path, line, msg) {
        let context = "";
        // Try to grab context from cache if available
        if(window.CURRENT_FILE_CACHE && window.CURRENT_FILE_CACHE[path]) {
            const lines = window.CURRENT_FILE_CACHE[path].content.split('\n');
            // Grab 5 lines before and after
            const start = Math.max(0, line - 6);
            const end = Math.min(lines.length, line + 5);
            context = lines.slice(start, end).map((l, i) => `${start + i + 1} | ${l}`).join('\n');
        }

        const report = `Build Error Report\nFile: ${path}\nLine: ${line}\nError: ${msg}\n\nContext:\n${context}`;
        navigator.clipboard.writeText(report).then(() => {
            const toast = document.getElementById('toast-msg') || document.createElement('div');
            toast.innerText = "📋 Report Copied!";
            toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:#333; color:white; padding:8px 16px; border-radius:20px; z-index:9999;";
            document.body.appendChild(toast);
            setTimeout(() => toast.remove(), 2000);
        });
    }

    async function handleAutoFix(path, line, errorMsg) {
        console.log("AutoFix Triggered:", path, line);

        // 1. Verify file content
        let content = "";
        if (window.CURRENT_FILE_CACHE && window.CURRENT_FILE_CACHE[path]) {
            content = window.CURRENT_FILE_CACHE[path].content;
        } else {
            try {
                const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'preview_file', file_path: path }) });
                const data = await res.json();
                content = b64DecodeUnicode(data.content);
            } catch(e) { 
                return alert("Error: Could not read file content.\n" + e.message); 
            }
        }

        if(!content) return alert("File content is empty.");

        // 2. Extract Context
        const lines = content.split('\n');
        const startLine = Math.max(0, line - 20);
        const endLine = Math.min(lines.length, line + 5);
        const codeBlock = lines.slice(startLine, endLine).join('\n');

        // 3. UI Feedback
        const toast = document.createElement('div');
        toast.innerText = "⏳ Asking AI to fix syntax...";
        toast.style.cssText = "position:fixed; top:20px; left:50%; transform:translateX(-50%); background:#d946ef; color:white; padding:10px 20px; border-radius:30px; z-index:9999; font-weight:bold; box-shadow:0 5px 20px rgba(0,0,0,0.5);";
        document.body.appendChild(toast);

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: apiBody({ 
                    action: 'fix_syntax', 
                    code_block: codeBlock, 
                    error_message: errorMsg 
                })
            });
            const data = await res.json();

            toast.remove();

            if (data.success && data.fixed_code) {
                // 4. Construct Operation
                const operation = {
                    file_path: path,
                    action: "replace_block",
                    find_block: codeBlock, 
                    replace_with: data.fixed_code,
                    message: `Auto-fix syntax error: ${data.explanation}`
                };

                // 5. Load into Patcher (Wrapped in Array)
                // We wrap 'operation' in [ ] so the backend treats it as a list of 1 item
                document.getElementById('json-input').value = JSON.stringify([operation], null, 2);
                saveState();

                // --- THE FIX IS HERE ---
                if(confirm(`✨ AI Found a Fix!\n\nReason: ${data.explanation}\n\nClick OK to Apply & Re-Bundle.`)) {
                    // A. Switch to Patcher Tab
                    switchTab('tab-patcher', document.querySelectorAll('.nav-item')[1]);

                    // B. EXECUTE THE PATCH AUTOMATICALLY
                    setTimeout(() => {
                        runPatch('patch'); // <--- This triggers the API, updates Terminal, and re-runs Bundler
                    }, 500); 
                }

            } else {
                alert("AI could not fix it automatically.\nReason: " + (data.explanation || "Unknown"));
            }
        } catch (e) {
            toast.remove();
            alert("Connection Error: " + e.message);
        }
    }

    // --- ACTIONS ---
        async function generateAiPatch() {
        const prompt = document.getElementById('ai-prompt-input').value.trim();
        if(!prompt) return alert("Please enter a prompt.");

        const checkedBoxes = document.querySelectorAll('#file-list-container .file-check:checked');
        if(checkedBoxes.length === 0) return alert("Please select at least one file in the Context tab to modify.");

        const filePaths = Array.from(checkedBoxes).map(cb => cb.value);
        const btn = document.querySelector('.ai-controls button');
        const originalText = btn.innerText;
        btn.innerText = "Thinking...";
        btn.disabled = true;

        try {
            const contextPayload = [];
            for (const path of filePaths) {
                if (window.CURRENT_FILE_CACHE && window.CURRENT_FILE_CACHE[path]) {
                    contextPayload.push({ path: path, content: btoa(window.CURRENT_FILE_CACHE[path].content) });
                } else {
                    const res = await fetch(CONFIG.funcUrl, { method: 'POST', headers: {'Content-Type': 'application/json'}, body: apiBody({ action: 'preview_file', file_path: path }) });
                    const data = await res.json();
                    contextPayload.push({ path: path, content: data.content });
                }
            }

            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'generate_ops', user_prompt: prompt, context_files: contextPayload })
            });

            const data = await res.json();

            if(data.operations) {
                document.getElementById('json-input').value = data.operations;
                saveState();
                const editor = document.getElementById('json-input');
                editor.style.outline = "2px solid #d946ef";
                setTimeout(() => editor.style.outline = "none", 500);
            }
        } catch (e) {
            alert("AI Error: " + e.message);
        } finally {
            btn.innerText = originalText;
            btn.disabled = false;
        }
    }

async function runPatch(actionType) {
        // RESET STATE: Clear blame map and remove previous red highlights from terminal
        FILE_OP_MAP = {}; 
        document.querySelectorAll('.op-row').forEach(el => {
            el.style.borderLeft = '';
            el.style.backgroundColor = '';
        });

        const inputVal = document.getElementById('json-input').value;
        let payload = {};
        try { 
            if(actionType === 'patch') {
                // Try to parse. If it fails, the catch block will report exactly why.
                const parsed = JSON.parse(inputVal);
                payload = parsed.operations || parsed; 
            }
        } catch(e) { 
            // Report the specific error to the Terminal so you can copy it
            const errorMsg = `JSON PARSE ERROR:\n${e.message}`;
            const errId = addTerminalCard(null, { error: errorMsg });
            document.getElementById(errId).scrollIntoView({ behavior: 'smooth' });
            return; 
        }


        if(actionType === 'commit_prod') payload.version_name = prompt("Version Name (e.g. v1.0):") || "v1.0";

        // Auto-prepend Project Path if missing
        if (CONFIG.projectPath && Array.isArray(payload)) {
            payload.forEach(op => {
                if (op.file_path && !op.file_path.startsWith(CONFIG.projectPath)) {
                    const cleanPath = op.file_path.startsWith('/') ? op.file_path.slice(1) : op.file_path;
                    op.file_path = CONFIG.projectPath + cleanPath;
                }
            });
        }

        const termId = addTerminalCard(null, { loading: true });

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: apiBody({ 
                    action: actionType, 
                    operations: payload, 
                    version_name: payload.version_name,
                    project_path: CONFIG.projectPath 
                })
            });
            const data = await res.json();

            updateTerminalCard(termId, data, payload, true); 

            if(data.success) {
                if(actionType === 'patch') setTimeout(() => bundleAndPreview(null), 1500);
                setTimeout(fetchState, 1000);
            }
        } catch (e) {
            updateTerminalCard(termId, { error: e.message });
        }
    }

