    function aceFind(direction) {
        if (!aceEditorInstance) return;
        const input = document.getElementById('ace-search-input');
        const countEl = document.getElementById('ace-search-count');
        const query = input.value;

        if (!query) {
            countEl.innerText = "";
            aceEditorInstance.selection.clearSelection();
            return;
        }

        const escaped = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const pattern = escaped.replace(/\s+/g, '\\s+');
        const content = aceEditorInstance.getValue();
        const regex = new RegExp(pattern, 'gim');

        const matches = [];
        let match;
        while ((match = regex.exec(content)) !== null) {
            matches.push({ index: match.index, length: match[0].length });
        }

        const total = matches.length;
        if (total === 0) {
            countEl.innerText = "0 found";
            return;
        }

        const currentPos = aceEditorInstance.getCursorPosition();
        const currentIndexVal = aceEditorInstance.session.doc.positionToIndex(currentPos);

        let matchIdx = -1;
        for (let i = 0; i < total; i++) {
            if (currentIndexVal >= matches[i].index && currentIndexVal < matches[i].index + matches[i].length) {
                matchIdx = i; break;
            }
        }

        let nextIdx = 0;
        if (direction === 'next') {
            nextIdx = (matchIdx !== -1) ? (matchIdx + 1) % total : (matches.findIndex(m => m.index > currentIndexVal) !== -1 ? matches.findIndex(m => m.index > currentIndexVal) : 0);
        } else if (direction === 'prev') {
            nextIdx = (matchIdx !== -1) ? (matchIdx - 1 + total) % total : (matches.findIndex(m => m.index < currentIndexVal) !== -1 ? matches.findIndex(m => m.index < currentIndexVal) : total - 1);
        } else {
            nextIdx = (matchIdx !== -1) ? matchIdx : (matches.findIndex(m => m.index >= currentIndexVal) !== -1 ? matches.findIndex(m => m.index >= currentIndexVal) : 0);
        }

        const target = matches[nextIdx];
        const startPos = aceEditorInstance.session.doc.indexToPosition(target.index);
        const endPos = aceEditorInstance.session.doc.indexToPosition(target.index + target.length);
        const Range = ace.require('ace/range').Range;
        const aceRange = new Range(startPos.row, startPos.column, endPos.row, endPos.column);

        aceEditorInstance.selection.setRange(aceRange);
        aceEditorInstance.revealRange(aceRange);
        countEl.innerText = `${nextIdx + 1} of ${total}`;
    }

