    async function downloadSingleFile(path, btn) {
        const originalHtml = btn.innerHTML;
        btn.innerHTML = '...'; btn.disabled = true;
        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'preview_file', file_path: path })
            });
            const data = await res.json();
            if(!data.content) throw new Error("Empty");

            const byteCharacters = atob(data.content);
            const byteNumbers = new Array(byteCharacters.length);
            for (let i = 0; i < byteCharacters.length; i++) byteNumbers[i] = byteCharacters.charCodeAt(i);
            const blob = new Blob([new Uint8Array(byteNumbers)], {type: "application/octet-stream"});

            const link = document.createElement('a');
            link.href = URL.createObjectURL(blob);
            link.download = path.split('/').pop();
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        } catch (e) { alert("Fail: " + e.message); } 
        finally { btn.innerHTML = originalHtml; btn.disabled = false; }
    }

    function handleBriefing(mode) {
            const checkedFiles = Array.from(document.querySelectorAll('.file-check:checked')).map(cb => cb.value);
            let report = "# Session Briefing\n**Repo:** " + CONFIG.repoName + "\n**Date:** " + new Date().toLocaleString() + "\n\n## 1. Changelog\n";
            if(sessionLogs.length === 0) report += "(No changes yet)\n";
            else sessionLogs.forEach(log => { report += `### [${log.time}] ${log.type}\n`; if(log.data.commit_sha) report += `- Commit: ${log.data.commit_sha.substring(0,7)}\n`; report += "\n"; });
            report += "\n## 2. Context Files\n";
            checkedFiles.forEach(f => report += `- ${f}\n`);
            if(mode === 'copy') navigator.clipboard.writeText(report).then(() => alert("Copied!"));
            else { const blob = new Blob([report], { type: 'text/markdown' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = "briefing.md"; a.click(); }
    }

