    async function processExport(type) {
        const checked = Array.from(document.querySelectorAll('#file-list-container .file-check:checked')).map(c => c.value);
        const statusEl = document.getElementById('export-status');
        const btns = document.querySelectorAll('#export-modal button');

        btns.forEach(b => b.disabled = true);
        statusEl.innerText = "Fetching files... (0/" + checked.length + ")";

        try {
            const fetchedFiles = [];
            for (let i = 0; i < checked.length; i++) {
                const path = checked[i];
                statusEl.innerText = `Fetching ${i+1}/${checked.length}: ${path}`;
                try {
                    const res = await fetch(CONFIG.funcUrl, {
                        method: 'POST', headers: {'Content-Type': 'application/json'},
                        body: apiBody({ action: 'preview_file', file_path: path })
                    });
                    const data = await res.json();
                    if (data.content) {
                        fetchedFiles.push({ path: path, content: b64DecodeUnicode(data.content) });
                    }
                } catch (e) { console.error("Failed to fetch", path); }
            }

            statusEl.innerText = "Generating " + type.toUpperCase() + "...";

            if (type === 'zip') {
                const zip = new JSZip();
                fetchedFiles.forEach(f => {
                    const cleanPath = f.path.startsWith('/') ? f.path.slice(1) : f.path;
                    zip.file(cleanPath, f.content);
                });
                const blob = await zip.generateAsync({type: "blob"});
                const link = document.createElement('a');
                link.href = URL.createObjectURL(blob);
                link.download = `${CONFIG.repoName}-export.zip`;
                link.click();
            } 
            else if (type === 'txt') {
                let giantText = `EXPORT FROM ${CONFIG.repoName}\nDATE: ${new Date().toLocaleString()}\n\n`;
                fetchedFiles.forEach(f => {
                    giantText += `${"=".repeat(60)}\nFILE: ${f.path}\n${"=".repeat(60)}\n\n${f.content}\n\n`;
                });
                const blob = new Blob([giantText], {type: "text/plain"});
                const link = document.createElement('a');
                link.href = URL.createObjectURL(blob);
                link.download = `${CONFIG.repoName}-merged.txt`;
                link.click();
            }
            document.getElementById('export-modal').style.display = 'none';
        } catch (e) {
            alert("Export failed: " + e.message);
            statusEl.innerText = "Error: " + e.message;
        } finally {
            btns.forEach(b => b.disabled = false);
        }
    }

