<script>
  // --- CONFIG & STATE ---
    let CONFIG = { 
        funcUrl: localStorage.getItem('conduit_funcUrl') || '',
        // Project context prefers sessionStorage for tab isolation
        repoName: sessionStorage.getItem('conduit_repoName') || localStorage.getItem('conduit_repoName') || 'IDE',
        projectPath: sessionStorage.getItem('conduit_projectPath') || localStorage.getItem('conduit_projectPath') || '',
        autoFix: sessionStorage.getItem('conduit_auto_fix') === 'true',
        autoSanity: sessionStorage.getItem('conduit_auto_sanity') === 'true',
        showPreview: localStorage.getItem('conduit_showPreview') !== 'false',
        efDeploymentMode: localStorage.getItem('conduit_ef_mode') || 'default',
        wasmValidation: localStorage.getItem('conduit_wasm_validation') !== 'false',
        floatingConsole: localStorage.getItem('conduit_floating_console') === 'true',
        consoleHalf: localStorage.getItem('conduit_console_half') === 'true'
    };

    // Global State
    let sessionLogs = [];
    let dbHistory = [];
    let repoFiles = []; 
    let editHistory = []; 
    let historyIndex = -1;
    let chatHistory = []; 
    let logOffset = 0;
    let historyOffset = 0;
    let isPerformingAction = false;
    let tabScrollPositions = {};
    let sqlHistory = [];
    let sqlHistoryIndex = -1;
    let workflowPage = 1;
    let currentFilterTab = null;
    let filters = {
        patcher: { time: 'all', files: [], categories: ['patch', 'sql', 'ai', 'system'] },
        history: { time: 'all', files: [] },
        cicd: { time: 'all', files: [] }
    };
    let cicdDataRaw = []; // Store raw runs for local filtering

    // --- AI CONFIG STATE ---
    const DEFAULT_AI_CONFIG = {
      providers: {
        'default_main': {
          name: 'DeepSeek V3 (OpenRouter)',
          baseUrl: 'https://openrouter.ai/api/v1/chat/completions',
          model: 'deepseek/deepseek-chat', 
          apiKeyEnv: 'Deepseek_API',
          type: 'openai'
        },
        'default_groq': {
          name: 'GroqCloud',
          baseUrl: 'https://api.groq.com/openai/v1/chat/completions',
          model: 'openai/gpt-oss-120b',
          apiKeyEnv: 'GROQ_API_KEY',
          type: 'openai'
        },
        'default_analyst': {
           name: 'Gemini Flash (Google)',
           baseUrl: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-lite-latest:generateContent',
           model: '',
           apiKeyEnv: 'GEMINI_API_KEY',
           type: 'google'
        }
      },
      roles: {
        chat: 'default_groq',
        architect: 'default_groq',
        fast_fix: 'default_groq',
        analyst: 'default_analyst'
      }
    };

    // Load from local storage or fallback to default
    window.aiConfig = JSON.parse(localStorage.getItem('conduit_ai_config') || 'null') || DEFAULT_AI_CONFIG;

    // Caches
    window.OP_CACHE = {}; 
    window.BUILD_CACHE = {}; 
    let FILE_OP_MAP = {}; 
    let aceEditorInstance = null;
    let originalViewerContent = "";
    let currentViewerPath = "";
    let diffLeft = null;
    let diffRight = null;

    // --- INIT ---
    window.onload = async () => {
        if (window.IS_CONDUIT_PREVIEW) return;

        // Disable automatic scroll restoration
        if ('scrollRestoration' in history) {
            history.scrollRestoration = 'manual';
        }

        // Force scroll reset
        const mv = document.querySelector('.main-view');
        if (mv) mv.scrollTop = 0;

        // Ensure we aren't stuck in fullscreen mode on reload
        document.body.classList.remove('fs-mode');

        // Auto-resize for chat textarea
        const ci = document.getElementById('chat-input');
        if (ci) {
            ci.addEventListener('input', function() {
                this.style.height = '42px';
                this.style.height = (this.scrollHeight) + 'px';
            });
        }

        // Load Settings into UI
        document.getElementById('setting-func-url').value = CONFIG.funcUrl;
        document.getElementById('setting-repo-name').value = CONFIG.repoName;
        document.getElementById('setting-project-path').value = CONFIG.projectPath;
        document.getElementById('setting-auto-fix').checked = CONFIG.autoFix;
        document.getElementById('setting-auto-sanity').checked = CONFIG.autoSanity;
        document.getElementById('setting-show-preview').checked = CONFIG.showPreview;
        document.getElementById('setting-wasm-validation').checked = CONFIG.wasmValidation;
        document.getElementById('setting-ef-mode').value = CONFIG.efDeploymentMode;

        const fc = document.getElementById('setting-floating-console');
        fc.checked = CONFIG.floatingConsole;
        toggleConsoleSubSetting(CONFIG.floatingConsole);
        document.getElementById('setting-console-half').checked = CONFIG.consoleHalf;
        initFloatingHUD();

        renderAIConfigUI(); // Render AI Settings
        applyPreviewTabVisibility(); // Apply visibility on load

        // Restore Editor State (Tab-specific)
        const savedJson = sessionStorage.getItem('conduit_autosave') || localStorage.getItem('conduit_autosave');
        if(savedJson) {
            document.getElementById('json-input').value = savedJson;
            editHistory.push(savedJson);
            historyIndex = 0;
        }

        if(typeof acorn === 'undefined') console.warn("Acorn missing. Syntax checking disabled.");

        // --- CONDUIT INSPECTOR BUS ---
    window.inspectorLogData = [];
    window.ideLogData = [];
    window.inspectorNetData = [];
    window.ideNetData = [];
    window.currentLogSource = 'app';

    // --- HOST IDE LOG & NET INTERCEPTOR ---
    const originalConsole = { ...console };
    ['log', 'warn', 'error', 'info', 'debug'].forEach(method => {
        console[method] = (...args) => {
            const msg = args.map(a => typeof a === 'object' ? JSON.stringify(a, null, 2) : String(a)).join(' ');
            const time = new Date().toLocaleTimeString([], {hour12:false, hour:'2-digit', minute:'2-digit', second:'2-digit'});
            window.ideLogData.push({ method, msg, time });

            const container = document.getElementById('ins-console-ide');
            if (container) renderLogLine(container, method, msg, time);
            originalConsole[method].apply(console, args);
        };
    });

    const originalFetch = window.fetch;
    window.fetch = async (...args) => {
        const start = Date.now();
        const url = args[0];
        const options = args[1] || {};
        try {
            const response = await originalFetch(...args);
            const clone = response.clone();
            const duration = Date.now() - start;
            let resBody = '[Binary Data]';
            try { resBody = await clone.json(); } catch(e) { try { resBody = await clone.text(); } catch(e2){} }

            const netEntry = {
                url, method: options.method || 'GET',
                status: response.status, duration,
                requestBody: options.body || null,
                responseBody: resBody
            };
            window.ideNetData.push(netEntry);
            renderNetworkRow('ide', netEntry);
            return response;
        } catch(err) { throw err; }
    };

    function renderLogLine(container, method, msg, time) {
        const row = document.createElement('div');
        row.className = `ins-row ins-log-${method}`;

        const isMultiline = msg.includes('\n') || msg.length > 120 || msg.includes('stack:');

        if (!isMultiline) {
            row.innerHTML = `<button class="ins-copy-btn" onclick="copyInsEntry(this)">Copy</button>` +
                            `<span style="color:#555; margin-right:10px; font-size:9px;">${time}</span>` +
