    // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
    function applyLocalPatch(content, ops) {
        let lines = content.split('\n');
        let logs = [];
        let success = true;

        if (typeof ops === 'string') {
            try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
        }

        ops.forEach(op => {
            if (op.action === 'comment') return;
            if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }

            if (op.action === 'replace_block') {
                // Strategy 1: Exact String Match (Fastest)
                const currentStr = lines.join('\n');
                if (currentStr.includes(op.find_block)) {
                    lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
                    logs.push('Exact match applied');
                    return;
                }

                // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
                const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
                if (searchLines.length === 0) return;

                let matchStart = -1;
                let matchEnd = -1;

                // Scan file lines
                for (let i = 0; i < lines.length; i++) {
                    // If first line matches (ignoring whitespace)
                    if (lines[i].trim() === searchLines[0]) {
                        // Check subsequent lines
                        let allMatch = true;
                        let fileOffset = 0;
                        let searchOffset = 1;

                        while (searchOffset < searchLines.length) {
                            if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
                            const nextFile = lines[i + fileOffset + 1].trim();
                            // Skip empty lines in file if they aren't in search block
                            if (nextFile === '') {
                                fileOffset++;
                                continue;
                            }
                            if (nextFile !== searchLines[searchOffset]) {
                                allMatch = false;
                                break;
                            }
                            fileOffset++;
                            searchOffset++;
                        }

                        if (allMatch) {
                            matchStart = i;
                            matchEnd = i + fileOffset;
                            break;
                        }
                    }
                }

                if (matchStart !== -1) {
                    // Replace the range of lines
                    const replacement = op.replace_with.split('\n');
                    lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
                    logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
                } else {
                    success = false;
                    logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
                    console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
                }
            }
        });
        return { content: lines.join('\n'), success, logs };
    }



    async function runAutoFixLoop(name, code, errorList) {
        const status = document.getElementById('ef-status-msg');
        let currentCode = code;
        let currentErrors = errorList;

        // Fix one by one (recursive loop)
        async function fixNext(index) {
            if (index >= currentErrors.length) return true; // All initial errors processed

            const err = currentErrors[index];
            status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
            status.style.color = "#eab308"; // Dev yellow

            try {
                // 1. Get Patch from AI
                const res = await fetch(CONFIG.funcUrl, { 
                    method: 'POST', 
                    headers: {'Content-Type': 'application/json'},
                    body: apiBody({ 
                        action: 'propose_syntax_fix', 
                        code: currentCode, 
                        error: err 
                    })
                });
                const data = await res.json();
                const ops = data.operations;

                if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");

                // 2. Apply Patch Locally
                const patchResult = applyLocalPatch(currentCode, ops);
                if (!patchResult.success) throw new Error("Generated patch did not match code.");

                currentCode = patchResult.content;
                document.getElementById('ef-code').value = currentCode; // Update UI

                // 3. Re-Validate
                const scanRes = await fetch(CONFIG.funcUrl, { 
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
                });
                const scanData = await scanRes.json();

                if (scanData.valid) {
                    status.innerText = "✅ Syntax Fixed!";
                    return true;
                } else {
                    // If errors remain, update list and Prompt user
                    currentErrors = scanData.errors;
                    if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
                        // Recursively fix the *new* first error (since layout changed)
                        return await fixNext(0);
                    } else {
                        return false;
                    }
                }

            } catch (e) {
                if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
                    return await fixNext(index);
                } else {
                    return false;
                }
            }
        }

        return await fixNext(0);
    }

    async function deployEdgeFunction() {
        const name = document.getElementById('ef-name').value.trim();
        let code = document.getElementById('ef-code').value.trim();
        const status = document.getElementById('ef-status-msg');

        if (!name) return showGlobalToast("Function name is required", true);
        if (code === "Loading...") return showGlobalToast("Please wait, function is still loading", false);

        localStorage.setItem('conduit_last_ef', name);

        const isEmpty = !code;
        const isModified = !isEmpty && code !== window.EF_ORIGINAL_SOURCE;

        if (isModified) {
            status.innerText = "🧬 Validating Syntax...";
            status.style.color = "var(--ai-accent)";
            try {
                const scanRes = await fetch(CONFIG.funcUrl, { 
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: 'validate_syntax_deep', code_block: code, file_path: 'index.ts' })
                });
                const scanData = await scanRes.json();

                if (!scanData.valid) {
                    const errorListStr = scanData.errors.map(e => `Line ${e.line}: ${e.message}`).join('\n');
                    if (confirm(`Syntax Errors Detected:\n\n${errorListStr}\n\nAttempt Auto-Fix?`)) {
                        const fixed = await runAutoFixLoop(name, code, scanData.errors);
                        if (!fixed) return;
                        code = document.getElementById('ef-code').value; // Update code ref after fix
                    } else return;
                }
            } catch(e) {
                if(!confirm("Syntax check unavailable. Deploy anyway?")) return;
            }
        }

        status.innerText = "⏳ Processing...";
        status.style.color = "var(--ai-accent)";

        try {
            if (isModified) {
                status.innerText = "💾 Syncing local changes...";
                const patchRes = await fetch(CONFIG.funcUrl, {
                    method: 'POST', headers: {'Content-Type': 'application/json'},
                    body: apiBody({ action: 'patch', operations: [{
                        file_path: `supabase/functions/${name}/index.ts`,
                        action: "create_file",
                        content: code
                    }]})
                });
                const patchData = await patchRes.json();
                if (!patchData.success) throw new Error("GitHub sync failed. Check connectivity.");
            }

            // Step 2: Trigger Workflow
            status.innerText = "🚀 Triggering deploy.yml...";
            const deployInputs = { function_name: name };
            const buildRes = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ 
                    action: 'trigger_build', 
                    workflow_id: 'deploy.yml', 
                    branch: 'conduit-dev',
                    inputs: deployInputs
                })
            });
            const buildData = await buildRes.json();

            if (buildData.success) {
                status.innerText = "✅ Dispatched! Redirecting...";
                status.style.color = "var(--prod)";
                setTimeout(() => { 
                    closeEFManager(); 
                    switchTab('tab-cicd', document.querySelectorAll('.nav-item')[4]); 
                    loadWorkflows(); 
                    // Sync Files (new function) and Logs (commit)
                    fetchState(false, true); 
                    fetchFileList();
                }, 1500);
            } else {
                throw new Error(buildData.error || "Workflow trigger failed (No error details provided by server).");
            }
        } catch (e) {
            console.error("❌ Deployment failed:", e);
            status.innerText = "❌ " + (e.message || "Check browser console");
            status.style.color = "var(--danger)";
        }
    }

