    function copyChatMsg(btn) {
        const msgDiv = btn.closest('.msg');
        // Clone to manipulate without affecting UI
        const clone = msgDiv.cloneNode(true);
        // Remove the actions container from the text we copy
        const actions = clone.querySelector('.msg-actions');
        if (actions) actions.remove();

        const text = clone.innerText.trim();
        navigator.clipboard.writeText(text).then(() => {
            const originalIcon = btn.innerText;
