    // --- BUNDLER & PREVIEW ---
    function loadExternalUrl(forcedUrl = null) {
        const input = document.getElementById('browser-url');
        let url = forcedUrl || input.value.trim();
        if (!url) return;

        // Auto-prefix with https if protocol is missing
        if (!/^https?:\/\//i.test(url)) {
            url = 'https://' + url;
            input.value = url;
        }

        const iframe = document.getElementById('preview-frame');
        const display = document.getElementById('preview-url-display');

        // Revoke any existing local blob URLs to free memory
        if (window.PREVIEW_BLOB_URL) {
            URL.revokeObjectURL(window.PREVIEW_BLOB_URL);
            window.PREVIEW_BLOB_URL = null;
        }

        // Critical: Must remove srcdoc attribute entirely for src to take precedence
        iframe.removeAttribute('srcdoc');
        iframe.src = url;

        display.innerText = 'External: ' + url;
        console.log("[Preview] Loading external URL:", url);
    }

    function refreshPreview() {
        const iframe = document.getElementById('preview-frame');
        // If src exists and is not a local blob/srcdoc placeholder, it's an external URL
        if (iframe.hasAttribute('src') && iframe.src !== "") {
            loadExternalUrl();
        } else {
            // Fallback to local bundler
            bundleAndPreview(null);
        }
    }

    async function bundleAndPreview(index) {
        if(!CONFIG.funcUrl) {
            console.error('Bundler Error: No function URL configured');
            return;
        }
        document.querySelectorAll('.runtime-log').forEach(el => el.remove());

        let entry = (typeof index === 'number') ? dbHistory[index] : null;
        let sha = entry ? entry.sha : null;
        let rootPrefix = ''; 
        if (entry && entry.type === 'Prod') {
            const match = entry.title.match(/Deployed\s+(.+)/);
            if (match && match[1]) rootPrefix = match[1];
        }

        // Normalize project root: remove leading/trailing slashes
        let effectiveRoot = (rootPrefix || CONFIG.projectPath || "").trim().replace(/^\/+|\/+$/g, "");
        if (effectiveRoot) effectiveRoot += '/';

        let entryFile = effectiveRoot + 'index.html';
        const iframe = document.getElementById('preview-frame');
        iframe.srcdoc = `<div style="color:#666; font-family:sans-serif; text-align:center; padding:20px;">Initializing Environment...</div>`;

        const fileCache = {}; window.CURRENT_FILE_CACHE = fileCache;

        try {
            const treeRes = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'fetch_tree', project_path: effectiveRoot, ref_sha: sha })
            });
            const treeData = await treeRes.json();
            const files = (treeData.files || []).filter(f => f.path.startsWith(effectiveRoot));

            if (files.length === 0) throw new Error(`No files found in scope: ${effectiveRoot}`);

            const BATCH_SIZE = 12;
            const binaryExts = ['png', 'jpg', 'jpeg', 'gif', 'svg', 'ico', 'woff', 'woff2', 'ttf', 'webp'];
            for (let i = 0; i < files.length; i += BATCH_SIZE) {
                const batch = files.slice(i, i + BATCH_SIZE);
                await Promise.all(batch.map(async (file) => {
                    try {
                        const res = await fetch(CONFIG.funcUrl, {
                            method: 'POST', headers: {'Content-Type': 'application/json'},
                            body: apiBody({ action: 'preview_file', file_path: file.path, ref_sha: sha })
                        });
                        const data = await res.json();
                        if (data.content) {
                            const ext = file.path.split('.').pop().toLowerCase();
                            const isBinary = binaryExts.includes(ext);
                            fileCache[file.path] = { 
                                content: isBinary ? base64ToUint8Array(data.content) : b64DecodeUnicode(data.content),
                                ext, isBinary, sha: file.sha 
                            };
                        }
                    } catch(e) { console.error('Fetch Failed:', file.path, e); }
                }));
            }

            // Robust lookup: check exact, prefixed by repo name, or relative
            let entryContent = fileCache[entryFile] || fileCache['/' + entryFile];

            if (!entryContent && !effectiveRoot) {
                // If looking at root and failing, try RepoName prefix (common in some git setups)
                const repoPrefixed = CONFIG.repoName + '/' + entryFile;
                if (fileCache[repoPrefixed]) {
                    entryContent = fileCache[repoPrefixed];
                    effectiveRoot = CONFIG.repoName + '/';
                    entryFile = repoPrefixed;
                }
            }

            if(!entryContent) {
                console.error("❌ [Bundler] Entry missing. EntryPath:", entryFile, "Cache Keys:", Object.keys(fileCache));
                throw new Error(`Entry file "${entryFile}" not found. The bundler scanned ${Object.keys(fileCache).length} files but couldn't find your index.html point.`);
            }

            const importMap = { imports: { "react": "https://esm.sh/react@18.2.0", "react-dom": "https://esm.sh/react-dom@18.2.0", "react-dom/client": "https://esm.sh/react-dom@18.2.0/client" } };

            for (const fullPath in fileCache) {
                const file = fileCache[fullPath];
                const virtualPath = fullPath.startsWith(effectiveRoot) ? fullPath.substring(effectiveRoot.length) : fullPath;
                const isJs = ['js', 'mjs', 'ts', 'jsx', 'tsx'].includes(file.ext);

                if (isJs) {
                    // Use a more restrictive regex that doesn't cross statement boundaries ([^;\n]*?)
                    // This prevents CSS selectors like '.my-class' from being mistaken for file paths
                    file.content = file.content.replace(/(import|export)([^;\n]*?)(['"])([^'"]+)(['"])/g, (match, keyword, mid, q1, importPath, q2) => {
                        // 1. Keep absolute URLs as is
                        if (importPath.startsWith('http')) return match;

                        // 2. Handle Local Files
                        // Only rewrite if it looks like a file path (has an extension or is a directory jump)
                        if (importPath.startsWith('.') && (importPath.includes('/') || importPath.includes('.'))) {
                            const resolvedFull = resolvePath(fullPath, importPath);
                            if (resolvedFull.startsWith(effectiveRoot)) return `${keyword}${mid}${q1}${resolvedFull.substring(effectiveRoot.length)}${q2}`;
                            return match;
                        }

                        // 3. Handle Bare Specifiers (NPM Packages)
                        // If it's in our manual map (react/react-dom), the browser will handle it via importmap.
                        // Otherwise, redirect to esm.sh for auto-resolution.
                        if (importMap.imports[importPath]) return match;

                        // Avoid rewriting internal virtual paths that might have been registered without extensions
                        if (Object.keys(importMap.imports).some(k => k === importPath || k === './' + importPath)) return match;

                        return `${keyword}${mid}${q1}https://esm.sh/${importPath}${q2}`;
                    });

                    if (['jsx', 'tsx'].includes(file.ext)) {
                        try {
                            const res = Babel.transform(file.content, { presets: [['env', { modules: false }], 'react'], filename: fullPath });
                            file.content = res.code;
                        } catch (e) { throw new Error(`Babel Error in ${fullPath}: ${e.message}`); }
                    }
                }

                if (file.ext === 'css') {
                    const cleanCss = file.content.replace(/`/g, '\\`').replace(/\\/g, '\\\\');
                    file.content = `const s = document.createElement('style'); s.textContent = \`${cleanCss}\`; document.head.appendChild(s);`;
                    file.ext = 'js';
                }

                const mimeMap = { 'js': 'text/javascript', 'jsx': 'text/javascript', 'ts': 'text/javascript', 'tsx': 'text/javascript', 'html': 'text/html', 'css': 'text/css', 'png': 'image/png', 'jpg': 'image/jpeg', 'jpeg': 'image/jpeg', 'svg': 'image/svg+xml' };
                const mime = mimeMap[file.ext] || 'application/octet-stream';
                const blob = new Blob([file.content], { type: mime });
                file.blobUrl = URL.createObjectURL(blob);

                // Register exact path
                importMap.imports[virtualPath] = file.blobUrl;
                importMap.imports['./' + virtualPath] = file.blobUrl;

                // Register path without extension ONLY for scripts (standard ESM behavior)
                const scriptExts = ['js', 'jsx', 'ts', 'tsx', 'mjs'];
                if (virtualPath.includes('.') && scriptExts.includes(file.ext)) {
                    const noExt = virtualPath.split('.').slice(0, -1).join('.');
                    if (!importMap.imports[noExt]) {
                        importMap.imports[noExt] = file.blobUrl;
                        importMap.imports['./' + noExt] = file.blobUrl;
                    }
                }
            }

            const finalEntryContent = entryContent; // Already resolved above
            const doc = new DOMParser().parseFromString(finalEntryContent.content, 'text/html');
            const baseScript = doc.createElement('script');
            baseScript.textContent = `
                window.IS_CONDUIT_PREVIEW = true;
                window.process = { env: { NODE_ENV: "development" } };

                const safeStringify = (obj) => {
                    const cache = new Set();
                    return JSON.stringify(obj, (key, value) => {
                        if (typeof value === 'object' && value !== null) {
                            if (cache.has(value)) return '[Circular]';
                            cache.add(value);
                        }
                        if (value instanceof HTMLElement) return value.outerHTML.substring(0, 100) + '...';
                        return value;
                    }, 2);
                };

                window.onerror = function(msg, url, line, col, error) {
                    window.parent.postMessage({ 
                        type: 'CONDUIT_LOG', method: 'error', 
                        args: ['[RUNTIME ERROR]: ' + msg + ' (' + url + ':' + line + ':' + col + ')'],
                        time: new Date().toLocaleTimeString()
                    }, '*');
                    return false;
                };

                window.localLogs = [];
                window.localNetwork = [];
                ['log', 'warn', 'error', 'debug', 'info'].forEach(method => {
                    const original = console[method];
                    console[method] = (...args) => {
                        const time = new Date().toLocaleTimeString([], {hour12:false, hour:'2-digit', minute:'2-digit', second:'2-digit'});
                        const msg = args.map(a => typeof a === 'object' ? JSON.parse(safeStringify(a)) : a);
                        window.parent.postMessage({ type: 'CONDUIT_LOG', method, args: msg, time }, '*');
                        window.localLogs.push({ method, msg: msg.join(' '), time });
                        original.apply(console, args);
                    };
                });

                const originalFetch = window.fetch;
                window.fetch = async (...args) => {
                    const start = Date.now();
                    const url = args[0];
                    const options = args[1] || {};
                    try {
                        const response = await originalFetch(...args);
                        const clone = response.clone();
                        const duration = Date.now() - start;
                        let resBody = '[Binary Data]';
                        try { resBody = await clone.json(); } catch(e) { try { resBody = await clone.text(); } catch(e2){} }

                        const netEntry = {
                            url, method: options.method || 'GET',
                            status: response.status, duration,
                            requestBody: options.body || null,
                            responseBody: resBody,
                            time: new Date().toLocaleTimeString()
                        };
                        window.parent.postMessage({ type: 'CONDUIT_NETWORK', payload: netEntry }, '*');
                        window.localNetwork.push(netEntry);
                        return response;
                    } catch(err) {
                        window.parent.postMessage({ type: 'CONDUIT_LOG', method: 'error', args: ['Fetch Failed: ' + url, err.message], time: '' }, '*');
                        throw err;
                    }
                };
            `;
            iframe.srcdoc = doc.documentElement.outerHTML;
            if(window.POPOUT_REF && !window.POPOUT_REF.closed) window.POPOUT_REF.location.replace(window.PREVIEW_BLOB_URL);
            document.getElementById('preview-url-display').innerText = sha ? 'Viewing: ' + entry.title : 'Viewing: Live Dev (' + CONFIG.repoName + ')';
            document.getElementById('browser-url').value = '';
                    } catch(e) {
            console.error('CRITICAL BUILD FAILURE:', e);
            iframe.srcdoc = '<div style="color:red; padding:20px;"><b>Preview Error:</b><br>' + e.message + '</div>'; 
        }
    }

    // --- VISUAL ERROR BLAMING ---
    function highlightCulpritOp(opId, error) {
        const allOps = Array.from(document.querySelectorAll('.op-row'));
        const opRow = allOps.find(el => el.getAttribute('onclick') && el.getAttribute('onclick').includes(opId));

