    function closeRenameModal() {
        document.getElementById('rename-overlay').classList.remove('active');
        toggleFab(true);
    }

    async function executeRename() {
        const newPath = document.getElementById('rn-new-path').value.trim();
        if (!newPath || newPath === currentRenamePath) return closeRenameModal();

        if (isPerformingAction) return;
        isPerformingAction = true;
        showGlobalToast("Preparing move...");

        try {
            // 1. Get current content
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', 
                headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'preview_file', file_path: currentRenamePath })
            });
            const data = await res.json();
            if (!data.content) throw new Error("Could not read source file content");

            const ops = [
                { "action": "comment", "text": `[Rename] ${currentRenamePath} -> ${newPath}` },
                { "action": "delete_file", "file_path": currentRenamePath },
                { "action": "create_file", "file_path": newPath, "content": b64DecodeUnicode(data.content) }
            ];

            closeRenameModal();

            // 2. Load into Patcher
            document.getElementById('json-input').value = JSON.stringify(ops, null, 2);
            saveState();

            // 3. Switch to Patcher
            switchTab('tab-patcher', document.querySelectorAll('.nav-item')[1]);

            showGlobalToast("Rename loaded. Review and Test Patch.");

            // 4. Prompt for AI Healing
            setTimeout(() => {
                if (confirm("File moved! Shall I ask AI to scan and heal imports in other files?")) {
                    startNewChat();
                    toggleChat(true);
                    chatHistory.push({ 
                        role: 'user', 
                        text: `I just renamed "${currentRenamePath}" to "${newPath}". Please scan my project and provide a JSON patch to update any other files that import this file.` 
                    });
                    processAIResponse();
                }
            }, 1000);

        } catch (e) {
            alert("Move failed: " + e.message);
        } finally {
            isPerformingAction = false;
        }
    }

