            });
            const data = await res.json();
            if (data.success && data.operations) {
                currentSyntaxContext.ops = data.operations;
                const btn = document.getElementById('btn-auto-fix-wasm');
                btn.style.display = 'block';
                btn.innerHTML = "✨ Apply Deterministic Fix";
            }
        } catch(e) { console.warn("Check fix failed", e); }
    }

    async function applyDeterministicFix() {
