    let runStateCache = {};
    window.WORKFLOW_JOB_CACHE = {}; // Cache for job list HTML

    async function loadWorkflows(silent = false, isAppend = false) {
        const container = document.getElementById('workflow-list');
        if (!isAppend) workflowPage = 1;

        if (!silent && !isAppend && container.children.length === 0) {
            container.innerHTML = '<div style="padding:20px; text-align:center;">Fetching runs...</div>';
        }

        try {
            const res = await fetch(CONFIG.funcUrl, { 
                method: 'POST', headers: {'Content-Type': 'application/json'}, 
                body: apiBody({ action: 'fetch_workflows', page: workflowPage }) 
            });
            lastCicdRefresh = Date.now(); 
            const data = await res.json();

            if (data.runs && data.runs.length < 20) document.getElementById('load-more-cicd-btn').style.display = 'none';
            else document.getElementById('load-more-cicd-btn').style.display = 'block';

            // --- SMART POLLING LOGIC ---
            // 1. Check if we are still on the tab
            const isTabActive = document.getElementById('tab-cicd').classList.contains('active');

            // 2. Check if any runs are active
            const hasActiveRuns = data.runs && data.runs.some(r => r.status === 'in_progress' || r.status === 'queued');

            // 3. Schedule next poll ONLY if needed
            if (isTabActive && hasActiveRuns) {
                setTimeout(() => loadWorkflows(true), 10000);
            }
            // ---------------------------

            // --- AUTOMATION LOOP ---
            if (CONFIG.autoFix && data.runs && data.runs.length > 0) {
                const latest = data.runs[0];
                const fixedKey = 'conduit_fixed_' + latest.id;

                // RECURSION GUARD: Check if the failed commit was already an Auto-Fix
                const isRecursion = latest.head_commit && latest.head_commit.message.includes("[Auto-Fix]");

                if (latest.conclusion === 'failure' && !localStorage.getItem(fixedKey) && !isRecursion) {
                    const toast = document.createElement('div');
                    toast.innerHTML = `<span style="animation:pulse 1s infinite">🤖 Auto-Fixing Run #${latest.run_number}...</span>`;
                    toast.style.cssText = "position:fixed; bottom:150px; left:50%; transform:translateX(-50%); background:#eab308; color:black; padding:10px 20px; border-radius:30px; z-index:9999; font-weight:bold;";
                    document.body.appendChild(toast);

                    localStorage.setItem(fixedKey, 'true');

                    fetch(CONFIG.funcUrl, {
                        method: 'POST', headers: {'Content-Type': 'application/json'},
                        body: apiBody({ action: 'auto_fix_build', run_id: latest.id })
                    }).then(r => r.json()).then(d => {
                        toast.remove();
                        if(d.success) {
                            alert(`🤖 Auto-Fix Applied!\n\nAI successfully generated and committed a patch.`);
                            loadWorkflows(); 
                        }
                    });
                }
            }

            if(!data.runs || data.runs.length === 0) {
                if (!silent && !isAppend) container.innerHTML = '<div style="padding:20px; text-align:center;">No workflow runs found.</div>';
                return;
            }

            const expandedIds = Array.from(container.querySelectorAll('div[id^="wf-jobs-"]'))
                .filter(el => el.style.display !== 'none')
                .map(el => el.id);

            if (!isAppend) container.innerHTML = '';
            if (isAppend) cicdDataRaw = cicdDataRaw.concat(data.runs); else cicdDataRaw = data.runs;
            applyFiltersToCicd(expandedIds);
        } catch(e) {}
    }

    function applyFiltersToCicd(expandedIds = []) {
        const container = document.getElementById('workflow-list');
        const filtered = filterDataset(cicdDataRaw, 'cicd');
        container.innerHTML = '';
        filtered.forEach(run => {
                // --- STATE TRACKING & TOAST ---
                const currentState = run.conclusion || run.status;
                const cachedState = runStateCache[run.id];

                if (cachedState && cachedState !== 'success' && cachedState !== 'failure' && cachedState !== 'cancelled') {
                    if (currentState === 'success') showGlobalToast(`✅ Build #${run.run_number} Succeeded!`);
                    else if (currentState === 'failure') showGlobalToast(`❌ Build #${run.run_number} Failed!`, true);
                }
                runStateCache[run.id] = currentState;
                // ------------------------------

                const color = run.conclusion === 'success' ? 'var(--prod)' : (run.conclusion === 'failure' ? 'var(--danger)' : (run.conclusion === 'cancelled' ? '#666' : '#eab308'));
                const icon = run.conclusion === 'success' ? '✔' : (run.conclusion === 'failure' ? '✖' : (run.conclusion === 'cancelled' ? '⊘' : '●'));
                const div = document.createElement('div');
                div.style.borderBottom = '1px solid var(--border)';
                div.dataset.commitSha = run.head_commit.id;
                div.dataset.runId = run.id;

                const historyMatch = dbHistory.find(h => h.sha === run.head_commit.id);
                const isExpanded = expandedIds.includes(`wf-jobs-${run.id}`);
                const cachedJobs = window.WORKFLOW_JOB_CACHE[run.id] || null;

                div.innerHTML = `
                    <div style="padding:16px; display:flex; align-items:flex-start; gap:14px; cursor:pointer; background:${isExpanded ? '#1a1a1c' : '#111'}; transition: background 0.2s;" 
                         onclick="toggleWorkflowJobs(${run.id}, this)"
                         onmouseover="this.style.background='#161618'"
                         onmouseout="if(document.getElementById('wf-jobs-${run.id}').style.display === 'none') this.style.background='#111'; else this.style.background='#1a1a1c';">

                        <div style="display:flex; flex-direction:column; align-items:center; gap:5px;">
                            <div style="color:${color}; font-size:18px; padding-top:2px;">${icon}</div>
                            <button class="menu-btn favorite-btn" onclick="event.stopPropagation(); toggleFavorite('${run.head_commit.id}', 'Build', {title: '${run.name} #${run.run_number}', run_id: '${run.id}'})" style="padding:0; color:#555; font-size:14px;">★</button>
                        </div>

                        <div style="flex:1; min-width: 0;">
                            <div style="display:flex; align-items:center; gap:8px; margin-bottom:4px;">
                                ${historyMatch ? `<span class="status-pill" style="background:var(--primary-dim); color:var(--primary); font-size:10px; padding: 2px 6px; border-radius: 4px;">#${historyMatch.conduit_id}</span>` : ''}
                                ${run.head_commit.message.includes('[Auto-Fix]') ? '<span class="status-pill" style="background:rgba(217,70,239,0.2); color:#d946ef; font-size:10px; padding: 2px 6px; border-radius: 4px; border:1px solid rgba(217,70,239,0.3);">🤖 AI</span>' : ''}
                                <span style="font-weight:600; font-size:14px; color:#eee;">${run.name}</span>
                                <span style="font-weight:400; color:#666; font-size:12px;">#${run.run_number}</span>
                            </div>
                            <div style="font-size:12px; color:#aaa; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; font-family:'JetBrains Mono', monospace;">
                                ${run.head_commit.message.split('\n')[0]}
