            const html = data.jobs.map(job => {
                    const statusColor = job.conclusion === 'success' ? 'var(--prod)' : (job.conclusion === 'failure' ? 'var(--danger)' : '#888');
                    const isFail = job.conclusion === 'failure';
                    return `
                    <div style="padding:8px 12px 8px 45px; display:flex; justify-content:space-between; align-items:center; border-bottom:1px solid #111; font-size:12px;">
