                            ${isFail ? `<button class="icon-btn" style="color:${statusColor}; border-color:#333;" onclick="viewJobSummary(${job.id}, '${job.name}', event)" title="View Summary"><svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg></button>` : ''}
                            <button class="icon-btn" style="color:#aaa; border-color:#333;" onclick="downloadJobLogs(${job.id}, '${job.name}')">⬇</button>
