        if (tab === 'patcher') {
            let catHtml = `<div class="input-label" style="margin-top:20px;">Log Categories</div><div class="card" style="padding:0; margin-top:10px;">`;
            const cats = [
                { id: 'patch', label: '📄 Code Patches' },
                { id: 'sql', label: '🗄️ Database Queries' },
                { id: 'ai', label: '🧠 AI Insights' },
                { id: 'system', label: '📡 System Events' }
            ];
            catHtml += cats.map(c => `
                <label class="filter-checkbox-item">
                    <input type="checkbox" class="filter-cat-check" value="${c.id}" ${filters.patcher.categories.includes(c.id) ? 'checked' : ''}>
                    <span>${c.label}</span>
                </label>
            `).join('');
            catHtml += `</div>`;
            listContainer.innerHTML = catHtml + `<div class="input-label" style="margin-top:20px;">Files Involved</div>` + `<div class="card" style="padding:0; margin-top:10px;">` + (uniqueFiles.length === 0 ? '<div style="padding:20px; text-align:center; color:#666;">No files found.</div>' : uniqueFiles.map(f => `<label class="filter-checkbox-item"><input type="checkbox" class="filter-file-check" value="${f}" ${filters.patcher.files.includes(f) || filters.patcher.files.length === 0 ? 'checked' : ''}><span>${f}</span></label>`).join('')) + `</div>`;
        } else {
