    function applyActiveFilters() {
        const selectedFiles = Array.from(document.querySelectorAll('.filter-file-check:checked')).map(cb => cb.value);
        const allChecks = document.querySelectorAll('.filter-file-check');
        filters[currentFilterTab].files = (selectedFiles.length === allChecks.length) ? [] : selectedFiles;

        if (currentFilterTab === 'patcher') {
            filters.patcher.categories = Array.from(document.querySelectorAll('.filter-cat-check:checked')).map(cb => cb.value);
            applyFiltersToPatcher();
        }
        else if (currentFilterTab === 'history') applyFiltersToHistory();
        else if (currentFilterTab === 'cicd') applyFiltersToCicd();

        closeFilterOverlay();
    }

    function closeFilterOverlay() { document.getElementById('filter-overlay').classList.remove('active'); }

    function filterDataset(items, tab) {
        const f = filters[tab];
        const now = Date.now();

        return items.filter(item => {
            // 1. Time Filter
            if (f.time !== 'all') {
                const ts = new Date(item.created_at).getTime();
                const diff = now - ts;
                if (f.time === 'hour' && diff > 3600000) return false;
                if (f.time === 'today' && diff > 86400000) return false;
                if (f.time === 'week' && diff > 604800000) return false;
            }

            // 2. File Filter
            if (f.files.length > 0) {
                let touchedFiles = [];
                if (tab === 'history') touchedFiles = (item.ops || []).map(o => o.file_path || '');
                if (tab === 'patcher') {
                    // Patcher logic is handled by applyFiltersToPatcher, but we add safety here
                    touchedFiles = (item.results || []).map(r => r.file);
                }
                if (tab === 'cicd') {
                    const match = dbHistory.find(h => h.sha === item.head_commit.id);
                    touchedFiles = match ? (match.ops || []).map(o => o.file_path || '') : [];
                }
                // Filter out empty paths
                touchedFiles = touchedFiles.filter(p => p !== '');
                if (touchedFiles.length > 0 && !touchedFiles.some(tf => f.files.includes(tf))) return false;
            }
            return true;
        });
    }

    function applyFiltersToHistory() {
        renderHistory(filterDataset(dbHistory, 'history'));
    }

    function applyFiltersToPatcher() {
        const f = filters.patcher;
        const now = Date.now();
        document.querySelectorAll('#terminal-list .log-entry').forEach(el => {
            // Skip runtime logs
            if (el.classList.contains('runtime-log')) return;

            const respData = el.querySelector('textarea[id$="-response-data"]')?.value;
            if (!respData) return;
            const resp = JSON.parse(respData);

            let visible = true;
            // Time Filter
            if (f.time !== 'all') {
                const ts = el.id.startsWith('term-saved-') ? new Date(resp.created_at).getTime() : parseInt(el.id.replace('term-', ''));
                const diff = now - ts;
                if (f.time === 'hour' && diff > 3600000) visible = false;
                else if (f.time === 'today' && diff > 86400000) visible = false;
            }
            // Category Filter
            if (visible && f.categories && !f.categories.includes(el.dataset.category)) visible = false;

            // File Filter
            if (visible && f.files.length > 0) {
                const files = resp.results ? resp.results.map(r => r.file) : [];
                if (files.length > 0 && !files.some(path => f.files.includes(path))) visible = false;
            }
            el.style.display = visible ? 'block' : 'none';
        });
    }

