    async function scanRepoForFunctions(repoName, isDeep) {
        const list = document.getElementById('discovery-list');
        const targetRepo = repoName === 'current_deep' ? CONFIG.repoName : repoName;

        document.getElementById('disc-title').innerText = `Scanning: ${targetRepo}`;
        list.innerHTML = '<div style="padding:20px; text-align:center;">Scanning file tree...</div>';

        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: { 'Content-Type': 'application/json' },
                body: apiBody({ action: 'fetch', repo_name: targetRepo })
            });
            const data = await res.json();

            const functions = [];
            (data.files || []).forEach(f => {
                const isMatch = isDeep 
                    ? f.path.endsWith('index.ts')
                    : (f.path.includes('supabase/functions/') && f.path.endsWith('index.ts'));

                if (isMatch) {
                    let name = "";
                    if (f.path.includes('supabase/functions/')) {
                        const parts = f.path.split('supabase/functions/')[1].split('/');
                        name = parts[0];
                    } else {
                        const parts = f.path.split('/');
                        name = parts.length > 1 ? parts[parts.length - 2] : 'root';
                    }
                    // CRITICAL: Explicitly bind the repo name here
                    functions.push({ name: name, path: f.path, repo: targetRepo, type: "function" });
                }
            });

            if (functions.length === 0) list.innerHTML = '<div style="padding:20px; text-align:center; color:#666;">No functions found.</div>';
            else {
                currentDiscoveryItems = functions;
                renderDiscoveryList(functions, 'function');
            }

        } catch(e) { list.innerHTML = `<div style="color:var(--danger)">Error: ${e.message}</div>`; }
    }

    function renderDiscoveryList(items, mode) {
        const list = document.getElementById('discovery-list');
        list.innerHTML = items.map(item => {
            // Logic: Is this a foreign repo?
            const isForeign = item.repo && item.repo !== CONFIG.repoName;
            const isFunction = item.type === 'function';

            let actionBtn = '<span style="color:#666;">›</span>';
            let clickAction = mode === 'source' 
                ? (item.id === 'current_deep' ? `scanRepoForFunctions('current_deep', true)` : `scanRepoForFunctions('${item.name}', false)`)
                : `importFunction('${item.repo}', '${item.path}', '${item.name}')`;

            if (isFunction) {
                if (isForeign) {
                    // Foreign Repo: Show Remote Deploy Button
                    actionBtn = `<button class="btn-prod" onclick="event.stopPropagation(); triggerRemoteDeploy('${item.repo}', '${item.name}')" style="padding:4px 10px; font-size:10px; height:auto; color:white;">🚀 Deploy Remote</button>`;
                    // Clicking the row still imports for viewing, but button triggers deploy
                } else {
                    // Local Repo: Show Import
                    actionBtn = `<button class="btn-primary" style="padding:2px 8px; font-size:10px; height:auto;">Import</button>`;
                }
            }

            return `
            <div class="model-item" onclick="${clickAction}" style="cursor:pointer;">
                <div style="display:flex; align-items:center; gap:10px; flex:1;">
                    <span style="font-size:16px;">${item.type === 'function' ? '⚡' : (item.type === 'special' ? '🔍' : '📦')}</span>
                    <div style="display:flex; flex-direction:column;">
                        <span style="font-weight:500; color:#eee;">${item.name}</span>
                        ${item.path ? `<small style="color:#666; font-size:9px;">${item.path}</small>` : ''}
                    </div>
                </div>
                ${actionBtn}
            </div>`;
        }).join('');
    }

    function filterDiscoveryList(q) {
        const query = q.toLowerCase();
        const filtered = currentDiscoveryItems.filter(i => 
            i.name.toLowerCase().includes(query) || 
            (i.path && i.path.toLowerCase().includes(query))
        );
        // Determine mode based on the first item type in the UNFILTERED list to maintain UI consistency
        const mode = currentDiscoveryItems.some(i => i.type === 'function') ? 'function' : 'source';
        renderDiscoveryList(filtered, mode);
    }

    async function triggerRemoteDeploy(repo, funcName) {
        if (!confirm(`🚀 Trigger deployment for '${funcName}' inside remote repo '${repo}'?`)) return;

        showGlobalToast(`Signaling ${repo}...`);
        try {
