    function syncSelectAllState() {
        const master = document.getElementById('master-file-check');
        if (!master) return;
        const checks = Array.from(document.querySelectorAll('#file-list-container .file-check'));
        if (checks.length === 0) return;

        const allChecked = checks.every(c => c.checked);
        const someChecked = checks.some(c => c.checked);

        master.indeterminate = someChecked && !allChecked;
        master.checked = allChecked;
