    function saveState() {
        const val = document.getElementById('json-input').value;
        // Isolated tab save
        sessionStorage.setItem('conduit_autosave', val);
        // Global fallback for persistence
        localStorage.setItem('conduit_autosave', val);

        if (historyIndex === -1 || editHistory[historyIndex] !== val) {
            editHistory = editHistory.slice(0, historyIndex + 1);
            editHistory.push(val);
            historyIndex++;
        }
    }

    function editorUndo() {
        if (historyIndex > 0) {
            historyIndex--;
            document.getElementById('json-input').value = editHistory[historyIndex];
        }
    }

    function editorRedo() {
        if (historyIndex < editHistory.length - 1) {
            historyIndex++;
            document.getElementById('json-input').value = editHistory[historyIndex];
        }
    }

    function clearEditor() {
        document.getElementById('json-input').value = '';
        saveState();
    }

