    async function undoLog(domId, shaBefore) {
        if (!confirm("Undo this patch? The repository will be restored to its state before this operation.")) return;

        showGlobalToast("⏪ Rolling back...");
        try {
            const res = await fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'rollback', ref_sha: shaBefore })
            });
            const data = await res.json();

            if (data.success) {
                const el = document.getElementById(domId);
                if (el) {
                    el.style.transform = 'translateX(100%)';
                    el.style.opacity = '0';
                    el.style.transition = 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)';
                    setTimeout(() => {
                        el.remove();
                        fetchFileList();
                        fetchState(false, false);
                        showGlobalToast("✨ Patch undone successfully");
                        // Auto-rebuild preview to match state after undo
                        setTimeout(() => bundleAndPreview(null), 800);
                    }, 400);
                }
            } else throw new Error(data.error || "Rollback failed");
        } catch (e) {
            showGlobalToast(e.message, true);
        }
    }

