    function saveSqlState() {
        const val = document.getElementById('sqlEditor').value;
        if (!val.trim() && sqlHistory.length === 0) return;

        if (sqlHistoryIndex === -1 || sqlHistory[sqlHistoryIndex] !== val) {
            // If we are editing in the middle of history, clear forward history (standard undo/redo behavior)
            sqlHistory = sqlHistory.slice(0, sqlHistoryIndex + 1);
            sqlHistory.push(val);
            sqlHistoryIndex++;

            // Cap history at 50 items to keep localStorage clean
            if (sqlHistory.length > 50) {
                sqlHistory.shift();
                sqlHistoryIndex--;
            }

            persistSqlHistory();
        }
    }

    function persistSqlHistory() {
        localStorage.setItem('conduit_sql_history', JSON.stringify(sqlHistory));
        localStorage.setItem('conduit_sql_index', sqlHistoryIndex.toString());
    }

    function undoSql() {
        if (sqlHistoryIndex > 0) {
            sqlHistoryIndex--;
            document.getElementById('sqlEditor').value = sqlHistory[sqlHistoryIndex];
            persistSqlHistory();
        }
    }

    function redoSql() {
        if (sqlHistoryIndex < sqlHistory.length - 1) {
            sqlHistoryIndex++;
            document.getElementById('sqlEditor').value = sqlHistory[sqlHistoryIndex];
            persistSqlHistory();
        }
    }

