    function extractTableNames(sql) {
        if (!sql) return [];
        const tables = [];
        const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];

        // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
        const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
        // Pattern 2: Metadata queries (WHERE table_name = '...')
        const metaRegex = /table_name\s*=\s*'([^']+)'/gi;

        let match;
        while ((match = fromRegex.exec(sql)) !== null) {
            const name = match[1];
            if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
                tables.push(name);
            }
        }

        while ((match = metaRegex.exec(sql)) !== null) {
            const name = match[1];
            if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
                tables.push(name);
            }
        }

        return tables;
    }

    function convertToCSV(resultObj) {
        const data = resultObj.data || [];
        if (!data.length) return '';

        const tables = extractTableNames(resultObj.sql);
        const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';

        const headers = Object.keys(data[0]);
        const rows = data.map(row => 
            headers.map(header => {
                let cell = row[header] === null || row[header] === undefined ? '' : row[header];
                if (typeof cell === 'object') cell = JSON.stringify(cell);
                return '"' + String(cell).replace(/"/g, '""') + '"';
            }).join(',')
        );
        return metaHeader + [headers.join(','), ...rows].join('\n');
    }

