        const input = document.getElementById('tester-userInput');
        const container = document.getElementById('tester-chat-container');
        const text = input.value.trim();

        if (!key || !model || !text) return showGlobalToast("Check Key, Model, and Message", true);

        appendTesterMsg(text, 'tester-user');
        input.value = '';
        const botMsgDiv = appendTesterMsg("...", 'tester-bot');

        try {
            const res = await fetch('https://generativelanguage.googleapis.com/v1beta/' + model + ':generateContent?key=' + key, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ contents: [{ parts: [{ text: text }] }] })
            });

            const data = await res.json();
            if (data.error) throw new Error(data.error.message);
            const responseText = data.candidates[0].content.parts[0].text;
            botMsgDiv.innerText = responseText;
        } catch (e) { botMsgDiv.innerText = "Error: " + e.message; }
        container.scrollTop = container.scrollHeight;
    }

    function appendTesterMsg(text, sender) {
        const div = document.createElement('div');
        div.className = 'tester-msg ' + sender;
        div.innerText = text;
        document.getElementById('tester-chat-container').appendChild(div);
        return div;
    }

    let activeKeysToTest = [];

    function setTesterUI(mode) {
        const isBatch = mode === 'batch';
        document.getElementById('tester-view-manual').style.display = isBatch ? 'none' : 'flex';
        document.getElementById('tester-view-batch').style.display = isBatch ? 'block' : 'none';

        document.getElementById('seg-manual').classList.toggle('active', !isBatch);
        document.getElementById('seg-batch').classList.toggle('active', isBatch);

        if (isBatch) loadTesterKeys();
    }

    function openKeyImporter() {
        document.getElementById('key-importer-overlay').style.display = 'flex';
        document.getElementById('key-import-area').value = '';
        document.getElementById('key-import-area').focus();
    }

    function handleKeyImportInput(el) {
        const raw = el.value;
        if (!raw.includes('AIza')) return;

        // Extract all instances starting with AIza followed by alphanumeric characters
        const matches = raw.match(/AIza[a-zA-Z0-9_-]+/g);
        if (matches) {
            const uniqueKeys = [...new Set(matches)];
            const structured = uniqueKeys.join('\n');

            // Only update if the content has actually changed to avoid cursor jumping
            if (el.value !== structured) {
                el.value = structured;
                showGlobalToast(`✨ Detected ${uniqueKeys.length} keys`);
            }
        }
    }

    function executeKeyImport() {
        const structured = document.getElementById('key-import-area').value.trim();
        if (!structured) return;

        const keys = structured.split('\n').map(k => k.trim()).filter(k => k.startsWith('AIza'));

        if (keys.length === 0) return showGlobalToast("No valid keys to import", true);

        const values = keys.map((k, i) => `('gemini', '${k}', 'Imported Key ${i + 1}')`).join(',\n    ');
        const sql = `-- KEY IMPORT: Generated by Smart Importer\n-- Processing ${keys.length} structured keys\nINSERT INTO public.api_keys (service, api_key, name)\nVALUES\n    ${values};`;

        document.getElementById('key-importer-overlay').style.display = 'none';
        transitionToSql(sql);
    }

    function openTesterPaste() {
        document.getElementById('tester-paste-overlay').style.display = 'flex';
        const saved = localStorage.getItem('conduit_manual_batch_keys');
        if (saved) document.getElementById('tester-paste-area').value = saved;
    }

    function saveTesterPaste() {
        const val = document.getElementById('tester-paste-area').value;
        localStorage.setItem('conduit_manual_batch_keys', val);
        document.getElementById('tester-paste-overlay').style.display = 'none';
        if (document.getElementById('tester-source-select').value === 'manual') loadTesterKeys();
    }

    async function loadTesterKeys() {
        const source = document.getElementById('tester-source-select').value;
        const container = document.getElementById('key-validation-container');
        const totalLabel = document.getElementById('count-total-keys');
        const validLabel = document.getElementById('count-valid-keys');

        container.innerHTML = '<div class="text-center py-20 text-slate-500">Preparing list...</div>';
        validLabel.innerText = '0';
        activeKeysToTest = [];

        try {
            let keys = [];
            if (source === 'database') {
                const SB_URL = "https://xvldfsmxskhemkslsbym.supabase.co";
                const SB_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inh2bGRmc214c2toZW1rc2xzYnltIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjI2ODgxNzksImV4cCI6MjA3ODI2NDE3OX0.5arqrx8Tt7v-hpXpo_ncoK4IX8th9IibxAuv93SSoOU";
                const res = await fetch(SB_URL + '/rest/v1/api_keys?service=eq.gemini&select=*', { headers: { "apikey": SB_KEY, "Authorization": "Bearer " + SB_KEY } });
                keys = await res.json();
            } else {
                const raw = localStorage.getItem('conduit_manual_batch_keys') || '';
                keys = raw.split('\n').map(k => k.trim()).filter(k => k).map((k, i) => ({ name: 'Manual Key ' + (i+1), api_key: k }));
            }

            activeKeysToTest = keys;
            totalLabel.innerText = keys.length;
            container.innerHTML = '';

            if (keys.length === 0) {
                container.innerHTML = '<p class="text-center text-slate-500 py-10">No keys found in ' + source + '.</p>';
                return;
            }

            keys.forEach((keyData, idx) => {
                const row = document.createElement('div');
                row.id = 'tester-row-' + idx;
                row.className = "bg-slate-800/40 border border-slate-800 p-5 rounded-2xl shadow-inner";
                row.innerHTML = `
                    <div class="flex justify-between items-start mb-2">
                        <div class="flex-1">
                            <h3 class="text-sm font-black text-slate-200 uppercase tracking-tight">${keyData.name}</h3>
                            <p class="text-[10px] text-slate-600 font-mono">${keyData.api_key.substring(0, 16)}...</p>
                        </div>
                        <div class="status-badge px-2 py-1 rounded-md text-[9px] font-black bg-slate-800 text-slate-500 border border-slate-700">READY</div>
                    </div>
                    <div class="flex items-center justify-between border-t border-slate-800/50 mt-3 pt-3">
                        <div class="result-area text-[11px] font-medium"></div>
                        <button onclick="validateTesterKey('${keyData.api_key}', document.getElementById('tester-row-${idx}'), true)" class="w-8 h-8 rounded-full bg-blue-500/10 flex items-center justify-center text-blue-500 border border-blue-500/20 active:scale-90">
                            <svg width="14" height="14" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg>
                        </button>
                    </div>`;
                container.appendChild(row);
            });
        } catch (err) { container.innerHTML = '<div class="p-4 bg-red-900/20 text-red-200 rounded-xl">Error: ' + err.message + '</div>'; }
    }

    async function runBatchTest() {
        if (activeKeysToTest.length === 0) return alert("Load some keys first.");
        const btn = document.getElementById('tester-start-batch-btn');

        btn.disabled = true; 
        btn.innerText = "TESTING...";

        const validLabel = document.getElementById('count-valid-keys');
        const exhaustedLabel = document.getElementById('count-exhausted-keys');
        const bannedLabel = document.getElementById('count-banned-keys');

        validLabel.innerText = '0';
        exhaustedLabel.innerText = '0';
        bannedLabel.innerText = '0';

        let validCount = 0, exhaustedCount = 0, bannedCount = 0;

        // Concurrent run
        const promises = activeKeysToTest.map(async (keyData, idx) => {
            const row = document.getElementById('tester-row-' + idx);
            await validateTesterKey(keyData.api_key, row);

            // Re-check the status updated on the object by validateTesterKey
            const s = keyData.last_status;
            const m = (keyData.last_msg || "").toLowerCase();

            if (s == 200) {
                validCount++;
                validLabel.innerText = validCount;
            } else if (s == 429 || s === "RESOURCE_EXHAUSTED") {
                exhaustedCount++;
                exhaustedLabel.innerText = exhaustedCount;
            } else if (s == 403 || s === "PERMISSION_DENIED" || m.includes("not found") || m.includes("revoked")) {
                bannedCount++;
                bannedLabel.innerText = bannedCount;
            }
        });

        await Promise.all(promises);
        btn.disabled = false;
        btn.innerText = "START TEST";
        document.getElementById('tester-batch-actions').classList.remove('hidden');
        showGlobalToast("Batch Test Complete");
    }

    async function validateTesterKey(apiKey, element, isSingle = false) {
        const resultArea = element.querySelector('.result-area');
        const badge = element.querySelector('.status-badge');
        const model = document.getElementById('tester-batch-modelList').value;

        badge.innerText = "PINGING...";
        badge.className = "status-badge px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter bg-slate-700 text-blue-400";
        if (isSingle) resultArea.innerHTML = '';

        try {
            // Use selected model from the batch dropdown
            const url = 'https://generativelanguage.googleapis.com/v1beta/' + model + ':generateContent?key=' + apiKey;
            const res = await fetch(url, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ contents: [{ parts: [{ text: "Hello, respond with exactly one word: 'OK'." }] }] })
            });
            const data = await res.json();
            const keyObj = activeKeysToTest.find(k => k.api_key === apiKey);

            if (res.ok) {
                badge.innerText = "SUCCESS";
                badge.className = "status-badge px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter bg-teal-900/40 text-teal-400";
                resultArea.innerHTML = `<p style="color:#10b981; font-size:12px; margin-top:4px;">✓ Response: ${data.candidates[0].content.parts[0].text.trim()}</p>`;
                if(keyObj) { keyObj.last_status = 200; keyObj.last_msg = "OK"; }
                return true;
            } else {
                const status = data.error?.code || res.status;
                const msg = data.error?.message || "Unknown Error";
                badge.innerText = status;
                badge.className = "status-badge px-2 py-1 rounded text-[10px] font-black uppercase tracking-tighter bg-red-900/40 text-red-400";
                resultArea.innerHTML = `<p style="color:#ef4444; font-size:11px; margin-top:4px; font-family:monospace;">✕ ${msg}</p>`;
                if(keyObj) { keyObj.last_status = status; keyObj.last_msg = msg; }
                return false;
            }
        } catch (err) {
            badge.innerText = "FAILED";
            resultArea.innerHTML = '<p style="color:#ef4444; font-size:11px; margin-top:4px;">✕ Network Error</p>';
            return false;
        }
    }

    function copyTesterReport() {
        let report = `KEY TEST AUDIT REPORT\nGenerated: ${new Date().toLocaleString()}\n${'='.repeat(30)}\n\n`;
        activeKeysToTest.forEach(k => {
            // Export full keys for administrative use
            report += `Name: ${k.name || 'Unnamed'}\nKey: ${k.api_key}\nStatus: ${k.last_status || 'NOT TESTED'}\nMessage: ${k.last_msg || 'N/A'}\n${'-'.repeat(20)}\n`;
        });
        navigator.clipboard.writeText(report).then(() => showGlobalToast("Full audit report copied!"));
    }

    function transitionToSql(sql) {
        closeKeyManager();
        setTimeout(() => {
            openSQLExecutor();
            const editor = document.getElementById('sqlEditor');
            editor.value = sql;
            editor.focus();
            saveSqlState();
            showGlobalToast("SQL Generator: Script Prepared");
        }, 400);
    }

    function cooldownRateLimitedKeys() {
        const limited = activeKeysToTest.filter(k => k.last_status == 429 || k.last_status === "RESOURCE_EXHAUSTED");
        if (limited.length === 0) return showGlobalToast("No rate-limited keys found", true);

        const keys = limited.map(k => `'${k.api_key}'`).join(', ');
        const sql = `-- AUTO-COOLDOWN: Generated by Key Tester\n-- Targeting ${limited.length} keys that hit rate limits\nUPDATE public.api_keys \nSET cooldown_until = NOW() + INTERVAL '1 hour',\n    is_active = true\nWHERE api_key IN (${keys});`;

        transitionToSql(sql);
    }

    function removeBannedKeys() {
        const banned = activeKeysToTest.filter(k => k.last_status == 403 || k.last_status === "PERMISSION_DENIED" || (k.last_msg && k.last_msg.toLowerCase().includes("api key not found")));
        if (banned.length === 0) return showGlobalToast("No banned keys found", true);

        const keys = banned.map(k => `'${k.api_key}'`).join(', ');
        const sql = `-- REAPER: Generated by Key Tester\n-- Deleting ${banned.length} keys that are revoked/banned\nDELETE FROM public.api_keys \nWHERE api_key IN (${keys});`;

        transitionToSql(sql);
    }

    function downloadSqlCsv() {
        if (!lastSqlResultData || lastSqlResultData.isError) return;
        const csvContent = convertToCSV(lastSqlResultData);
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');

        const tables = extractTableNames(lastSqlResultData.sql);
        const tableSlug = tables.length > 0 ? tables.join('_').substring(0, 30) + '_' : '';
        const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 10);

        link.setAttribute('href', url);
        link.setAttribute('download', `${tableSlug}export_${timestamp}.csv`);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        showGlobalToast('CSV Download Started');
    }
</script>
</body>

</html>



