/* --- CORE SETUP & THEME VARIABLES --- */
:root {
    --bg-dark: #0c0c0c;
    --surface-dark: #1e1e1e;
    --text-primary-dark: #e1e1e1;
    --text-secondary-dark: #a0a0a0;
    --accent-teal: #42d7b8;
    --purple-glow: #9b59b6;
    --border-color: rgba(255, 255, 255, 0.1);
    --bronze-dark: #4d3a1f;
    --bronze-light: #c8a876;
    --linkoin-gold: #FFD700;
    --linkoin-gold-glow: rgba(255, 215, 0, 0.4);
    --radius-main: 20px;
    --nav-height: 55px; /* Slimmer height */
    --cyber-gold: #b1d34b;
    --progress-percentage: 76%;
    --warning-glow: #ffab40;
    --glass-bg: rgba(30, 30, 30, 0.5);
    --glass-border: rgba(255, 255, 255, 0.1);
}
* {
    margin: 0; padding: 0; box-sizing: border-box;
    font-family: 'Poppins', 'Segoe UI', system-ui, sans-serif;
    -webkit-tap-highlight-color: transparent;
}
html, body, #root {
    height: 100dvh;
    overflow: hidden;
    background-color: var(--bg-dark);
    color: var(--text-primary-dark);
}
body.library-open { overflow: hidden; }

/* --- LAYOUT & MAIN APP STYLES --- */
.app-container {
    height: 100%;
    width: 100%;
    margin: 0 auto;
    position: relative;
    display: flex;
    flex-direction: column;
    background-color: var(--bg-dark);
    transition: all 0.3s ease;
}

/* Only restrict width on mobile */
@media (max-width: 899px) {
    .app-container { max-width: 500px; border-right: 1px solid var(--border-color); border-left: 1px solid var(--border-color); }
}

.main-content {
    flex-grow: 1;
    overflow: hidden;
    position: relative;
}
.tab-content {
    display: flex;
    height: 100%;
    flex-direction: column;
}
/* In React we render conditionally, so we don't strictly need .active display logic, but keeping it for structure */
.tab-content .page-content { padding: 1.5rem; } 
.tab-content > .scrollable-content { flex-grow: 1; overflow-y: auto; }
.tab-content > .scrollable-content::-webkit-scrollbar { display: none; }

.icon-button {
    background: none; border: none;
    color: var(--text-primary-dark);
    font-size: 1.2rem; cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    height: 2.5rem; width: 2.5rem;
}

/* --- SHARED & REUSABLE COMPONENTS --- */
.section-title { font-size: 0.9rem; font-weight: 600; color: var(--text-secondary-dark); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 1rem; display: flex; justify-content: space-between; align-items: center; }
.section-title a { font-size: 0.8rem; text-decoration: none; color: var(--accent-teal); }
.profile-avatar { width: 40px; height: 40px; border-radius: 50%; object-fit: cover; border: 2px solid var(--accent-teal); cursor: pointer; }

/* --- DISCOVER TAB STYLES --- */
#discover-content { flex-direction: column; }
#discover-header { display: flex; align-items: center; justify-content: space-between; padding: 1rem 1.5rem; flex-shrink: 0; position: sticky; top: 0; z-index: 100; background: rgba(12, 12, 12, 0.8); backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px); border-bottom: 1px solid var(--border-color); }
.discover-title { font-family: 'Newsreader', serif; font-size: 2rem; font-weight: 500; line-height: 1; background: linear-gradient(45deg, var(--text-primary-dark) 60%, var(--accent-teal)); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
#discover-header .header-actions { display: flex; align-items: center; gap: 1rem; }
#discover-header .profile-avatar { width: 36px; height: 36px; }
.discover-sub-nav { display: flex; border-bottom: 1px solid var(--border-color); flex-shrink: 0; position: sticky; top: 70px; z-index: 90; background: rgba(12, 12, 12, 0.8); backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px); }
.discover-sub-nav .nav-item { flex: 1; padding: 1rem 0; text-align: center; font-weight: 600; color: var(--text-secondary-dark); cursor: pointer; position: relative; }
