        .entre-section-h { font-weight: bold; font-size: 18px; margin: 25px 0 12px 0; }
        .entre-case-box { border: 1.5px solid #000; padding: 15px 25px; margin: 20px 0; background: #fff; }
        .entre-case-label { font-weight: bold; display: block; margin-bottom: 10px; font-size: 17px; }
        .entre-activity-box { border: 1px solid #000; padding: 15px; margin: 20px 0; }
        .entre-activity-label { background: #000; color: #fff; padding: 2px 10px; font-weight: bold; margin-bottom: 10px; display: inline-block; }
        .entre-reflection-box { background: var(--entre-grey); border: 1px dashed #444; padding: 15px; margin: 15px 0; font-style: italic; }
        .entre-likert-table { width: 100%; border-collapse: collapse; margin: 15px 0; font-size: 13px; }
        .entre-likert-table th { background: var(--entre-grey); border: 1px solid #000; padding: 5px; text-align: center; }
        .entre-likert-table td { border: 1px solid #000; padding: 8px; }
        .entre-ansoff-matrix { display: table; width: 100%; border-collapse: separate; border-spacing: 10px; table-layout: fixed; }
        .entre-ansoff-quadrant { display: table-cell; border: 2px solid var(--entre-blue); background: #f8f9fa; padding: 15px; vertical-align: middle; text-align: center; font-weight: bold; height: 120px; }
        .entre-label-axis { font-weight: bold; color: var(--entre-blue); font-size: 12px; text-transform: uppercase; }

        /* HISTORY ENGINE STYLES */
        .history-canvas { position: relative; overflow: hidden; }
        .history-watermark::before {
            content: 'History of Ethiopia and the Horn Module (Hist.1102)';
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%) rotate(-45deg);
            font-size: 45px;
            color: rgba(200, 200, 200, 0.15);
            white-space: nowrap;
            z-index: 0;
            pointer-events: none;
            font-family: var(--font-serif);
        }
        .history-header-text {
            text-align: center;
            font-style: italic;
            font-weight: bold;
            font-size: 14px;
            margin-bottom: 30px;
        }
        .history-unit-title {
            text-align: center;
            text-transform: uppercase;
            font-weight: bold;
            font-size: 22px;
            margin: 20px 0;
            line-height: 1.2;
        }
        .history-arrow-list {
            list-style: none;
            padding-left: 0;
        }
        .history-arrow-list li {
            position: relative;
            padding-left: 30px;
            margin-bottom: 10px;
            text-align: justify;
        }
        .history-arrow-list li::before {
            content: '➢';
            position: absolute;
            left: 0;
            color: #000;
            font-size: 18px;
        }
        .history-source-line {
            font-size: 13px;
            margin-top: 5px;
            color: #333;
        }
        .history-cover-frame {
            border: 4px solid #000;
            outline: 1px solid #000;
            outline-offset: -8px;
            height: 100%;
            padding: 40px;
            box-sizing: border-box;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: space-between;
            /* The third inner line via shadow */
            box-shadow: inset 0 0 0 10px white, inset 0 0 0 12px black;
        }
        .history-bolt {
            position: absolute;
            width: 20px;
            height: 20px;
            border: 2px solid #000;
            border-radius: 50%;
            background: white;
            display: flex;
            align-items: center;
            justify-content: center;
        }
        .history-bolt::after { content: ''; width: 8px; height: 8px; background: #000; border-radius: 50%; }
    </style>
</head>
<body>

    <div id="ui-layer">
        <div style="display: flex; gap: 10px; margin-bottom: 8px;">
            <select id="engine-select" style="flex: 1; padding: 8px; border-radius: 4px; background: #333; color: white; border: 1px solid #007bff;">
                <option value="history">ENGINE: History (2021 Edition)</option>
                <option value="logic">ENGINE: Logic (Ministry Edition)</option>
                <option value="anthro">ENGINE: Anthropology (2026 Edition)</option>
                <option value="psych">ENGINE: General Psychology (Legacy)</option>
                <option value="entre">ENGINE: Entrepreneurship (MoSHE 2019)</option>
            </select>
            <button onclick="masterDraw()" style="flex: 1; margin-top: 0;">EXECUTE DRAW COMMAND</button>
        </div>
        <textarea id="json-pen" placeholder="Paste JSON instructions..."></textarea>
    </div>

    <div id="exit-viewer" onclick="toggleViewer()">← EXIT READER</div>
    <div id="magnify-toggle" onclick="toggleViewer()">🔍</div>
    <div id="document-container"></div>

    <script>
        function masterDraw() {
            const engine = document.getElementById('engine-select').value;
            if (engine === 'psych') {
                drawPsychology();
            } else if (engine === 'anthro') {
                drawAnthropology();
            } else if (engine === 'logic') {
                drawLogic();
            } else if (engine === 'history') {
                drawHistory();
            } else if (engine === 'entre') {
                drawEntrepreneur();
            }
        }

        function drawEntrepreneur() {
            const raw = document.getElementById('json-pen').value;
            const container = document.getElementById('document-container');
            try {
                const doc = JSON.parse(raw);
                container.innerHTML = '';
                const availableWidth = window.innerWidth - 20;
                const scale = availableWidth < 794 ? availableWidth / 794 : 1;

                Object.keys(doc).forEach(pageKey => {
                    const pageData = doc[pageKey];
                    const wrapper = document.createElement('div');
                    wrapper.className = 'page-wrapper';
                    wrapper.style.marginTop = '20px';

                    const pageDiv = document.createElement('div');
                    pageDiv.className = 'page-canvas';
                    pageDiv.style.transform = `scale(${scale})`;

                    pageData.content.forEach(item => {
                        const el = renderEntrepreneurItem(item, pageKey);
                        pageDiv.appendChild(el);
                    });

                    wrapper.appendChild(pageDiv);
                    container.appendChild(wrapper);
                });
            } catch (err) { alert("Entrepreneur Engine Error: " + err); }
        }

        function renderEntrepreneurItem(item, pageKey) {
            const element = document.createElement('div');
            if (item.type === 'chapter-header') {
                element.className = 'entre-chapter-title';
                element.innerHTML = `CHAPTER ${item.number || ''}: ${item.title || ''}`;
            } 
            else if (item.type === 'header') {
                element.className = 'entre-section-h';
                element.innerHTML = item.body;
            }
            else if (item.type === 'paragraph') {
                element.className = 'p-block';
                element.innerHTML = item.body;
            }
            else if (item.type === 'entre-case') {
                element.className = 'entre-case-box';
                element.innerHTML = `<span class="entre-case-label">${item.label || 'Case Study'}</span>${item.body}`;
            }
            else if (item.type === 'entre-activity') {
                element.className = 'entre-activity-box';
                let html = `<div class="entre-activity-tag">Activity ${item.number || ''}</div>`;
                if (item.objective) html += `<div><b>Objective of activity:</b> ${item.objective}</div>`;
                if (item.instructions) html += `<div style="margin-top:5px"><b>Instructions:</b> ${item.instructions}</div>`;
                html += `<div style="margin-top:10px">${item.body || ''}</div>`;
                element.innerHTML = html;
            }
            else if (item.type === 'entre-reflection') {
                element.className = 'entre-reflection-box';
                let listHtml = item.items ? `<ul>${item.items.map(i => `<li>${i}</li>`).join('')}</ul>` : '';
                element.innerHTML = `<span class="entre-reflection-label">${item.label || 'Reflection Questions'}:</span><div style="font-style: italic;">${item.body || ''}</div>${listHtml}`;
            }
            else if (item.type === 'bullet-list') {
                const charMap = { 
                    'finger': '☞', 
                    'pen': '✍', 
                    'arrow': '➢', 
                    'square': '■', 
                    'chevron': '➤', 
                    'circle': '○', 
                    'diamond': '❖', 
                    'dot': '●', 
                    'default': '•' 
                };

                element.innerHTML = (item.items || []).map(text => {
                    let bulletHtml = '';
                    if (item.bullet === 'spark') {
                        bulletHtml = `<img src="assets/bullet-spark.png" class="entre-bullet-img">`;
                    } else {
                        const char = charMap[item.bullet] || charMap['default'];
                        bulletHtml = `<div class="entre-bullet-char">${char}</div>`;
                    }

                    return `
                        <div class="entre-bullet-item">
                            ${bulletHtml}
                            <div>${text}</div>
                        </div>`;
                }).join('');
            }
            else if (item.type === 'entre-likert-grid') {
                element.innerHTML = `<table class="entre-likert-table">
                    <tr><th style="width:50px">S. No</th><th>Characteristic</th><th style="width:30px">1</th><th style="width:30px">2</th><th style="width:30px">3</th><th style="width:30px">4</th><th style="width:30px">5</th></tr>
                    ${(item.rows || []).map(r => `<tr><td style="text-align:center">${r.no}</td><td>${r.text}</td><td></td><td></td><td></td><td></td><td></td></tr>`).join('')}
                </table>`;
            }
            else if (item.type === 'footer') {
                element.className = 'footer';
                element.innerText = item.val || pageKey;
            }
            else if (item.type === 'spacer') {
                element.style.flexGrow = item.flex || '0';
                element.style.height = item.height || '0px';
            }

            if (item.style) Object.assign(element.style, item.style);
            return element;
        }

        function drawHistory() {
            const raw = document.getElementById('json-pen').value;
            const container = document.getElementById('document-container');
            try {
                const doc = JSON.parse(raw);
                container.innerHTML = '';
                const availableWidth = window.innerWidth - 20;
                const scale = availableWidth < 794 ? availableWidth / 794 : 1;

                Object.keys(doc).forEach(pageKey => {
                    const pageData = doc[pageKey];
                    const wrapper = document.createElement('div');
                    wrapper.className = 'page-wrapper';
                    wrapper.style.marginTop = '20px';

                    const pageDiv = document.createElement('div');
                    pageDiv.className = 'page-canvas history-canvas';
                    if (pageData.watermark !== false) pageDiv.classList.add('history-watermark');
                    pageDiv.style.transform = `scale(${scale})`;

                    // Check for Cover Pattern
                    if (pageData.is_cover) {
                        const frame = document.createElement('div');
                        frame.className = 'history-cover-frame';
                        // Bolts
                        ['top:5px;left:5px','top:5px;right:5px','bottom:5px;left:5px','bottom:5px;right:5px'].forEach(pos => {
                            const bolt = document.createElement('div');
                            bolt.className = 'history-bolt';
                            bolt.style.cssText = pos;
                            pageDiv.appendChild(bolt);
                        });
                        pageDiv.appendChild(frame);
                        // Render cover content inside frame
                        pageData.content.forEach(item => {
                            const el = renderHistoryItem(item);
                            frame.appendChild(el);
                        });
                    } else {
                        pageData.content.forEach(item => {
                            const el = renderHistoryItem(item, pageKey);
                            pageDiv.appendChild(el);
                        });
                    }

                    wrapper.appendChild(pageDiv);
                    container.appendChild(wrapper);
                });
            } catch (err) { alert("History Engine Error: " + err); }
        }

        function renderHistoryItem(item, pageKey) {
            const element = document.createElement('div');
            if (item.type === 'history-header') {
                element.className = 'history-header-text';
                element.innerText = 'History of Ethiopia and the Horn Module (Hist.1102)';
            }
            else if (item.type === 'history-unit-header') {
                element.innerHTML = `<div class="history-unit-title">UNIT ${item.number || ''}<br>${item.title || ''} (${item.hours || ''} hours)</div>`;
            }
            else if (item.type === 'history-arrow-list') {
                element.className = 'history-arrow-list';
                element.innerHTML = (item.items || []).map(i => `<li>${i}</li>`).join('');
            }
            else if (item.type === 'paragraph') {
                element.className = 'p-block';
                element.innerHTML = item.body;
            }
            else if (item.type === 'header') {
                element.className = 'h-block';
                element.innerHTML = item.body;
            }
            else if (item.type === 'history-footer') {
                element.className = 'footer';
                element.style.marginTop = 'auto';
                element.innerText = item.page || pageKey;
            }
            else if (item.type === 'history-graphic') {
                element.className = 'graphic-container';
                element.innerHTML = `<img src="${item.url}" style="max-width:100%"><div class="history-source-line"><b>Source:</b> ${item.source || ''}</div>`;
            }
            else if (item.type === 'spacer') {
                element.style.flexGrow = item.flex || '0';
                element.style.height = item.height || '0px';
            }

            if (item.style) Object.assign(element.style, item.style);
            return element;
        }

        function drawLogic() {
            const raw = document.getElementById('json-pen').value;
            const container = document.getElementById('document-container');
            try {
                const doc = JSON.parse(raw);
                container.innerHTML = '';
                const availableWidth = window.innerWidth - 20;
                const scale = availableWidth < 794 ? availableWidth / 794 : 1;

                Object.keys(doc).forEach(pageKey => {
                    const pageData = doc[pageKey];
                    const wrapper = document.createElement('div');
                    wrapper.className = 'page-wrapper';
                    wrapper.style.marginTop = '20px';

                    const pageDiv = document.createElement('div');
                    pageDiv.className = 'page-canvas';
                    pageDiv.style.transform = `scale(${scale})`;
                    pageDiv.id = `page-${pageKey}`;

                    pageData.content.forEach(item => {
                        const element = document.createElement('div');

                        if (item.type === 'logic-header') {
                            element.className = 'logic-header';
                        }
                        else if (item.type === 'logic-footer') {
                            element.className = 'logic-footer';
                            element.innerHTML = `<span>${item.authors || ''}</span><span>Page ${item.page || pageKey}</span>`;
                        }
                        else if (item.type === 'chapter-title') {
                            element.innerHTML = `<span class="logic-chapter-num">CHAPTER ${item.number}</span><span class="logic-chapter-title">${item.title}</span>`;
                        }
                        else if (item.type === 'paragraph') {
                            element.className = 'p-block';
                            element.innerHTML = item.body;
                        }
                        else if (item.type === 'header') {
                            element.className = 'h-block';
                            element.innerHTML = item.body;
                        }
                        else if (item.type === 'bullet-list') {
                            element.className = 'list-block';
                            element.innerHTML = '<ul>' + (item.items || []).map(i => `<li>${i}</li>`).join('') + '</ul>';
                        }
                        else if (item.type === 'logic-activity') {
                            element.className = 'logic-activity-box';
                            element.innerHTML = `<span class="logic-activity-label">${item.label || ''}</span>${item.body}`;
                        }
                        else if (item.type === 'logic-argument') {
                            element.className = 'logic-argument-block';
                            let html = (item.premises || []).map(p => `<div>${p}</div>`).join('');
                            html += `<div class="logic-argument-line"></div>`;
                            html += `<div>${item.conclusion}</div>`;
                            element.innerHTML = html;
                        }
                        else if (item.type === 'logic-self-check') {
                            let html = `<div style="margin-bottom:10px;"><b>${item.number}.</b> ${item.question}</div>`;
                            for(let i=0; i<(item.lines || 2); i++) {
                                html += `<div class="logic-exercise-line"></div>`;
                            }
                            element.innerHTML = html;
                        }
                        else if (item.type === 'graphic') {
                            element.className = 'graphic-container';
                            element.innerHTML = `${item.svgCode}${item.caption ? `<div class="graphic-caption">${item.caption}</div>` : ''}`;
                        }
                        else if (item.type === 'logic-quote') {
                            element.className = 'logic-quote-block';
                            element.innerHTML = item.body;
                        }
                        else if (item.type === 'logic-note') {
                            element.className = 'logic-note-box';
                            element.innerHTML = `<span class="logic-note-label">Note:</span><div style="font-style:italic;">${item.body}</div>`;
                        }
                        else if (item.type === 'logic-example') {
                            element.innerHTML = `<div><span class="logic-example-label">${item.label || 'Example'}:</span> ${item.body || ''}</div>`;
                        }
                        else if (item.type === 'spacer') {
                            element.style.flexGrow = item.flex || '0';
                            element.style.height = item.height || '0px';
                        }

                        if (item.style) Object.assign(element.style, item.style);
                        pageDiv.appendChild(element);
                    });
                    wrapper.appendChild(pageDiv);
                    container.appendChild(wrapper);
                });
                window.scrollTo({ top: 0, behavior: 'smooth' });
            } catch (err) { alert("Logic Engine Error: " + err); }
        }

        function drawAnthropology() {
            const raw = document.getElementById('json-pen').value;
            const container = document.getElementById('document-container');

            try {
                const doc = JSON.parse(raw);
                container.innerHTML = '';
                const availableWidth = window.innerWidth - 20;
                const scale = availableWidth < 794 ? availableWidth / 794 : 1;

                Object.keys(doc).forEach(pageKey => {
                    const pageData = doc[pageKey];
                    const wrapper = document.createElement('div');
                    wrapper.className = 'page-wrapper';
                    wrapper.style.marginTop = '20px';

                    const pageDiv = document.createElement('div');
                    pageDiv.className = 'page-canvas';
                    pageDiv.style.transform = `scale(${scale})`;
                    pageDiv.id = `page-${pageKey}`;

                    if (pageData.requires_manual_image === true) {
                        const flag = document.createElement('div');
                        flag.className = 'manual-flag';
                        flag.innerText = '🖼️ MANUAL IMAGE REQUIRED';
                        pageDiv.appendChild(flag);
                    }

                    pageData.content.forEach(item => {
                        const element = document.createElement('div');

                        if (item.type === 'unit-header') {
                            element.className = 'anthro-unit-header';
                            element.innerHTML = `<span class="anthro-unit-label">Unit ${item.number || ''}</span><span class="anthro-unit-title">${item.title || ''}</span><span class="anthro-unit-hours">Study Hours: ${item.hours || ''}</span>`;
                        }
                        else if (item.type === 'callout-box') {
                            element.className = 'anthro-callout';
                            const iconFile = item.icon === 'books' ? 'icon-books.png' : 'icon-question-man.png';
                            let listHtml = '';
                            if (item.items) {
                                listHtml = '<div class="anthro-list">' + 
                                    item.items.map(i => `
                                        <div class="anthro-list-item">
                                            <img src="assets/bullet-swirl.png" class="anthro-bullet-img">
                                            <div>${i}</div>
                                        </div>`).join('') + 
                                    '</div>';
                            }
                            element.innerHTML = `
                                <div class="anthro-callout-icon"><img src="assets/${iconFile}"></div>
                                <div class="anthro-callout-content">
                                    <span class="anthro-callout-title">${item.label || ''}</span>
                                    ${item.body || ''}
                                    ${listHtml}
                                </div>`;
                        }
                        else if (item.type === 'bullet-list') {
                            element.className = 'anthro-list';
                            const listItems = item.items || [];
                            listItems.forEach(text => {
                                const row = document.createElement('div');
                                row.className = 'anthro-list-item';

                                let bImg = 'bullet-swirl.png'; // Default
                                if (item.bullet === 'spark') bImg = 'bullet-spark.png';
                                if (item.bullet === 'checkmark') bImg = 'bullet-check.png';

                                if (item.bullet === 'char') {
                                    row.innerHTML = `<div class="anthro-bullet-char">${item.char || '•'}</div><div>${text}</div>`;
                                } else {
                                    row.innerHTML = `<img src="assets/${bImg}" class="anthro-bullet-img"><div>${text}</div>`;
                                }
                                element.appendChild(row);
                            });
                        }
                        else if (item.type === 'anthro-toc') {
                            element.innerHTML = item.items.map(i => `
                                <div class="anthro-toc-item anthro-toc-level-${i.level || 0}">
                                    <span>${i.text}</span>
                                    <div class="anthro-toc-dots"></div>
                                    <span class="anthro-toc-page">${i.page}</span>
                                </div>
                            `).join('');
                        }
                        else if (item.type === 'title-block') {
                            element.className = 'anthro-title-block';
                            element.innerHTML = `
                                <div class="anthro-title-sub">${item.top || ''}</div>
                                <div class="anthro-title-main">${item.main || ''}</div>
                                <div class="anthro-title-sub">${item.bottom || ''}</div>
                            `;
                        }
                        else if (item.type === 'graphic') {
                            element.className = 'graphic-container';
                            element.innerHTML = `${item.svgCode}${item.caption ? `<div class="graphic-caption">${item.caption}</div>` : ''}`;
                        }
                        else if (item.type === 'paragraph') {
                            element.className = 'p-block';
                            element.innerHTML = item.body;
                        }
                        else if (item.type === 'header') {
                            element.className = 'h-block';
                            element.innerHTML = item.body;
                        }
                        else if (item.type === 'table') {
                            let t = '<table>';
                            item.rows.forEach((row, idx) => {
                                const isHeader = idx === 0 && item.headerStyle;
                                const tdClass = isHeader ? 'class="anthro-table-header"' : '';
                                t += '<tr>' + row.map(c => `<td ${tdClass}>${c}</td>`).join('') + '</tr>';
                            });
                            element.innerHTML = t + '</table>';
                        }
                        else if (item.type === 'reference-item') {
                            element.className = 'anthro-reference';
                            element.innerHTML = item.body;
                        }
                        else if (item.type === 'term-header') {
                            element.className = 'anthro-term';
                            element.innerText = item.body;
                        }
                        else if (item.type === 'kv-list') {
                            element.className = 'anthro-kv-container';
                            element.innerHTML = item.items.map(row => `
                                <div class="anthro-kv-row">
                                    <div class="anthro-kv-label">${row.label}</div>
                                    <div class="anthro-kv-separator">:</div>
                                    <div class="anthro-kv-value">${row.value}</div>
                                </div>
                            `).join('');
                        }
                        else if (item.type === 'footnote') {
                            element.className = 'anthro-footnote';
                            element.innerHTML = `<sup>${item.number || ''}</sup> ${item.body}`;
                        }
                        else if (item.type === 'spacer') {
                            element.style.flexGrow = item.flex || '0';
                            element.style.height = item.height || '0px';
                        }
                        else if (item.type === 'footer') {
                            element.className = 'footer';
                            element.innerText = item.val;
                        }

                        // Apply styles if present
                        if (item.style) {
                            Object.assign(element.style, item.style);
                        }

                        pageDiv.appendChild(element);
                    });

                    wrapper.appendChild(pageDiv);
                    container.appendChild(wrapper);
                });
                window.scrollTo({ top: window.innerHeight * 0.4, behavior: 'smooth' });
            } catch (err) {
                alert("Anthropology Engine Error: " + err);
            }
        }

        function drawPsychology() {
            const raw = document.getElementById('json-pen').value;
            const container = document.getElementById('document-container');

            try {
                const doc = JSON.parse(raw);
                container.innerHTML = '';

                const availableWidth = window.innerWidth - 20;
                const scale = availableWidth < 794 ? availableWidth / 794 : 1;

                Object.keys(doc).forEach(pageKey => {
                    const pageData = doc[pageKey];

                    const wrapper = document.createElement('div');
                    wrapper.className = 'page-wrapper';
                    wrapper.style.minHeight = (1123 * scale) + 'px';
                    wrapper.style.marginTop = '20px';

                    const pageDiv = document.createElement('div');
                    pageDiv.className = 'page-canvas';
                    pageDiv.style.transform = `scale(${scale})`;
                    pageDiv.id = `page-${pageKey}`;

                    // Apply Manual Image Flag
                    if (pageData.requires_manual_image === true) {
                        pageDiv.setAttribute('data-manual-image', 'true');
                        const flag = document.createElement('div');
                        flag.className = 'manual-flag';
                        flag.innerText = '🖼️ MANUAL IMAGE REQUIRED';
                        pageDiv.appendChild(flag);
                    }

                    pageData.content.forEach(item => {
                        const element = document.createElement('div');

                        if (item.type === 'paragraph') {
                            element.className = 'p-block';
                            element.innerHTML = item.body;
