                    },
                    layers: [
                        { id: 'atmosphere', type: 'background', paint: { 'background-color': '#000' } },
                        { id: 'sat', type: 'raster', source: 'sat' }
                    ],
                    terrain: { source: 'terrain', exaggeration: 1.5 }
                },
                center: [0, 20], zoom: 2, pitch: 45
            });

            this.narrator = window.speechSynthesis;
            this.initVoice();
            this.map.on('load', () => {
                document.getElementById('splash').style.opacity = '0';
                document.getElementById('map-container').style.filter = 'brightness(1)';
                setTimeout(() => document.getElementById('splash').remove(), 1000);
            });

            this.map.on('movestart', () => document.getElementById('map-container').classList.add('moving'));
            this.map.on('move', () => {
                try {
                    const center = this.map.getCenter();
                    if (this.map.getSource('terrain')) {
                        const elevation = this.map.queryTerrainElevation(center);
                        if (typeof elevation === 'number') {
                            document.getElementById('hud-alt').innerText = `${Math.round(elevation)} m.a.s.l`;
                        }
                    }
                } catch (e) {}
            });

            this.map.on('moveend', () => {
                document.getElementById('map-container').classList.remove('moving');
                this.sounds.updatePanners(this.map);
            });
        }

        initVoice() {
            const Speech = window.SpeechRecognition || window.webkitSpeechRecognition;
            if (!Speech || this.recognition) return;
            this.recognition = new Speech();
            this.recognition.continuous = true;
            this.recognition.onresult = (e) => {
                const cmd = e.results[e.results.length-1][0].transcript.toLowerCase();
                const match = this.currentScript?.find(s => s.voice_trigger && cmd.includes(s.voice_trigger));
                if (match) this.executeScene(match);
            };
            try { this.recognition.start(); } catch(e) {}
        }

        async play() {
            if(document.getElementById('editor-sheet').classList.contains('open')) toggleSheet();
            this.sounds.init();
            this.narrator.cancel(); // Stop any previous reading
            this.isPlaying = true;
            this.currentWeatherType = null;
            this.sounds.stopAll();

            // Clear Registry
            this.registry.forEach(id => {
                if (this.map.getLayer(id)) this.map.removeLayer(id);
                if (this.map.getSource(id)) this.map.removeSource(id);
            });
            this.registry = [];

            this.markers.forEach(m => m.remove());
            this.markers = [];
            this.currentStep = 0;

            const raw = document.getElementById('json-input').value;
            try {
                this.currentScript = JSON.parse(raw);
            } catch (e) {
                alert("JSON Error: " + e.message); return;
            }

            try {
                while (this.currentStep < this.currentScript.length) {
                    const scene = this.currentScript[this.currentStep];
                    if (this.evaluateCondition(scene.condition)) {
                        await this.executeScene(scene);
                        if (scene.updates) Object.assign(this.state, scene.updates);

                        if (scene.next) {
                            const idx = this.currentScript.findIndex(s => s.id === scene.next);
                            if (idx !== -1) { this.currentStep = idx; continue; }
                        }
                    }
                    this.currentStep++;
                }
            } catch (e) { 
                console.error("EXECUTION ERROR:", e);
            } finally {
                this.isPlaying = false;
            }
        }

        evaluateCondition(cond) {
            if (!cond) return true;
            try {
                const func = new Function('state', `return ${cond}`);
                return func(this.state);
            } catch(e) { return true; }
        }

        executeScene(scene) {
            return new Promise((resolve) => {
                const progress = ((this.currentStep + 1) / this.currentScript.length) * 100;
                document.getElementById('timeline-progress').style.width = `${progress}%`;

                // 1. Atmosphere / Sky Fix
                document.getElementById('map-container').className = scene.filter ? `filter-${scene.filter}` : '';
                if (scene.weather) this.startWeather(scene.weather);

                if (scene.sky || scene.fog) {
                    this.map.setSky({
                        "sky-color": scene.sky?.color || "#000000",
                        "horizon-color": scene.sky?.horizon || "#ffffff",
                        "fog-color": scene.fog?.color || "#ffffff",
                        "fog-ground-blend": 0.5
                    });
                }

                // 2. Academic HUD Updates
                const hud = document.getElementById('academic-hud');
                if (hud) {
                    hud.style.opacity = scene.unit ? '1' : '0.5';
                    if (scene.unit) document.getElementById('hud-unit').innerText = scene.unit.toUpperCase();
                }

                // 3. Choice Interactivity
                if (scene.choices) {
                    this.presentChoices(scene.choices, scene.subtitle).then(nextId => {
                        const nextIdx = this.currentScript.findIndex(s => s.id === nextId);
                        this.currentStep = nextIdx - 1;
                        resolve();
                    });
                    return;
                }

                // 4. Subtitles & Synchronized Voice
                const sub = document.getElementById('subtitle');
                sub.innerText = scene.subtitle || '';
                sub.classList.toggle('active', !!scene.subtitle);

                let voiceFinished = true;
                if (scene.narrate && scene.subtitle) {
                    voiceFinished = false;
                    const u = new SpeechSynthesisUtterance(scene.subtitle);
                    u.rate = 1.0; 
                    u.onend = () => { voiceFinished = true; };
                    u.onerror = () => { voiceFinished = true; };
                    this.narrator.speak(u);
                }

                // 5. Camera with Interruption Handling
                if (scene.camera) {
                    try {
                        if (scene.camera.type === 'orbit') {
                            this.startOrbit(scene.camera, scene.duration);
                        } else {
                            this.map.flyTo({
                                ...scene.camera,
                                duration: scene.duration || 3000,
                                essential: true
                            });
                        }
                    } catch (e) { console.warn("Camera transition interrupted"); }
                    if (scene.camera.shake) this.startShake(scene.camera.shake, scene.duration);
                }

                // 6. Action Elements
                if (scene.action === 'draw') this.animateTrace(scene);
                if (scene.action === 'radar') this.startRadar(scene.radar);
                if (scene.action === 'blast') this.addBlast(scene);
                if (scene.action === 'extrude') this.addExtrusion(scene);

                // 7. Markers
                if (scene.marker) {
                    const el = document.createElement('div');
                    el.className = `marker-${scene.marker.type}`;
                    if(scene.marker.type === 'beacon') {
                        for(let i=0; i<3; i++) {
                            const r = document.createElement('div'); r.className = 'beacon-ring';
                            r.style.animationDelay = `${i * 0.6}s`; el.appendChild(r);
                        }
                    }
                    const m = new maplibregl.Marker({ element: el }).setLngLat(scene.marker.coords).addTo(this.map);
                    this.markers.push(m);
                }

                // Wait for both the visual duration AND the narration to finish
                const checkFinish = setInterval(() => {
                    if (voiceFinished) {
                        clearInterval(checkFinish);
                        setTimeout(resolve, scene.wait || 500);
                    }
                }, 100);
            });
        }

        presentChoices(choices, prompt) {
            return new Promise(res => {
                const overlay = document.getElementById('choice-overlay');
                const btns = document.getElementById('choice-buttons');
                document.getElementById('choice-prompt').innerText = prompt || "CHOOSE PATH";
                btns.innerHTML = ''; overlay.classList.add('active');
                choices.forEach(c => {
                    const b = document.createElement('button');
                    b.className = 'choice-btn'; b.innerText = c.label;
                    b.onclick = () => { overlay.classList.remove('active'); res(c.scene_id); };
                    btns.appendChild(b);
                });
            });
        }

        animateTrace(scene) {
            const id = 't-' + Math.random().toString(36).substr(2, 4);
            this.registry.push(id);
            this.map.addSource(id, { type: 'geojson', data: { type: 'Feature', geometry: { type: 'LineString', coordinates: [scene.coordinates[0]] } } });
            this.map.addLayer({ id, source: id, type: 'line', paint: { 'line-color': scene.color || '#3b82f6', 'line-width': 4 } });
            let step = 0;
            const draw = () => {
                if (step >= scene.coordinates.length || !this.map.getSource(id)) return;
                this.map.getSource(id).setData({ type: 'Feature', geometry: { type: 'LineString', coordinates: scene.coordinates.slice(0, ++step) } });
                if (step < scene.coordinates.length) setTimeout(() => requestAnimationFrame(draw), scene.duration / scene.coordinates.length);
            };
            draw();
        }

        startRadar(config) {
            const id = 'radar-' + Math.random().toString(36).substr(2,4);
            this.registry.push(id);
            let angle = 0;
            this.map.addSource(id, { type: 'geojson', data: { type: 'Feature', geometry: { type: 'Polygon', coordinates: [[[0,0],[0,0],[0,0]]] } } });
            this.map.addLayer({ id, type: 'fill', source: id, paint: { 'fill-color': config.color || '#00ff00', 'fill-opacity': 0.3 } });
            const update = () => {
                angle += 2; const radius = config.radius || 0.01; const center = config.center;
                const coords = [center];
                for(let i=0; i<=30; i++) {
                    const rad = (angle + i) * Math.PI / 180;
                    coords.push([center[0] + Math.cos(rad) * radius, center[1] + Math.sin(rad) * radius]);
                }
                coords.push(center);
                if(this.map.getSource(id)) {
                    this.map.getSource(id).setData({ type: 'Feature', geometry: { type: 'Polygon', coordinates: [coords] } });
                    requestAnimationFrame(update);
                }
            };
            update();
        }

        addBlast(scene) {
            const id = 'blast-' + Math.random().toString(36).substr(2,4);
            this.registry.push(id);
            this.sounds.playImpact();
            this.map.addSource(id, { type: 'geojson', data: { type: 'Feature', geometry: { type: 'LineString', coordinates: [[0,0],[0,0]] } } });
            this.map.addLayer({ id, type: 'line', source: id, paint: { 'line-color': scene.color || '#ff4400', 'line-width': 2 } });
            let radius = 0;
            const expand = () => {
                radius += 0.002; const center = scene.center; const coords = [];
                for(let i=0; i<=360; i+=10) {
                    const rad = i * Math.PI / 180;
                    coords.push([center[0] + Math.cos(rad) * radius, center[1] + Math.sin(rad) * radius]);
                }
                if(this.map.getSource(id)) {
                    this.map.getSource(id).setData({ type: 'Feature', geometry: { type: 'LineString', coordinates: coords } });
                    if(radius < 0.1) requestAnimationFrame(expand);
                }
            };
            expand();
        }

        addExtrusion(scene) {
            const id = 'ext-' + Math.random().toString(36).substr(2,4);
            this.registry.push(id);
            this.map.addSource(id, { type: 'geojson', data: {
                type: 'FeatureCollection',
                features: scene.data.map(d => ({ type: 'Feature', properties: { height: d.h }, geometry: { type: 'Polygon', coordinates: [[[d.c[0]-0.002, d.c[1]-0.002], [d.c[0]+0.002, d.c[1]-0.002], [d.c[0]+0.002, d.c[1]+0.002], [d.c[0]-0.002, d.c[1]+0.002], [d.c[0]-0.002, d.c[1]-0.002]]] } }))
            }});
            this.map.addLayer({ id, type: 'fill-extrusion', source: id, paint: { 'fill-extrusion-color': scene.color || '#3b82f6', 'fill-extrusion-height': ['get', 'height'], 'fill-extrusion-opacity': 0.8 } });
        }

        startWeather(type) {
            const canvas = document.getElementById('weather-canvas');
            const ctx = canvas.getContext('2d');
            this.currentWeatherType = type;
            canvas.width = window.innerWidth; canvas.height = window.innerHeight;
            let particles = [];
            for(let i=0; i<100; i++) particles.push({ x: Math.random()*canvas.width, y: Math.random()*canvas.height, s: Math.random()*5+2 });
            const animate = () => {
                if (this.currentWeatherType !== type) return;
                ctx.clearRect(0,0,canvas.width, canvas.height);
                ctx.fillStyle = type === 'rain' ? '#3b82f6' : '#fff';
                particles.forEach(p => {
                    ctx.fillRect(p.x, p.y, type === 'rain' ? 1 : 3, type === 'rain' ? 10 : 3);
                    p.y += p.s; if(p.y > canvas.height) p.y = -10;
                });
                requestAnimationFrame(animate);
            };
            animate();
        }

        startOrbit(config, duration) {
            let start = null;
            const animate = (time) => {
                if (!start) start = time;
                const progress = time - start;
                this.map.setBearing((progress / (duration/360)) % 360);
                if (progress < duration && this.isPlaying) requestAnimationFrame(animate);
            };
            requestAnimationFrame(animate);
        }

        startShake(intensity, duration) {
            const canvas = this.map.getCanvas();
            const start = Date.now();
            const interval = setInterval(() => {
                const elapsed = Date.now() - start;
                if (elapsed > duration) {
                    canvas.style.transform = '';
                    clearInterval(interval); return;
                }
                canvas.style.transform = `translate(${(Math.random()-0.5)*intensity}px, ${(Math.random()-0.5)*intensity}px)`;
            }, 50);
        }
    }

    const director = new MapDirector();
    const demo = [
        { "id": "intro", "subtitle": "INITIALIZING NEURAL LINK...", "filter": "vhs", "camera": { "center": [0, 20], "zoom": 2 }, "duration": 3000 },
        { "id": "tokyo", "subtitle": "LOCATING SECTOR: TOKYO", "camera": { "center": [139.6503, 35.6762], "zoom": 12, "pitch": 60 }, "duration": 4000 },
        { "id": "choice", "subtitle": "ANOMALY DETECTED. SELECT OPERATIONAL MODE.", "choices": [
            { "label": "RECON SCAN", "scene_id": "recon" },
            { "label": "KINETIC STRIKE", "scene_id": "strike" }
        ]},
        { "id": "recon", "subtitle": "SCANNING...", "action": "radar", "radar": { "center": [139.6503, 35.6762] }, "next": "dubai" },
        { "id": "strike", "subtitle": "STRIKE INBOUND", "action": "blast", "center": [139.6503, 35.6762], "camera": { "shake": 20 }, "next": "dubai" },
        { "id": "dubai", "subtitle": "TARGET SECURED. RELOCATING TO DUBAI HUB.", "camera": { "center": [55.2708, 25.2048], "zoom": 14, "pitch": 70 }, "duration": 4000 },
        { "id": "end", "subtitle": "LINK TERMINATED.", "camera": { "zoom": 2 }, "duration": 2000 }
    ];
    const textbook = [
        {
            "id": "ch3_intro",
            "unit": "ETHIOPIA & THE HORN",
            "subtitle": "CHAPTER 3: THE TOPOGRAPHY OF ETHIOPIA. The topography is largely determined by the geologic activities of the Cenozoic Era. The uplifting of the Arabo-Ethiopian swell and Trapean lava have given rise to an outward sloping highland plateau.",
            "camera": { "center": [39.5, 9.0], "zoom": 5.5, "pitch": 30, "bearing": 0 },
            "duration": 8000,
            "narrate": true
        },
        {
            "id": "western_highlands",
            "unit": "WESTERN HIGHLANDS",
            "subtitle": "The Western Highlands make up 44% of the country. This region includes the Tigray Plateau, North Central Massifs, and the Shewa Plateau. More than 50% of the landmass is above 1,000 meters.",
            "camera": { "center": [37.5, 11.5], "zoom": 7, "pitch": 50, "bearing": -10 },
            "duration": 7000,
            "narrate": true
        },
        {
            "id": "ras_dashen",
            "unit": "SIMEN MOUNTAINS",
            "subtitle": "MOUNT RAS DASHEN (4,620 m.a.s.l): Located in the North Central Massifs, it is the fourth highest mountain in Africa and the highest point in Ethiopia.",
            "camera": { "center": [38.37, 13.23], "zoom": 11, "pitch": 75, "bearing": 45 },
            "marker": { "type": "beacon", "coords": [38.37, 13.23] },
            "action": "extrude",
            "color": "#fbbf24",
            "data": [{"c": [38.37, 13.23], "h": 4620}],
            "duration": 10000,
            "narrate": true
        },
        {
            "id": "rift_valley",
            "unit": "RIFT VALLEY",
            "subtitle": "THE RIFT VALLEY: A structural depression formed by faulting. It extends from the Afar Triangle to Chew Bahir. Elevation drops to 125m below sea level at the Kobar Sink (Dallol).",
            "camera": { "center": [40.5, 12.0], "zoom": 8, "pitch": 45, "bearing": 0 },
            "duration": 9000,
            "narrate": true
        }
    ];
    document.getElementById('json-input').value = JSON.stringify(textbook, null, 2);
</script>
