<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>2048 Game</title>
    <style>
        body {
            font-family: 'Clear Sans', 'Helvetica Neue', Arial, sans-serif;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            background-color: #faf8ef;
            color: #776e65;
            margin: 0;
            padding: 20px;
            box-sizing: border-box;
        }

        .container {
            background-color: #bbada0;
            border-radius: 6px;
            padding: 10px;
            position: relative;
            margin-bottom: 20px;
        }

        #game-board {
            display: grid;
            grid-template-columns: repeat(4, 100px);
            grid-template-rows: repeat(4, 100px);
            gap: 10px;
            background-color: #bbada0;
            border-radius: 6px;
            position: relative;
        }

        .grid-cell {
            width: 100px;
            height: 100px;
            border-radius: 3px;
            background-color: rgba(238, 228, 218, 0.35);
        }

        .tile-container {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            pointer-events: none; /* Allows clicks to pass through to the game board if needed */
        }

        .tile {
            position: absolute;
            width: 100px;
            height: 100px;
            background-color: #eee4da;
            border-radius: 3px;
            display: flex;
            justify-content: center;
            align-items: center;
            font-size: 35px;
            font-weight: bold;
            color: #776e65;
            transition: transform 0.1s ease-in-out;
            box-sizing: border-box;
        }

        /* Tile colors */
        .tile-2 { background-color: #eee4da; color: #776e65; }
        .tile-4 { background-color: #ede0c8; color: #776e65; }
        .tile-8 { background-color: #f2b179; color: #f9f6f2; }
        .tile-16 { background-color: #f59563; color: #f9f6f2; }
        .tile-32 { background-color: #f67c5f; color: #f9f6f2; }
        .tile-64 { background-color: #f65e3b; color: #f9f6f2; }
        .tile-128 { background-color: #edcf72; color: #f9f6f2; font-size: 30px;}
        .tile-256 { background-color: #edcc61; color: #f9f6f2; font-size: 30px;}
        .tile-512 { background-color: #edc850; color: #f9f6f2; font-size: 30px;}
        .tile-1024 { background-color: #edc53f; color: #f9f6f2; font-size: 25px;}
        .tile-2048 { background-color: #edc22e; color: #f9f6f2; font-size: 25px;}
        /* Add more tile colors for higher values if needed */

        #score-container {
            background-color: #bbada0;
            color: #f9f6f2;
            padding: 8px 15px;
            border-radius: 3px;
            font-size: 25px;
            font-weight: bold;
            position: absolute;
            top: 10px;
            right: 10px;
            z-index: 10;
        }

        #game-message {
            margin-top: 20px;
            font-size: 24px;
            font-weight: bold;
            color: #776e65;
            text-align: center;
        }

        button {
            background-color: #8f7a66;
            color: #f9f6f2;
            padding: 10px 20px;
            border: none;
            border-radius: 3px;
            font-size: 18px;
            cursor: pointer;
            margin-top: 20px;
        }
        button:hover {
            background-color: #9f8a76;
        }
    </style>
</head>
<body>
    <h1>2048</h1>
    <div id="score-container">Score: <span id="score">0</span></div>
    <div class="container">
        <div id="game-board">
            <!-- Grid cells will be generated by JS for background -->
            <div class="grid-cell"></div><div class="grid-cell"></div><div class="grid-cell"></div><div class="grid-cell"></div>
            <div class="grid-cell"></div><div class="grid-cell"></div><div class="grid-cell"></div><div class="grid-cell"></div>
            <div class="grid-cell"></div><div class="grid-cell"></div><div class="grid-cell"></div><div class="grid-cell"></div>
            <div class="grid-cell"></div><div class="grid-cell"></div><div class="grid-cell"></div><div class="grid-cell"></div>
        </div>
        <div class="tile-container" id="tile-container">
            <!-- Tiles will be appended here by JS -->
        </div>
    </div>
    <div id="game-message"></div>
    <button id="new-game-btn">New Game</button>

    <script>
        const boardSize = 4;
        let board = [];
        let score = 0;
        let gameOver = false;
        const tileContainer = document.getElementById('tile-container');
        const scoreDisplay = document.getElementById('score');
        const gameMessage = document.getElementById('game-message');
        const newGameBtn = document.getElementById('new-game-btn');

        // Initialize the game
        function initGame() {
            board = Array(boardSize).fill(0).map(() => Array(boardSize).fill(0));
            score = 0;
            gameOver = false;
            scoreDisplay.textContent = score;
            gameMessage.textContent = '';
            tileContainer.innerHTML = ''; // Clear existing tiles
            addRandomTile();
            addRandomTile();
            renderBoard();
        }

        // Add a random tile (2 or 4) to an empty spot
        function addRandomTile() {
            const emptyCells = [];
            for (let r = 0; r < boardSize; r++) {
                for (let c = 0; c < boardSize; c++) {
                    if (board[r][c] === 0) {
                        emptyCells.push({ r, c });
                    }
                }
            }

            if (emptyCells.length > 0) {
                const randomCell = emptyCells[Math.floor(Math.random() * emptyCells.length)];
                board[randomCell.r][randomCell.c] = Math.random() < 0.9 ? 2 : 4;
            } else {
                // If no empty cells, check for game over immediately
                if (!canMove()) {
                    setGameOver();
                }
            }
        }

        // Render the board (create/update tile elements)
        function renderBoard() {
            tileContainer.innerHTML = ''; // Clear all tiles before re-rendering

            for (let r = 0; r < boardSize; r++) {
                for (let c = 0; c < boardSize; c++) {
                    const value = board[r][c];
                    if (value !== 0) {
                        const tile = document.createElement('div');
                        tile.classList.add('tile', `tile-${value}`);
                        tile.textContent = value;
                        // Position calculations (adjust for padding/gap if needed)
                        tile.style.transform = `translate(${c * 110}px, ${r * 110}px)`; /* 100px tile + 10px gap */
                        tileContainer.appendChild(tile);
                    }
                }
            }
        }

        // --- Game Logic (Swipe functions) ---

        // Helper to slide tiles in a row/column
        function slide(row) {
            let newRow = row.filter(val => val !== 0); // Remove zeros
            let zeros = Array(boardSize - newRow.length).fill(0);
            return zeros.concat(newRow); // Add zeros back to the start
        }

        // Helper to combine tiles in a row/column
        function combine(row) {
            for (let i = boardSize - 1; i > 0; i--) {
                if (row[i] === row[i - 1] && row[i] !== 0) {
                    row[i] *= 2;
                    score += row[i]; // Update score
                    row[i - 1] = 0;
                }
            }
            return row;
        }

        function filterAndShift(line) {
            let newArr = line.filter(val => val !== 0);
            return Array(boardSize - newArr.length).fill(0).concat(newArr);
        }

        function compareBoards(oldBoard, newBoard) {
            for (let r = 0; r < boardSize; r++) {
                for (let c = 0; c < boardSize; c++) {
                    if (oldBoard[r][c] !== newBoard[r][c]) {
                        return true; // Boards are different
                    }
                }
            }
            return false; // Boards are the same
        }


        function slideAndCombine(line) {
            line = line.filter(val => val !== 0); // Remove zeros
            for (let i = 0; i < line.length - 1; i++) {
                if (line[i] === line[i + 1]) {
                    line[i] *= 2;
                    score += line[i];
                    line.splice(i + 1, 1); // Remove the merged tile
                }
            }
            while (line.length < boardSize) {
                line.push(0); // Fill with zeros
            }
            return line;
        }

        function move(direction) {
            if (gameOver) return;

            let boardChanged = false;
            let oldBoard = JSON.parse(JSON.stringify(board)); // Deep copy

            switch (direction) {
                case 'left':
                    for (let r = 0; r < boardSize; r++) {
                        board[r] = slideAndCombine(board[r]);
                    }
                    break;
                case 'right':
                    for (let r = 0; r < boardSize; r++) {
                        board[r] = slideAndCombine(board[r].reverse()).reverse();
                    }
                    break;
                case 'up':
                    for (let c = 0; c < boardSize; c++) {
                        let column = [];
                        for (let r = 0; r < boardSize; r++) {
                            column.push(board[r][c]);
                        }
                        column = slideAndCombine(column);
                        for (let r = 0; r < boardSize; r++) {
                            board[r][c] = column[r];
                        }
                    }
                    break;
                case 'down':
                    for (let c = 0; c < boardSize; c++) {
                        let column = [];
                        for (let r = 0; r < boardSize; r++) {
                            column.push(board[r][c]);
                        }
                        column = slideAndCombine(column.reverse()).reverse();
                        for (let r = 0; r < boardSize; r++) {
                            board[r][c] = column[r];
                        }
                    }
                    break;
            }

            boardChanged = compareBoards(oldBoard, board);

            if (boardChanged) {
                addRandomTile();
                renderBoard();
                scoreDisplay.textContent = score;
                if (!canMove() && !hasEmptyCells()) {
                    setGameOver();
                }
            }
        }


        // Check if there are any empty cells
        function hasEmptyCells() {
            for (let r = 0; r < boardSize; r++) {
                for (let c = 0; c < boardSize; c++) {
                    if (board[r][c] === 0) {
                        return true;
                    }
                }
            }
            return false;
        }

        // Check if any moves are possible (either empty cells or combinable tiles)
        function canMove() {
            if (hasEmptyCells()) return true;

            // Check for horizontal merges
            for (let r = 0; r < boardSize; r++) {
                for (let c = 0; c < boardSize - 1; c++) {
                    if (board[r][c] !== 0 && board[r][c] === board[r][c + 1]) {
                        return true;
                    }
                }
            }

            // Check for vertical merges
            for (let c = 0; c < boardSize; c++) {
                for (let r = 0; r < boardSize - 1; r++) {
                    if (board[r][c] !== 0 && board[r][c] === board[r + 1][c]) {
                        return true;
                    }
                }
            }

            return false;
        }

        function setGameOver() {
            gameOver = true;
            gameMessage.textContent = 'Game Over! Score: ' + score;
        }

        // Event Listeners
        document.addEventListener('keydown', (e) => {
            console.log(e.key); // Debugging line

            switch (e.key) {
                case 'ArrowUp':
                    move('up');
                    e.preventDefault();
                    break;
                case 'ArrowDown':
                    move('down');
                    e.preventDefault();
                    break;
                case 'ArrowLeft':
                    move('left');
                    e.preventDefault();
                    break;
                case 'ArrowRight':
                    move('right');
                    e.preventDefault();
                    break;
            }
        });

        newGameBtn.addEventListener('click', initGame);

        // Start the game
        initGame();
    </script>
</body>
</html>

