            margin: 0;
            font-family: sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
        }

        header {
            width: 100%;
            background: #2c2c2c;
            padding: 15px 20px;
            box-sizing: border-box;
            position: sticky;
            top: 0;
            z-index: 1000;
            border-bottom: 2px solid #007bff;
            display: flex;
            justify-content: space-between;
