        .editor-toolbar { display: flex; justify-content: flex-end; gap: 8px; margin-bottom: 8px; }
        .icon-btn { background: var(--card-bg); border: 1px solid var(--border); color: var(--text-muted); padding: 6px 12px; border-radius: 8px; cursor: pointer; font-size: 12px; display: flex; align-items: center; gap: 5px; }
        .icon-btn:active { background: var(--border); }

        .json-editor {
            width: 100%; min-height: 200px; background: var(--input-bg);
            border: 1px solid var(--border); color: #d4d4d4;
            font-family: 'JetBrains Mono', monospace; font-size: 13px; line-height: 1.5;
            padding: 12px; border-radius: 12px; resize: none; margin-bottom: 16px;
        }

        .terminal-container { margin-top: 24px; display: flex; flex-direction: column; gap: 10px; }
        .terminal-label { font-size: 12px; text-transform: uppercase; color: var(--text-muted); letter-spacing: 1px; margin-bottom: 5px; }

        .log-entry {
            border: 1px solid var(--border); border-radius: 8px; overflow: hidden;
            background: #000; font-family: 'JetBrains Mono', monospace;
        }
        .log-header {
            padding: 12px; cursor: pointer; display: flex; align-items: center; justify-content: space-between;
            background: #0f0f11; border-bottom: 1px solid transparent; transition: background 0.2s;
        }
        .log-header:active { background: #1a1a1c; }
        .log-header.expanded { border-bottom-color: var(--border); }

        .log-meta { display: flex; align-items: center; gap: 10px; font-size: 12px; }
        .log-time { color: var(--text-muted); }
        .status-pill { padding: 2px 6px; border-radius: 4px; font-size: 10px; font-weight: bold; text-transform: uppercase; }
        .pill-success { background: rgba(34, 197, 94, 0.2); color: var(--prod); }
        .pill-fail { background: rgba(239, 68, 68, 0.2); color: var(--danger); }

        .log-body { display: none; padding: 0; }
        .log-body.open { display: block; }

        .op-row {
            padding: 10px 12px; border-bottom: 1px solid #222; font-size: 11px;
            display: flex; flex-direction: column; gap: 4px;
        }
        .op-row:last-child { border-bottom: none; }
        .op-row.row-fail { border-left: 3px solid var(--danger); background: rgba(239, 68, 68, 0.05); }
        .op-title { color: #fff; font-weight: 600; display: flex; justify-content: space-between; }
        .op-details { color: #888; white-space: pre-wrap; margin-top: 2px; }
        .score-badge { font-size: 9px; padding: 1px 4px; border-radius: 3px; border: 1px solid #444; }

        .preview-container {
            height: calc(100vh - var(--nav-height) - 140px);
            border-radius: 12px; overflow: hidden; border: 1px solid var(--border);
            background: white; position: relative;
        }
        iframe { width: 100%; height: 100%; border: none; }
        .refresh-btn { position: absolute; bottom: 16px; right: 16px; background: rgba(0,0,0,0.8); color: white; border-radius: 50%; width: 44px; height: 44px; display: flex; align-items: center; justify-content: center; border: none; cursor: pointer; }

        body.fs-mode .nav-bar, body.fs-mode .header, body.fs-mode .main-view > p, body.fs-mode .fs-hide { display: none !important; }
        body.fs-mode .main-view { padding: 0 !important; height: 100vh; width: 100vw; overflow: hidden; }
        body.fs-mode #tab-preview { display: block; height: 100%; }
        body.fs-mode .preview-container { height: 100% !important; border: none; border-radius: 0; }

        .fs-back-btn { display: none; position: fixed; top: 20px; left: 20px; z-index: 9999; background: rgba(0,0,0,0.8); color: white; border-radius: 50%; width: 44px; height: 44px; align-items: center; justify-content: center; border: 1px solid rgba(255,255,255,0.2); cursor: pointer; backdrop-filter: blur(4px); }
        body.fs-mode .fs-back-btn { display: flex; }

        .nav-bar {
            position: fixed; bottom: 0; width: 100%; height: var(--nav-height);
            background: rgba(21, 21, 23, 0.9); backdrop-filter: blur(10px);
            border-top: 1px solid var(--border);
            display: flex; justify-content: space-around; align-items: center;
            padding-bottom: 15px; z-index: 100;
