    <script>
        // --- CONFIG ---
        let CONFIG = {
            funcUrl: localStorage.getItem('conduit_funcUrl') || '',
            previewUrl: localStorage.getItem('conduit_previewUrl') || ''
        };
        let sessionLogs = [];
        let dbHistory = [];

        // --- INIT ---
        window.onload = async () => {
            document.getElementById('setting-func-url').value = CONFIG.funcUrl;
            document.getElementById('setting-preview-url').value = CONFIG.previewUrl;

            const savedJson = localStorage.getItem('conduit_autosave');
            if(savedJson) {
                document.getElementById('json-input').value = savedJson;
                editHistory.push(savedJson);
                historyIndex = 0;
            }

            if(CONFIG.funcUrl) {
                await fetchState();
            } else {
                switchTab('tab-settings', document.querySelectorAll('.nav-item')[4]);
            }
        };

        async function fetchState(force = false) {
            if(!CONFIG.funcUrl) return;
            try {
                if(force) document.getElementById('history-container').innerHTML = '<div style="padding:10px; text-align:center; color:var(--text-muted);">Syncing...</div>';

                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({ action: 'init' })
                });

                if(!res.ok) throw new Error("Connection failed");
                const data = await res.json();

                if(data.config) {
                    CONFIG.previewUrl = data.config.preview_url || CONFIG.previewUrl;
                    document.getElementById('setting-preview-url').value = CONFIG.previewUrl;
                    if(CONFIG.previewUrl && !document.getElementById('preview-frame').src) {
                        document.getElementById('preview-frame').src = CONFIG.previewUrl;
                        document.getElementById('preview-url-display').textContent = CONFIG.previewUrl;
                    }
                }

                if(data.history) {
                    dbHistory = data.history;
                    renderHistory(dbHistory);
                }

            } catch (e) {
                console.error(e);
                document.getElementById('history-container').innerHTML = `<div style="padding:10px; text-align:center; color:var(--danger);">Sync Error: ${e.message}</div>`;
            }
        }

        // --- UI UTILS ---
        function switchTab(tabId, btn) {
            document.querySelectorAll('.tab-content').forEach(t => t.classList.remove('active'));
            document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
            document.getElementById(tabId).classList.add('active');
            if(btn) btn.classList.add('active');
        }

        function toggleFullscreen(active) {
            if(active) document.body.classList.add('fs-mode');
            else document.body.classList.remove('fs-mode');
        }

        // --- SETTINGS SYNC ---
        async function saveSettings() {
            const funcUrl = document.getElementById('setting-func-url').value.trim();
            const previewUrl = document.getElementById('setting-preview-url').value.trim();

            if(!funcUrl) return alert("Function URL is required");

            localStorage.setItem('conduit_funcUrl', funcUrl);
            localStorage.setItem('conduit_previewUrl', previewUrl);
            CONFIG.funcUrl = funcUrl;
            CONFIG.previewUrl = previewUrl;

            try {
                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                        action: 'sync_state',
                        func_url: funcUrl,
                        preview_url: previewUrl,
                        editor_content: document.getElementById('json-input').value
                    })
                });
                if(res.ok) alert("Configuration Saved & Synced to DB.");
                else throw new Error("DB Sync failed");
            } catch(e) {
                alert("Saved locally, but failed to sync to DB: " + e.message);
            }

            location.reload();
        }

        // --- FILE CONTEXT ---
        async function fetchFileList() {
            if(!CONFIG.funcUrl) return alert("Configure API URL first");
            const listContainer = document.getElementById('file-list-container');
            listContainer.innerHTML = '<div style="padding:20px; text-align:center;">Fetching repo...</div>';
            try {
                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({ action: 'fetch' })
                });
                if(!res.ok) throw new Error("API Error");
                const data = await res.json();
                window.repoFiles = data.files || [];
let FILE_OP_MAP = {};
                renderFileList(window.repoFiles);
            } catch (e) {
                listContainer.innerHTML = `<div style="color:var(--danger); padding:20px;">Error: ${e.message}</div>`;
            }
        }

        function levenshtein(a, b) {
            const matrix = [];
            for (let i = 0; i <= b.length; i++) { matrix[i] = [i]; }
            for (let j = 0; j <= a.length; j++) { matrix[0][j] = j; }
            for (let i = 1; i <= b.length; i++) {
                for (let j = 1; j <= a.length; j++) {
                    if (b.charAt(i - 1) == a.charAt(j - 1)) matrix[i][j] = matrix[i - 1][j - 1];
                    else matrix[i][j] = Math.min(matrix[i - 1][j - 1] + 1, Math.min(matrix[i][j - 1] + 1, matrix[i - 1][j] + 1));
                }
            }
            return matrix[b.length][a.length];
        }

        function filterFiles(query) {
            if (!window.repoFiles) return;
            if (!query) return renderFileList(window.repoFiles);
            const scored = window.repoFiles.map(file => {
                const name = file.path.split('/').pop();
                const dist = levenshtein(name.toLowerCase(), query.toLowerCase());
                const maxLen = Math.max(name.length, query.length);
                const score = Math.round((1 - dist / maxLen) * 100);
                return { ...file, score: score };
            });
            const filtered = scored.filter(f => f.score > 20).sort((a, b) => b.score - a.score);
            renderFileList(filtered, true);
        }

        function renderFileList(files, showScore = false) {
            const container = document.getElementById('file-list-container');
            container.innerHTML = '';
            if (files.length === 0) return container.innerHTML = '<div style="padding:20px; text-align:center;">No files found.</div>';

            files.forEach(file => {
                const div = document.createElement('div');
                div.className = 'file-item';
                const scoreHtml = showScore ? `<span class="match-score">${file.score}%</span>` : '';
                div.innerHTML = `
                    <div class="v-info"><strong>${file.path.split('/').pop()} ${scoreHtml}</strong><small>${file.path}</small></div>
                    <input type="checkbox" class="file-check" value="${file.path}" checked style="accent-color: var(--primary);">
                `;
                container.appendChild(div);
            });
        }

        function toggleAllFiles(source) {
            document.querySelectorAll('.file-check').forEach(cb => cb.checked = source.checked);
        }

        // --- HISTORY & ACTIONS ---
        function renderHistory(historyData) {
             const container = document.getElementById('history-container');
             if(!historyData || historyData.length === 0) return container.innerHTML = '<div style="padding:10px; text-align:center; color:var(--text-muted);">No history logs.</div>';

             container.innerHTML = historyData.map((h, index) => {
                 const dateStr = new Date(h.created_at).toLocaleString();
                 // CONDITIONAL RENDERING OF MENU ITEMS
                 const canLoad = !!h.ops;
                 const canPreview = !!h.sha;
                 const canRollback = h.sha && h.type === 'Dev';

                 return `
                <div class="version-item">
                    <div class="v-header">
                        <div class="v-info">
                            <strong>${h.title || 'Untitled'} <span class="match-score" style="color:${h.type==='Prod'?'var(--prod)':'var(--dev)'}; margin-left:6px; background:rgba(255,255,255,0.05)">${h.type}</span></strong>
                            <small>${dateStr} • ${h.meta || ''}</small>
                        </div>
                        <div style="position:relative">
                            <button class="menu-btn" onclick="event.stopPropagation(); toggleMenu(${index})">
                                <svg width="20" height="20" fill="currentColor" viewBox="0 0 24 24"><path d="M12 8c1.1 0 2-.9 2-2s-.9-2-2-2-2 .9-2 2 .9 2 2 2zm0 2c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2zm0 6c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2z"></path></svg>
                            </button>
                            <div id="menu-${index}" class="menu-dropdown">
                                ${canLoad ? `<div class="menu-item" onclick="loadVersion(${index})">
                                    <svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
                                    Load Patch
                                </div>` : ''}
                                ${canPreview ? `<div class="menu-item" onclick="previewVersion(${index})">
                                    <svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"></path></svg>
                                    Preview
                                </div>` : ''}
                                <div class="menu-item" onclick="addNote(${index})">
                                    <svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
                                    Edit Note
                                </div>
                                ${canRollback ? `<div class="menu-item danger" onclick="handleRollback(${index})">
                                    <svg width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><path d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6"></path></svg>
                                    Rollback To
                                </div>` : ''}
                            </div>
                        </div>
                    </div>
                    <div class="v-note ${h.note ? 'has-content' : ''}" onclick="addNote(${index})">${h.note || ''}</div>
                </div>
            `;
            }).join('');
        }

        function toggleMenu(index) {
            document.querySelectorAll('.menu-dropdown').forEach(m => m.classList.remove('show'));
            const menu = document.getElementById(`menu-${index}`);
            if(menu) menu.classList.add('show');
        }

        function closeAllMenus(e) {
            if(!e.target.closest('.menu-btn')) {
                document.querySelectorAll('.menu-dropdown').forEach(m => m.classList.remove('show'));
            }
        }

        function loadVersion(index) {
             const entry = dbHistory[index];
             if(confirm(`Load patch from '${entry.title}' into editor?`)) {
                 const formatted = JSON.stringify({ operations: entry.ops }, null, 2);
                 document.getElementById('json-input').value = formatted;
                 saveState(); 
                 switchTab('tab-patcher', document.querySelectorAll('.nav-item')[1]);
             }
        }

        async function previewVersion(index) {
            const entry = dbHistory[index];
            const iframe = document.getElementById('preview-frame');
            iframe.removeAttribute('src');
            iframe.contentWindow.document.open();
            iframe.contentWindow.document.write('<div style="color:#888; font-family:sans-serif; text-align:center; padding:20px;">Fetching history (' + entry.sha.substring(0,7) + ')...</div>');
            iframe.contentWindow.document.close();

            switchTab('tab-preview', document.querySelectorAll('.nav-item')[2]);

            try {
                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                        action: 'preview_file',
                        file_path: 'index.html', 
                        ref_sha: entry.sha
                    })
                });
                const data = await res.json();
                if(data.content) iframe.srcdoc = data.content;
                else throw new Error("No content returned");
            } catch(e) {
                alert("Error fetching historical preview: " + e.message);
            }
        }

        async function addNote(index) {
            const entry = dbHistory[index];
            const current = entry.note || '';
            const newNote = prompt("Add a note to this version:", current);

            if(newNote !== null) {
                dbHistory[index].note = newNote;
                renderHistory(dbHistory);

                try {
                    await fetch(CONFIG.funcUrl, {
                        method: 'POST',
                        headers: {'Content-Type': 'application/json'},
                        body: JSON.stringify({
                            action: 'update_note',
                            id: entry.id,
                            note: newNote
                        })
                    });
                } catch(e) {
                    alert("Note saved locally but failed to sync: " + e.message);
                }
            }
        }

        async function handleRollback(index) {
            const entry = dbHistory[index];
            if(confirm(`DANGER: Rollback dev branch to '${entry.title}' (${entry.sha.substring(0,7)})? Irreversible.`)) {
                const tempId = addTerminalCard(null, { loading: true });
                try {
                    const res = await fetch(CONFIG.funcUrl, {
                        method: 'POST',
                        headers: {'Content-Type': 'application/json'},
                        body: JSON.stringify({
                            action: 'rollback',
                            ref_sha: entry.sha
                        })
                    });
                    const data = await res.json();
                    if(data.success) {
                        updateTerminalCard(tempId, { message: "Rollback successful." });
                        fetchState(); 
                    } else {
                        throw new Error(data.error || "Rollback failed");
                    }
                } catch(e) {
                    updateTerminalCard(tempId, { error: e.message });
                }
            }
        }

        // --- BRIEFING ---
        function resetSession() {
            if(confirm("Clear local session log?")) {
                sessionLogs = [];
                alert("Session log cleared.");
            }
        }

        function handleBriefing(mode) {
             const checkedFiles = Array.from(document.querySelectorAll('.file-check:checked')).map(cb => cb.value);
             let report = "# Session Briefing\n**Date:** " + new Date().toLocaleString() + "\n\n## 1. Changelog\n";
             if(sessionLogs.length === 0) report += "(No changes yet)\n";
             else sessionLogs.forEach(log => {
                 report += `### [${log.time}] ${log.type}\n`;
                 if(log.data && log.data.results) log.data.results.forEach(res => { report += `- File: ${res.file} (${res.status})\n`; if(res.operations) res.operations.forEach(op => report += `  - ${op.type}: ${op.message}\n`); });
                 report += "\n";
             });
             report += "\n## 2. Context Files\n";
             checkedFiles.forEach(f => report += `- ${f}\n`);
             if(mode === 'copy') navigator.clipboard.writeText(report).then(() => alert("Copied!"));
             else { const blob = new Blob([report], { type: 'text/markdown' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = "briefing.md"; a.click(); }
        }

        // --- CORE PATCHER ---
        async function runPatch(actionType) {
FILE_OP_MAP = {};
if(fileRes.file) FILE_OP_MAP[fileRes.file] = opId;
            if(!CONFIG.funcUrl) return alert("Setup URL in Settings");
            const inputVal = document.getElementById('json-input').value;
            let payload;

            if(actionType === 'commit_prod') {
                const ver = prompt("Enter Release Version Name (e.g. v1.2):", "v1.0");
                if(!ver) return;
                payload = { version_name: ver };
            } else {
                try {
                    const parsed = JSON.parse(inputVal);
                    payload = parsed.operations ? parsed.operations : (Array.isArray(parsed) ? parsed : [parsed]);
                } catch (e) {
                    return addTerminalCard(null, { error: "Invalid JSON Syntax: " + e.message });
                }
            }

            const tempId = addTerminalCard(null, { loading: true });

            try {
                const reqBody = { action: actionType };
                if(actionType === 'patch') reqBody.operations = payload;
                if(actionType === 'commit_prod') reqBody.version_name = payload.version_name;

                const res = await fetch(CONFIG.funcUrl, {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify(reqBody)
                });
                const data = await res.json();
                updateTerminalCard(tempId, data, payload);

                if(data.success || data.count) {
                    sessionLogs.push({ time: new Date().toLocaleTimeString(), type: actionType, data: data });

                    if(actionType === 'patch') {
                        setTimeout(refreshPreview, 1500);
                    }
                    setTimeout(fetchState, 1000);
                }
            } catch (e) {
                updateTerminalCard(tempId, { error: e.message });
            }
        }

        // --- TERMINAL RENDERER ---
        function addTerminalCard(data, options = {}) {
function checkSyntaxErrors(code, filePath) { if (!code) return null; if (!filePath.endsWith('.js') && !filePath.endsWith('.mjs')) return null; try { acorn.parse(code, { ecmaVersion: 2022, sourceType: 'module' }); return null; } catch (e) { return { message: e.message, line: e.loc ? e.loc.line : 0 }; } }
let syntaxErrorFound = false; Object.keys(fileCache).forEach(path => { if (fileCache[path].mime === 'text/javascript') { const error = checkSyntaxErrors(fileCache[path].content, path); if (error) { syntaxErrorFound = true; const culpritOpId = FILE_OP_MAP[path]; if (culpritOpId) { const rows = Array.from(document.querySelectorAll('.op-row')); const opRow = rows.find(r => r.getAttribute('onclick') && r.getAttribute('onclick').includes(culpritOpId)); if (opRow) { opRow.style.borderLeft = '4px solid var(--danger)'; opRow.style.background = 'rgba(239, 68, 68, 0.1)'; const details = opRow.querySelector('.op-details'); if(details) details.innerHTML = `<strong style='color:var(--danger)'>⚠️ SYNTAX ERROR: ${error.message} (Line ${error.line})</strong>\n` + details.innerHTML; const logBody = opRow.closest('.log-body'); if(logBody) logBody.classList.add('open'); const logHeader = logBody.previousElementSibling; if(logHeader) logHeader.classList.add('expanded'); } } alert(`Syntax Error in ${path}\nLine: ${error.line}\n${error.message}`); } } }); if(syntaxErrorFound) { document.getElementById('preview-url-display').innerHTML = '<span style="color:var(--danger)">Bundle Aborted: Syntax Errors Detected</span>'; return; }
            const container = document.getElementById('terminal-list');
            const id = 'term-' + Date.now();
            const div = document.createElement('div');
            div.id = id; div.className = 'log-entry';
            if(options.loading) div.innerHTML = `<div class="log-header"><span>Processing...</span></div>`;
            else if (options.error) div.innerHTML = `<div class="log-header" style="color:var(--danger)"><span>Error</span></div><div class="log-body open" style="padding:12px; color:var(--danger); font-size:11px;">${options.error}</div>`;
            container.prepend(div);
            return id;
        }

        function updateTerminalCard(id, response, originalPayload) {
            const el = document.getElementById(id);
            if(!el) return;
            if(response.error) {
                el.innerHTML = `<div class="log-header" style="color:var(--danger)"><span>API Error</span><span class="status-pill pill-fail">500</span></div><div class="log-body open" style="padding:12px; color:var(--danger); font-size:11px;">${response.error}</div>`;
                return;
            }
            let failCount = 0; let opHtml = '';
            if(response.results && Array.isArray(response.results)) {
                response.results.forEach(fileRes => {
                    opHtml += `<div style="background:#111; padding:6px 12px; font-weight:bold; color:#fff; border-bottom:1px solid #222;">📄 ${fileRes.file}</div>`;
                    if(fileRes.operations) {
                        fileRes.operations.forEach(op => {
                            if(!op.success) failCount++;
                            const isFail = !op.success;
                            const scoreColor = op.score >= 95 ? 'var(--prod)' : (op.score >= 80 ? 'var(--dev)' : 'var(--danger)');
                            opHtml += `<div class="op-row ${isFail ? 'row-fail' : ''}"><div class="op-title"><span>${op.type.replace(/_/g, ' ').toUpperCase()}</span><span class="score-badge" style="border-color:${scoreColor}; color:${scoreColor}">${op.score}% Match</span></div><div class="op-details">${op.message}</div></div>`;
                        });
                    }
                });
            } else if (response.count) {
                opHtml = `<div class="op-row"><div class="op-details" style="color:var(--prod)">Production Deploy: ${response.count} files synced.</div></div>`;
            } else if (response.message) {
                 opHtml = `<div class="op-row"><div class="op-details" style="color:var(--prod)">${response.message}</div></div>`;
            }

            const isFail = failCount > 0;
            const badgeClass = isFail ? 'pill-fail' : 'pill-success';

            el.innerHTML = `
                <div class="log-header ${isFail ? 'expanded' : ''}" onclick="toggleLogBody('${id}')">
                    <div class="log-meta"><span class="log-time">${new Date().toLocaleTimeString()}</span><span class="status-pill ${badgeClass}">${isFail ? failCount+' FAILED' : 'SUCCESS'}</span></div>
                    <div class="flex-gap"><button class="icon-btn" style="padding:2px 6px; height:24px;" onclick="event.stopPropagation(); copyLogData('${id}')">COPY</button><span style="font-size:10px; color:#666">▼</span></div>
                </div>
                <div class="log-body ${isFail ? 'open' : ''}" id="${id}-body">${opHtml}</div>
                <textarea id="${id}-data" class="hidden">${JSON.stringify(response, null, 2)}</textarea>
            `;
        }

        function toggleLogBody(id) {
            const body = document.getElementById(id + '-body');
            const header = document.getElementById(id).querySelector('.log-header');
            body.classList.toggle('open');
            header.classList.toggle('expanded');
        }
        function copyLogData(id) {
            const data = document.getElementById(id + '-data').value;
            navigator.clipboard.writeText(data).then(() => alert("Log JSON copied"));
        }

        // Editor State
        let editHistory = []; let historyIndex = -1;
        function saveState() {
            const val = document.getElementById('json-input').value;
            localStorage.setItem('conduit_autosave', val);
            if (historyIndex === -1 || editHistory[historyIndex] !== val) { editHistory = editHistory.slice(0, historyIndex + 1); editHistory.push(val); historyIndex++; }
        }
        function editorUndo() { if (historyIndex > 0) { historyIndex--; document.getElementById('json-input').value = editHistory[historyIndex]; localStorage.setItem('conduit_autosave', editHistory[historyIndex]); } }
        function editorRedo() { if (historyIndex < editHistory.length - 1) { historyIndex++; document.getElementById('json-input').value = editHistory[historyIndex]; localStorage.setItem('conduit_autosave', editHistory[historyIndex]); } }
        function clearEditor() { if(confirm('Clear editor?')) { document.getElementById('json-input').value = ''; saveState(); } }
        function refreshPreview() { if(!CONFIG.previewUrl) return; const iframe = document.getElementById('preview-frame'); const url = new URL(CONFIG.previewUrl); url.searchParams.set('t', Date.now()); iframe.src = url.toString(); }
    </script>
</body>
</html>


