        }
    </style>
</head>
<body>
    <div class="game-container">
        <h1>Memory Game</h1>
        <div id="game-board"></div>
        <div class="stats">
            Moves: <span id="moves">0</span>
            Time: <span id="time">0s</span>
        </div>
        <div id="message"></div>
        <div class="controls">
            <button id="restart-button">Restart Game</button>
            <button id="restart-button">Restart Game</button>
            <button id="theme-toggle">Toggle Theme</button>
    </div>

    <script>
        const gameBoard = document.getElementById('game-board');
        const movesSpan = document.getElementById('moves');
        const timeSpan = document.getElementById('time');
        const messageDiv = document.getElementById('message');
        const restartButton = document.getElementById('restart-button');
        const themeToggleButton = document.getElementById('theme-toggle');
        const body = document.body;

        // Theme logic
        function applyTheme(theme) {
            if (theme === 'dark') {
                body.classList.add('dark-theme');
                body.classList.remove('light-theme');
            } else {
                body.classList.add('light-theme');
                body.classList.remove('dark-theme');
            }
            localStorage.setItem('memoryGameTheme', theme);
        }

        function toggleTheme() {
            const currentTheme = body.classList.contains('dark-theme') ? 'dark' : 'light';
            const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
            applyTheme(newTheme);
        }

        // Load theme from localStorage or default to dark
        const savedTheme = localStorage.getItem('memoryGameTheme');
        if (savedTheme) {
            applyTheme(savedTheme);
        } else {
            applyTheme('dark'); // Default to dark theme
        }

        themeToggleButton.addEventListener('click', toggleTheme);

        const symbols = ['ðŸ Ž', 'ðŸ Œ', 'ðŸ ’', 'ðŸ ‡', 'ðŸ ‹', 'ðŸ “', 'ðŸ  ', 'ðŸ ‰'];

        const symbols = ['ð', 'ð', 'ð', 'ð', 'ð', 'ð', 'ð', 'ð'];
        let cards = [];
        let flippedCards = [];
        let matchedPairs = 0;
        let moves = 0;
        let timer = null;
        let seconds = 0;
        let isProcessingFlip = false;

        function shuffle(array) {
            for (let i = array.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [array[i], array[j]] = [array[j], array[i]];
            }
            return array;
        }

        function createBoard() {
            cards = [];
            const gameSymbols = shuffle([...symbols, ...symbols]); // Duplicate and shuffle for pairs
            gameBoard.innerHTML = '';
            gameSymbols.forEach((symbol, index) => {
                const card = document.createElement('div');
                card.classList.add('card');
                card.dataset.symbol = symbol;
                card.dataset.index = index; // Unique index for each card element

                const front = document.createElement('div');
                front.classList.add('front');
                front.textContent = symbol;

                const back = document.createElement('div');
                back.classList.add('back');
                back.textContent = '?'; // Placeholder for unflipped card

                card.appendChild(back);
                card.appendChild(front);

                card.addEventListener('click', () => flipCard(card));
                gameBoard.appendChild(card);
                cards.push(card);
            });
        }

        function flipCard(card) {
            if (isProcessingFlip || card.classList.contains('flipped') || card.classList.contains('matched') || flippedCards.length === 2) {
                return;
            }

            if (timer === null) {
                startTimer();
            }

            card.classList.add('flipped');
            flippedCards.push(card);

            if (flippedCards.length === 2) {
                moves++;
                movesSpan.textContent = moves;
                isProcessingFlip = true;
                setTimeout(checkForMatch, 1000); // Give player time to see both cards
            }
        }

        function checkForMatch() {
            const [card1, card2] = flippedCards;
            if (card1.dataset.symbol === card2.dataset.symbol) {
                card1.classList.add('matched');
                card2.classList.add('matched');
                matchedPairs++;
                if (matchedPairs === symbols.length) {
                    endGame(true);
                }
            } else {
                card1.classList.remove('flipped');
                card2.classList.remove('flipped');
            }
            flippedCards = [];
            isProcessingFlip = false;
        }

        function startTimer() {
            seconds = 0;
            timeSpan.textContent = '0s';
            timer = setInterval(() => {
                seconds++;
                timeSpan.textContent = `${seconds}s`;
            }, 1000);
        }

        function stopTimer() {
            clearInterval(timer);
            timer = null;
        }

        function resetGame() {
            stopTimer();
            flippedCards = [];
            matchedPairs = 0;
            moves = 0;
            seconds = 0;
            isProcessingFlip = false;
            movesSpan.textContent = '0';
            timeSpan.textContent = '0s';
            messageDiv.textContent = '';
            createBoard();
        }

        function endGame(won) {
            stopTimer();
            if (won) {
                messageDiv.textContent = `Congratulations! You matched all pairs in ${moves} moves and ${seconds} seconds!`;
            }
        }

        restartButton.addEventListener('click', resetGame);

        // Initial game setup
        resetGame();
    </script>
</body>
</html>


