        const resetButton = document.getElementById('resetButton');
        const gameMessage = document.getElementById('gameMessage');

        const cardSymbols = ['⭐', '❤️', '🌈', '🚀', '🍎', '💡', '💎', '🌸'];
        let cards = [];
        let flippedCards = [];
        let matchedPairs = 0;
        let totalFlips = 0;
        let gameActive = false;
        let gameStarted = false;

        function initializeGame() {
            gameActive = false;
            gameStarted = false;
            flippedCards = [];
            matchedPairs = 0;
            totalFlips = 0;
            flipsDisplay.textContent = `Flips: ${totalFlips}`;
            matchesDisplay.textContent = `Matches: ${matchedPairs}`;
            gameMessage.textContent = 'Click "Reset Game" to start!';

            // Duplicate symbols to create pairs
            cards = [...cardSymbols, ...cardSymbols];
            shuffleCards(cards);
            renderBoard();
            setTimeout(() => { gameMessage.textContent = ''; }, 2000); // Clear message after 2 seconds
        }

        function shuffleCards(array) {
            for (let i = array.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [array[i], array[j]] = [array[j], array[i]];
            }
        }

        function renderBoard() {
            gameBoard.innerHTML = '';
            cards.forEach((symbol, index) => {
                const cardElement = document.createElement('div');
                cardElement.classList.add('card');
                cardElement.dataset.symbol = symbol;
                cardElement.dataset.index = index;

                const front = document.createElement('div');
                front.classList.add('front');
                front.textContent = '?'; // Hidden state symbol

                const back = document.createElement('div');
                back.classList.add('back');
                back.textContent = symbol; // Revealed state symbol

                cardElement.appendChild(front);
                cardElement.appendChild(back);

                cardElement.addEventListener('click', () => flipCard(cardElement));
                gameBoard.appendChild(cardElement);
            });
        }

        function flipCard(cardElement) {
            if (!gameActive && !gameStarted) {
                gameActive = true;
                gameStarted = true;
                gameMessage.textContent = ''; // Clear message once game starts
            }
            if (!gameActive || cardElement.classList.contains('flipped') || cardElement.classList.contains('matched') || flippedCards.length === 2) {
                return;
            }

            cardElement.classList.add('flipped');
            flippedCards.push(cardElement);
            totalFlips++;
            flipsDisplay.textContent = `Flips: ${totalFlips}`;

            if (flippedCards.length === 2) {
                gameActive = false; // Temporarily disable clicks
                checkForMatch();
            }
        }

        function checkForMatch() {
            const [card1, card2] = flippedCards;
            const symbol1 = card1.dataset.symbol;
            const symbol2 = card2.dataset.symbol;

            if (symbol1 === symbol2) {
                setTimeout(() => {
                    card1.classList.add('matched');
                    card2.classList.add('matched');
                    matchedPairs++;
                    matchesDisplay.textContent = `Matches: ${matchedPairs}`;
                    flippedCards = [];
                    gameActive = true; // Re-enable clicks
                    checkWin();
                }, 800);
            } else {
                setTimeout(() => {
                    card1.classList.remove('flipped');
                    card2.classList.remove('flipped');
                    flippedCards = [];
                    gameActive = true; // Re-enable clicks
                }, 1200);
            }
        }

        function checkWin() {
            if (matchedPairs === cardSymbols.length) {
                gameMessage.textContent = `Congratulations! You won in ${totalFlips} flips!`;
                gameActive = false;
            }
        }

        resetButton.addEventListener('click', initializeGame);

        initializeGame(); // Initialize the game on page load
    </script>
</body>
</html>


