        applyTheme(currentTheme);
        // Do not force config modal on load
        nav('sources'); // Default to sources
    };

    function saveConfig() {
        let url = document.getElementById('sbUrl').value.replace( /\/$/, "");
        const key = document.getElementById('sbKey').value;
        if(url && key) { localStorage.setItem('sbUrl', url); localStorage.setItem('sbKey', key); location.reload(); }
    }

    function applyTheme(theme) {
        document.body.setAttribute('data-theme', theme);
        localStorage.setItem('theme', theme);
        currentTheme = theme;
    }

    function toggleTheme() {
        const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
        applyTheme(newTheme);
    }

    function nav(screen) {
        document.querySelectorAll('.screen').forEach(el => el.classList.remove('active'));
        document.getElementById('screen-' + screen).classList.add('active');
        document.querySelectorAll('.nav-item').forEach(el => el.classList.remove('active'));
        if(document.getElementById('nav-'+screen)) document.getElementById('nav-'+screen).classList.add('active');

        if(screen === 'sources') refreshSources();
        if(screen === 'results') loadDecks();
        if(screen === 'queue') loadJobs();
