    async function sbFetch(path, options = {}) {
        const res = await fetch(`${CONFIG.url}${path}`, {
            ...options,
            headers: { 'apikey': CONFIG.key, 'Authorization': `Bearer ${CONFIG.key}`, 'Content-Type': 'application/json', 'Prefer': 'return=representation', ...options.headers }
        });
        if (res.status === 204) return null;
        if (!res.ok) throw new Error((await res.text()));
        return await res.json();
    }

    // --- *** API (CORRECTED) *** ---
    async function edgeFetch(body) {
        const res = await fetch(`${CONFIG.url}/functions/v1/ai-academic-processor`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${CONFIG.key}`, 'Content-Type': 'application/json' },
            body: JSON.stringify(body) // Simplified: always stringify the object passed in
        });
        if (!res.ok) throw new Error((await res.text()));
        return await res.json();
    }

    async function refreshSources() {
        const list = document.getElementById('source-list');
        list.innerHTML = '<div style="text-align:center; color:#64748b; padding:20px;">Loading...</div>';

        try {
            const [ghFiles, dbJobs] = await Promise.all([
                edgeFetch({ 'x-action': 'github_proxy', payload: { method: 'GET', path: currentPath } }),
                sbFetch('/rest/v1/chapter_processing_jobs?select=storage_path')
            ]);

            const registeredSet = new Set(dbJobs.map(j => j.storage_path));
            list.innerHTML = '';

            if(currentPath !== 'books') {
                const up = currentPath.substring(0, currentPath.lastIndexOf('/')) || 'books';
                list.innerHTML += `<div class="item-card" onclick="currentPath='${up}'; refreshSources();" style="text-align:center; padding:10px; cursor:pointer;">â¬ Back</div>`;
            }
            document.getElementById('breadcrumb').innerText = currentPath + '/';

            if(Array.isArray(ghFiles)) {
                ghFiles.sort((a,b) => (a.type === b.type ? 0 : a.type === 'dir' ? -1 : 1));
                ghFiles.forEach(item => {
                    const isFolder = item.type === 'dir';
                    const isReg = registeredSet.has(item.path);
                    const cleanName = item.name.replace(/_/g, ' ').replace('.txt','');

                    list.innerHTML += `
                    <div class="item-card" style="${isReg ? 'border-color:var(--success);' : ''}">
