                                <span class="badge ${isFolder ? 'folder' : 'file'}">${isFolder ? 'Folder' : 'Chapter'}</span>
                                ${isReg ? '<span class="badge success">Registered</span>' : ''}
                            </div>
                            <div class="actions">
                                ${isFolder ? `<button class="btn btn-outline" style="width:auto; padding:4px 8px; font-size:0.7rem;" onclick="openPromptEditor('${item.name}')">ð Config</button>` : ''}
                                ${isFolder ? `<button class="btn btn-primary" style="width:auto; padding:4px 8px; font-size:0.7rem;" onclick="regFolder('${item.path}')">Add All</button>` : ''}
                            </div>
                        </div>
                        <div class="action-row">
                            ${isFolder 
                                ? `<button class="btn btn-outline" onclick="currentPath='${item.path}'; refreshSources();">Open Folder</button>`
