    async function regFile(path) {
        const parts = path.split('/');
        const book = parts.length > 1 ? parts[parts.length-2].replace(/_/g,' ') : "Book";
        const chap = parts[parts.length-1].replace('.txt','').replace(/_/g,' ');

        try {
            await sbFetch('/rest/v1/chapter_processing_jobs', { method: 'POST', body: JSON.stringify({ book_title: book, chapter_title: chap, storage_path: path, status: 'pending' }) });
            toast("Registered!"); refreshSources();
        } catch(e) { alert(e.message); }
    }

    async function regFolder(path) {
        if(!confirm("Register all unregistered chapters in this folder?")) return;
        try {
            const files = await edgeFetch({ 'x-action': 'github_proxy', payload: { method: 'GET', path: path } });
            const existing = await sbFetch('/rest/v1/chapter_processing_jobs?select=storage_path');
            const existSet = new Set(existing.map(j => j.storage_path));

            const jobs = files.filter(f => f.type === 'file' && !existSet.has(f.path)).map(f => ({
                book_title: path.split('/').pop().replace(/_/g,' '),
                chapter_title: f.name.replace('.txt','').replace(/_/g,' '),
                storage_path: f.path, status: 'pending'
            }));

            if(jobs.length === 0) return toast("All already registered");
            await sbFetch('/rest/v1/chapter_processing_jobs', { method: 'POST', body: JSON.stringify(jobs) });
            toast(`Added ${jobs.length} Jobs`); refreshSources();
        } catch(e) { alert(e.message); }
    }

    async function openPromptEditor(bookName) {
        const modal = document.getElementById('promptModal');
        const title = document.getElementById('prompt-modal-title');
        const textarea = document.getElementById('promptJsonText');

        title.innerText = `Config for ${bookName.replace(/_/g, ' ')}`;
        document.getElementById('promptBookName').value = bookName;
        modal.dataset.fileSha = ''; 
        textarea.value = 'Loading existing config...';
        modal.style.display = 'flex';

        try {
            const data = await edgeFetch({ 'x-action': 'github_proxy', payload: { method: 'GET', path: `Prompts/${bookName}.json` } });
            if(data && data.content) {
                const decodedContent = atob(data.content);
                textarea.value = JSON.stringify(JSON.parse(decodedContent), null, 2);
                modal.dataset.fileSha = data.sha;
            } else {
                 throw new Error("File not found");
            }
        } catch (e) {
            const template = {
                book_title: bookName.replace(/_/g, ' '),
                chapters: { "ch-1": [ { title: "Deck Title 1", card_count: 15, instruction: "Instruction for deck 1." } ] }
            };
            textarea.value = JSON.stringify(template, null, 2);
        }
    }

    async function pasteFromClipboard() {
        try {
            const text = await navigator.clipboard.readText();
            document.getElementById('promptJsonText').value = text;
            toast("Pasted from clipboard!");
        } catch (err) { alert('Failed to read clipboard contents.'); }
    }

    // --- *** PROMPT SAVE (CORRECTED) *** ---
    async function savePromptConfig() {
        const modal = document.getElementById('promptModal');
        const bookName = document.getElementById('promptBookName').value;
        const fileSha = modal.dataset.fileSha || undefined;
        const textarea = document.getElementById('promptJsonText');

        let config;
        try { config = JSON.parse(textarea.value); } 
        catch (e) { toast("Error: Invalid JSON format."); return; }


        config.book_title = bookName.replace(/_/g, ' ');
        const finalContent = JSON.stringify(config, null, 2);
        const encodedContent = btoa(unescape(encodeURIComponent(finalContent)));

        try {
            // Build the entire request object for edgeFetch
            const requestPayload = {
                'x-action': 'github_proxy',
                payload: {
                    method: 'PUT',
                    path: `Prompts/${bookName}.json`,
                    body: { // This is now an object, not a string
                        message: `[UI] Update config for ${bookName}`,
                        content: encodedContent,
                        sha: fileSha
                    }
                }
            };

            await edgeFetch(requestPayload);

            toast("Config saved to GitHub!");
            modal.style.display = 'none';
        } catch (e) {
        } catch (e) {
            toast(`Error: Failed to save to GitHub: ${e.message}`);
        }

    }

    async function loadJobs() {
        const list = document.getElementById('job-list');
        try {
            const jobs = await sbFetch('/rest/v1/chapter_processing_jobs?status=not.in.(completed)&order=updated_at.desc');
            list.innerHTML = jobs.length === 0 ? '<div style="text-align:center; color:var(--text-muted)">No active jobs</div>' : '';

            jobs.forEach(j => {
                let statusColor = j.status === 'failed' ? 'var(--danger)' : j.status === 'pending' ? 'var(--warning)' : 'var(--primary)';
                if(j.status === 'completed') statusColor = 'var(--success)';

                list.innerHTML += `
                <div class="item-card" style="border-left:4px solid ${statusColor}">
                    <div class="card-header">
                        <div>
                            <div class="item-title">${j.chapter_title}</div>
                            <div class="item-sub">${j.book_title}</div>
                        </div>
                        <span class="badge" style="background-color: transparent; border: 1px solid ${statusColor}; color:${statusColor}">${j.status}</span>
                    </div>
                    <div class="item-sub" style="margin-top:8px; font-size: 0.7rem;">Decks: <b>${(j.generated_history||[]).length}</b> &nbsp;&nbsp; Attempts: <b>${j.attempt_count || 0}/5</b></div>
                    ${j.error_message ? `<div style="color:var(--danger); font-size:0.8rem; margin-top:8px; background: rgba(239, 68, 68, 0.1); padding: 5px 8px; border-radius: 4px;">${j.error_message}</div>` : ''}
                </div>`;
            });
        } catch(e) { list.innerHTML = "Error loading jobs: " + e.message; }
    }

    async function triggerLoop() {
        const log = document.getElementById('loop-log');
        const btn = document.querySelector('#screen-queue button');
        log.innerText = `Pinging the worker...`;
        btn.disabled = true;

        try {
            const res = await edgeFetch({}); // Empty body for worker trigger
            log.style.color = 'var(--success)';
            log.innerText = `Worker Response: ${res.message}`;
            toast("Worker cycle complete!");
            loadJobs();
        } catch (e) {
            log.style.color = 'var(--danger)';
            log.innerText = "Error: " + (JSON.parse(e.message)?.error || e.message);
        } finally {
            btn.disabled = false;
        }
    }

    async function loadDecks() {
        const list = document.getElementById('deck-list');
        try {
            const decks = await sbFetch('/rest/v1/published_decks?select=*&order=created_at.desc');
            list.innerHTML = '';
            if(decks.length === 0) { list.innerHTML = '<div style="text-align:center; color:var(--text-muted)">No decks yet</div>'; return; }

            const grouped = decks.reduce((acc, d) => {
                const book = d.source_document.split('/')[1]?.replace(/_/g,' ') || "Misc";
                if (!acc[book]) acc[book] = [];
                acc[book].push(d);
                return acc;
            }, {});

            for(const [book, ds] of Object.entries(grouped).sort((a,b) => a[0].localeCompare(b[0]))) {
                list.innerHTML += `<h2>${book}</h2>`;
                ds.forEach(d => {
                    list.innerHTML += `
                    <div class="item-card" onclick="openDeck('${d.id}')">
                        <div class="card-header">
                            <div class="item-title">${d.title}</div>
                            <span class="badge success">${d.card_count} cards</span>
                        </div>
                        <div class="item-sub">${d.description || ''}</div>
                    </div>`;
                });
            }
        } catch(e) { list.innerHTML = "Error loading decks"; }
    }

    async function openDeck(id) {
        const [d] = await sbFetch(`/rest/v1/published_decks?id=eq.${id}&select=*`);
        if (!d) { alert("Could not load deck."); return; }
        currentDeck = d.cards; cardIndex = 0;
        document.getElementById('view-title').innerText = d.title;
        nav('viewer'); renderCard();
    }

    function renderCard() {
        if (!currentDeck || currentDeck.length === 0) return;
        const c = currentDeck[cardIndex];
        const area = document.getElementById('flashcard-area');
        if (!c) { area.innerHTML = `<div>Card data is missing for index ${cardIndex}.</div>`; return; }

        let f="", b="", h= (c.type || "basic").toUpperCase();
        if(c.type === 'basic') { f=c.front; b=c.back; }
        else if(c.type === 'cloze') { f=(c.text || c.front || '').replace(/\{\{c1::(.*?)\}\}/g, "___"); b=(c.text || c.front || '').replace(/\{\{c1::(.*?)\}\}/g, "<b style=\\'color:var(--success)\\'>$1</b>"); }
        else if(c.type === 'list') { f=c.question || c.front; b=`<ul style="text-align:left; padding-left:20px;">${(c.items||c.back||[]).map(i=>`<li>${i}</li>`).join('')}</ul>`; }
        else { f=c.front || "Unknown"; b=c.back || "No answer"; }

        area.innerHTML = `
        <div class="flashcard" onclick="this.classList.toggle('flipped')">
            <div class="fc-front"><div class="fc-tag">${h}</div><div style="font-size:1.1rem;">${f}</div><div style="margin-top:20px; font-size:0.7rem; color:var(--text-muted);">(Tap to flip)</div></div>
            <div class="fc-back"><div>${b}</div>${c.metadata?.page_number ? `<div style="margin-top:15px; font-size:0.7rem; color:var(--primary);">Pg ${c.metadata.page_number}</div>` : ''}</div>
        </div>
        <div style="text-align:center; font-size:0.8rem;">${cardIndex+1} / ${currentDeck.length}</div>`;
    }
    function nextCard() { if(cardIndex < currentDeck.length-1) { cardIndex++; renderCard(); } }
    function prevCard() { if(cardIndex > 0) { cardIndex--; renderCard(); } }
    function nextCard() { if(cardIndex < currentDeck.length-1) { cardIndex++; renderCard(); } }
    function prevCard() { if(cardIndex > 0) { cardIndex--; renderCard(); } }
</script>
    <script src="//cdn.jsdelivr.net/npm/eruda"></script>
    <script>eruda.init();</script>
</html>

