            const s2List = document.getElementById('s2-stats-list');
            const q = data.script2.queue;
            s2List.innerHTML = `
                ${renderStatLine('Completed', q.completed, 'text-emerald-400', (q.completed/data.script2.total_chunks)*100)}
                ${renderStatLine('Failed', q.failed, 'text-rose-400', (q.failed/data.script2.total_chunks)*100)}
                ${renderStatLine('Processing', q.processing, 'text-sky-400', (q.processing/data.script2.total_chunks)*100)}
                ${renderStatLine('Pending', q.pending, 'text-slate-500', (q.pending/data.script2.total_chunks)*100)}
                <div class="mt-4 pt-4 border-t border-white/5 flex justify-between">
                    <span class="text-xs text-slate-400">Retried Items</span>
                    <span class="text-xs font-bold">${q.retried}</span>
                </div>
            `;

            // Logs UI
            const logList = document.getElementById('error-list');
            logList.innerHTML = data.errors.recent_logs.map(log => `
                <div class="glass-card p-3 rounded-2xl border-l-4 border-rose-500">
                    <div class="flex justify-between items-start">
                        <span class="text-[10px] font-bold text-rose-400 uppercase">${log.error_type}</span>
                        <span class="text-[8px] text-slate-500">${new Date(log.created_at).toLocaleTimeString()}</span>
