                    <p class="text-[9px] text-slate-500 mt-1 font-mono">${log.source_file}</p>
                </div>
            `).join('');
        }

        function renderStatLine(label, count, colorClass, percent) {
            return `
                <div class="space-y-1">
                    <div class="flex justify-between text-xs">
                        <span class="text-slate-400">${label}</span>
                        <span class="font-bold ${colorClass}">${count}</span>
                    </div>
                    <div class="w-full bg-white/5 h-1 rounded-full overflow-hidden">
                        <div class="h-full ${colorClass.replace('text', 'bg')} transition-all duration-1000" style="width: ${percent}%"></div>
                    </div>
                </div>
            `;
        }

        // Initial Fetch
        fetchStats();
        // Auto-refresh every 60 seconds
        setInterval(fetchStats, 60000);
    </script>
</body>
</html>

